// src/components/home/home.component.ts

import { Component, OnInit, signal, computed, ChangeDetectionStrategy, effect, WritableSignal } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterLink } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { EtfService } from '../../services/etf.service';
import { ETFAnalysis, ETF } from '../../models/etf';
import { HttpClientModule } from '@angular/common/http';

@Component({
  selector: 'app-home',
  templateUrl: './home.component.html',
  styleUrls: ['./home.component.scss'],
  standalone: true,
  imports: [
    CommonModule,
    RouterLink,
    FormsModule,
    HttpClientModule // Make sure to include HttpClientModule
  ],
  providers: [EtfService],
  changeDetection: ChangeDetectionStrategy.OnPush
})
export class HomeComponent implements OnInit {
  // Signals for state
  searchTerm: WritableSignal<string> = signal('');
  viewMode: WritableSignal<string> = signal('table');
  showFilters: WritableSignal<boolean> = signal(false);
  sortField: WritableSignal<string> = signal('code'); // Default sort
  sortDirection: WritableSignal<'asc' | 'desc'> = signal('asc');
  currentPage: WritableSignal<number> = signal(1); // Current page
  pageSize: WritableSignal<number> = signal(10); // Items per page
  selectedEtf: WritableSignal<ETF | undefined> = signal(undefined);

  // Computed Signals
  filteredEtfs = computed(() => {
    return this.etfService.etfs().filter((etf: ETF) => {
      return (
        etf.code.toLowerCase().includes(this.searchTerm().toLowerCase()) ||
        etf.name.toLowerCase().includes(this.searchTerm().toLowerCase())
      );
    });
  });

  paginatedData = computed(() => {
    const start = (this.currentPage() - 1) * this.pageSize();
    const end = start + this.pageSize();
    return this.filteredEtfs().slice(start, end);
  });

  totalPages = computed(() => {
    return Math.ceil(this.filteredEtfs().length / this.pageSize());
  });

  visiblePages = computed(() => {
    const total = this.totalPages();
    const current = this.currentPage();
    const delta = 2; // Number of pages to show on either side
    const range = [];

    // Always include the first page
    range.push(1);

    // Add pages before the current page
    for (let i = current - delta; i > 1; i--) {
      range.push(i);
    }

    // Add current page
    range.push(current);

    // Add pages after the current page
    for (let i = current + 1; i < current + delta; i++) {
      if (i < total) {
        range.push(i);
      }
    }

    // Add the last page
    if (total > 1 && !range.includes(total)) {
      range.push(total);
    }
    return [...new Set(range)].sort((a, b) => a - b);
  });

  // Method to check if pagination buttons can show
  canShowPagination = computed(() => this.totalPages() > 1);

  constructor(public etfService: EtfService) {
    // Effects for updating service filter state
    effect(() => {
      this.etfService.filterState.set({
        ...this.etfService.filterState(),
        searchTerm: this.searchTerm(),
        sortField: this.sortField(),
        sortDirection: this.sortDirection(),
        currentPage: this.currentPage(),
        pageSize: this.pageSize()
      });
    });

    // Initialize signals from service state (one-time operation)
    this.initializeSignalsFromService();
  }

