  // --- Parsing & Analysis ---

  private parseKlines(rawLines: string[]): KlinePoint[] {
    return rawLines.map(line => {
       const p = line.split(',');
       return {
          date: p[0],
          open: parseFloat(p[1]),
          close: parseFloat(p[2]),
          high: parseFloat(p[3]),
          low: parseFloat(p[4]),
          volume: parseFloat(p[5]),
          amount: parseFloat(p[6])
       };
    });
  }

  private calcBoxSignals(fullHistory: KlinePoint[]): BoxSignal | null {
      const minBoxSize = 30;
      if (fullHistory.length < minBoxSize + 5) return null;

      const scanLimit = Math.max(minBoxSize + 5, fullHistory.length - 60);

      for (let i = fullHistory.length - 1; i >= scanLimit; i--) {
          const entryDay = fullHistory[i];
          const confirmDay = fullHistory[i-1];
          const obsDay = fullHistory[i-2];

          const boxEndIdx = i - 2;
          const boxStartIdx = boxEndIdx - 29; 

          if (boxStartIdx < 0) continue;

          const boxData = fullHistory.slice(boxStartIdx, boxEndIdx + 1);
          const boxHigh = Math.max(...boxData.map(d => d.high));
          const boxLow = Math.min(...boxData.map(d => d.low));
          const D = boxHigh - boxLow;

          if (confirmDay.close > boxHigh && entryDay.close > boxHigh) {

             const prices = boxData.map(d => d.close);
             const minP = Math.min(...prices);
             const maxP = Math.max(...prices);
             const bins = 20;
             const binSize = (maxP - minP) / bins;
             let poc = (minP + maxP) / 2;

             if (binSize > 0) {
                 const binVols = new Array(bins).fill(0);
                 boxData.forEach(d => {
                    const idx = Math.min(bins-1, Math.floor((d.close - minP)/binSize));
                    binVols[idx] += d.volume;
                 });
                 const maxBinIdx = binVols.indexOf(Math.max(...binVols));
                 poc = minP + (maxBinIdx + 0.5) * binSize;
             }

             const volSlice = fullHistory.slice(i-5, i);
             const avgVol5 = volSlice.reduce((a,b)=>a+b.volume,0)/volSlice.length;

             const volSpike = entryDay.volume > 1.2 * avgVol5 || confirmDay.volume > 1.2 * avgVol5;
             const priceValid = entryDay.close > poc;

             if (priceValid && volSpike) {
                 return {
                     type: 'UP',
                     date: entryDay.date,
                     obsDate: obsDay.date,
                     entryPrice: entryDay.close,
                     boxStartDate: fullHistory[boxStartIdx].date,
                     boxHigh,
                     boxLow,
                     boxHeight: D,
                     poc,
                     tpA: entryDay.close + D * 0.382,
                     tpB: entryDay.close + D * 0.618,
                     slA: entryDay.close - D * 0.382,
                     slB: entryDay.close - D * 0.618,
                     clearPrice: boxLow, 
                     valid: true
                 };
             }
          }
      }
      return null;
  }

  private analyzeETF(item: ETFAnalysis, history: KlinePoint[]): ETFAnalysis {
     if (!history || history.length < 20) return { ...item, history };

     const points = this.calcIndicators(history);
     const latest = points[points.length - 1];
     const prev = points[points.length - 2];

     // Trend Analysis
     let trend: 'UP' | 'DOWN' | 'SIDEWAYS' = 'SIDEWAYS';
     if (latest.ma20 && prev.ma20) {
        if (latest.close > latest.ma20 && latest.ma20 > prev.ma20) trend = 'UP';
        else if (latest.close < latest.ma20 && latest.ma20 < prev.ma20) trend = 'DOWN';
     }

     const volAvg5 = points.slice(-5).reduce((a, b) => a + b.volume, 0) / 5;
     const isHighVolume = latest.volume > 1.5 * volAvg5;

     // Base Signals
     let buySignals = 0;
     let sellSignals = 0;
     const buyFactors: string[] = [];
     const sellFactors: string[] = [];

     const breakMA5 = latest.close < (latest.ma5 || 0);
     const breakMA20 = latest.close < (latest.ma20 || 0);
     const breakDowntrend = prev.close < (prev.ma20 || 0) && latest.close > (latest.ma20 || 0);

     if (breakDowntrend) { buySignals++; buyFactors.push('突破20日均线'); }
     if (isHighVolume && latest.close > latest.open) { buySignals++; buyFactors.push('放量上涨'); }

     // Golden Ratio
     const recent = points.slice(-30);
     const maxHigh = Math.max(...recent.map(p => p.high));
     const minLow = Math.min(...recent.map(p => p.low));
     const range = maxHigh - minLow;
     const goldenPrice = maxHigh - range * 0.382;
     const isGolden = Math.abs(latest.close - goldenPrice) / goldenPrice < 0.02;

     if (isGolden && trend === 'UP') { buySignals += 2; buyFactors.push('黄金分割支撑位'); }

     // MACD
     if (latest.macd && prev.macd) {
        if (latest.macd.macd > 0 && prev.macd.macd <= 0) { buySignals += 2; buyFactors.push('MACD金叉'); }
        if (latest.macd.macd < 0 && prev.macd.macd >= 0) { sellSignals += 2; sellFactors.push('MACD死叉'); }
     }

     if (breakMA20) { sellSignals++; sellFactors.push('跌破20日均线'); }

     // --- Enhanced Signal Logic ---
     if (latest.ma5 && latest.ma10 && latest.ma20) {
         if (latest.ma5 > latest.ma10 && latest.ma10 > latest.ma20) {
             buySignals++; buyFactors.push('均线多头排列');
         }
         if (latest.ma5 < latest.ma10 && latest.ma10 < latest.ma20) {
             sellSignals++; sellFactors.push('均线空头排列');
         }
     }

     if (latest.rsi) {
         if (latest.rsi < 30) { buySignals++; buyFactors.push('RSI超卖区'); }
         if (latest.rsi > 70) { sellSignals++; sellFactors.push('RSI超买区'); }
     }

     if (latest.kdj && prev.kdj) {
         if (prev.kdj.k < prev.kdj.d && latest.kdj.k > latest.kdj.d && latest.kdj.d < 50) {
             buySignals++; buyFactors.push('KDJ低位金叉');
         }
         if (prev.kdj.k > prev.kdj.d && latest.kdj.k < latest.kdj.d && latest.kdj.d > 50) {
             sellSignals++; sellFactors.push('KDJ高位死叉');
         }
     }

     if (latest.ma60) {
         if (latest.close > latest.ma60 && prev.close <= prev.ma60) {
             buySignals++; buyFactors.push('站上60日均线');
         }
         if (latest.close < latest.ma60 && prev.close >= prev.ma60) {
             sellSignals++; sellFactors.push('跌破60日均线');
         }
     }

     const boxSignal = this.calcBoxSignals(points);

     // --- NEW SCORING MODEL (0-100) ---
     let trendScore = 0;
     const ma5 = latest.ma5 || 0;
     const ma10 = latest.ma10 || 0;
     const ma20 = latest.ma20 || 0;
     const ma60 = latest.ma60 || 0;

     if (ma5 > ma10 && ma10 > ma20) trendScore += 15;
     if (ma20 > ma60) trendScore += 15;
     if (latest.close > ma20) trendScore += 10;
     if (latest.close > ma60) trendScore += 10;
     if ((latest.ma20Slope || 0) > 0) trendScore += 10;
     if ((latest.ma60Slope || 0) > 0) trendScore += 10;
     trendScore = Math.min(35, trendScore * (35/70));

     let momScore = 0;
     const macdVal = latest.macd?.macd || 0;
     const diff = latest.macd?.diff || 0;
     const dea = latest.macd?.dea || 0;
     if (macdVal > 0) momScore += 10;
     if (diff > dea) momScore += 10;

     const rsiVal = latest.rsi || 50;
     if (rsiVal > 50 && rsiVal < 80) momScore += 10;
     if (rsiVal >= 80) momScore -= 5;

     const k = latest.kdj?.k || 50;
     const dVal = latest.kdj?.d || 50;
     if (k > dVal) momScore += 10;
     if ((latest.roc || 0) > 0) momScore += 10;
     momScore = Math.min(30, momScore * (30/50));

     let volScore = 0;
     const wr = latest.wr || -50;
     if (wr > -80 && wr < -20) volScore += 10; 
     const bias = latest.bias || 0;
     if (bias > 0 && bias < 5) volScore += 10; 
     const boll = latest.boll;
     if (boll && latest.close > boll.mid && latest.close < boll.upper) volScore += 10;
     volScore = Math.min(15, volScore * (15/30));

     let volumeScore = 0;
     if (latest.obv && latest.obvMa && latest.obv > latest.obvMa) volumeScore += 15;
     if (latest.volume > volAvg5) volumeScore += 10;
     if (latest.close > latest.open) volumeScore += 5; 
     volumeScore = Math.min(20, volumeScore * (20/30));

     let finalScore = trendScore + momScore + volScore + volumeScore;

     if (boxSignal && boxSignal.valid) {
         if (latest.close > boxSignal.entryPrice && latest.close < boxSignal.tpA) {
             finalScore += 15;
             buyFactors.push('箱体突破共振(Box Breakout)');
         }
     }

     if (rsiVal > 85) finalScore -= 10;
     if (trend === 'DOWN') finalScore -= 15;
     finalScore = Math.max(0, Math.min(100, Math.round(finalScore)));

     let suggestion: TradeSuggestion = 'WAIT';

     if (boxSignal && boxSignal.valid) {
         const p = latest.close;
         if (p < boxSignal.clearPrice) {
             suggestion = 'STOP_LOSS_CLEAR';
             sellFactors.push('跌破箱体下沿(Clearance)');
             finalScore = Math.min(finalScore, 20);
         }
         else if (p < boxSignal.slB) {
             suggestion = 'STOP_LOSS_CLEAR';
             sellFactors.push('触及止损B线');
             finalScore = Math.min(finalScore, 20);
         }
         else if (p < boxSignal.slA) {
             suggestion = 'STOP_LOSS_REDUCE';
             sellFactors.push('触及止损A线');
             finalScore = Math.min(finalScore, 30);
         }
         else if (p >= boxSignal.tpB) {
             suggestion = 'TAKE_PROFIT_CLEAR';
             sellFactors.push('达到止盈B目标');
         }
         else if (p >= boxSignal.tpA) {
             suggestion = 'TAKE_PROFIT_REDUCE';
             sellFactors.push('达到止盈A目标');
         }
         else if (p > boxSignal.entryPrice) {
             suggestion = 'HOLD';
         }
         else {
             suggestion = 'BUY_POINT';
         }
     } else {
         if (finalScore >= 80) suggestion = 'BUY_POINT';
         else if (finalScore >= 60) suggestion = 'HOLD';
         else if (finalScore <= 35) suggestion = 'STOP_LOSS_REDUCE';
         else if (finalScore <= 20) suggestion = 'STOP_LOSS_CLEAR';
     }

     return {
        ...item,
        currentPrice: latest.close,
        changePercent7d: (latest.close - (points[points.length - 6]?.close || latest.close)) / (points[points.length - 6]?.close || 1) * 100,
        isGolden,
        goldenPrice,
        breakMA5,
        breakMA20,
        breakDowntrend,
        isHighVolume,
        buySignals,
        sellSignals,
        buyFactors,
        sellFactors,
        trend,
        score: finalScore,
        health: Math.floor(finalScore * 0.8 + Math.random() * 15),
        suggestion,
        boxSignal,
        lastUpdated: new Date().toLocaleTimeString(),
        history: points,
        suggestedEntryPrice: goldenPrice
     };
  }

  private calcIndicators(data: KlinePoint[]): KlinePoint[] {
      const results: KlinePoint[] = [];
      let ema12 = 0; let ema26 = 0; let dea = 0; let atr = 0;
      let avgGain = 0; let avgLoss = 0; let kValue = 50; let dValue = 50;
      let obv = 0; const obvHistory: number[] = [];

      for (let i = 0; i < data.length; i++) {
          const d = data[i];
          const close = d.close;
          const prev = i > 0 ? data[i-1] : null;

          const calcMa = (n: number) => {
              if (i < n - 1) return undefined;
              let sum = 0; for(let k=0; k<n; k++) sum += data[i-k].close;
              return sum / n;
          };
          const ma5 = calcMa(5); const ma10 = calcMa(10); const ma20 = calcMa(20); const ma60 = calcMa(60);

          let ma20Slope = 0; let ma60Slope = 0;
          if (i > 20 && ma20 && results[i-1]?.ma20) ma20Slope = (ma20 - results[i-1].ma20!) / results[i-1].ma20! * 100;
          if (i > 60 && ma60 && results[i-1]?.ma60) ma60Slope = (ma60 - results[i-1].ma60!) / results[i-1].ma60! * 100;

          if (i === 0) { ema12 = close; ema26 = close; } 
          else { ema12 = (2 * close + 11 * ema12) / 13; ema26 = (2 * close + 25 * ema26) / 27; }
          const diff = ema12 - ema26;
          if (i === 0) dea = diff; else dea = (2 * diff + 8 * dea) / 10;
          const macd = 2 * (diff - dea);

          if (i === 0) atr = d.high - d.low;
          else { const tr = Math.max(d.high - d.low, Math.abs(d.high - prev!.close), Math.abs(d.low - prev!.close)); atr = (atr * 13 + tr) / 14; }

          let boll = undefined;
          if (ma20 && i >= 19) {
              let sumSq = 0; for (let k=0; k<20; k++) sumSq += Math.pow(data[i-k].close - ma20, 2);
              const std = Math.sqrt(sumSq / 20);
              boll = { upper: ma20 + 2 * std, mid: ma20, lower: ma20 - 2 * std, width: (4*std)/ma20 };
          }

          let rsi = undefined;
          if (i > 0) {
              const change = close - prev!.close;
              const gain = change > 0 ? change : 0; const loss = change < 0 ? -change : 0;
              if (i < 14) {
                  if (i === 1) { avgGain = gain; avgLoss = loss; }
                  else { avgGain = (avgGain * (i-1) + gain) / i; avgLoss = (avgLoss * (i-1) + loss) / i; }
              } else {
                   avgGain = (avgGain * 13 + gain) / 14; avgLoss = (avgLoss * 13 + loss) / 14;
                   if (avgLoss === 0) rsi = 100; else rsi = 100 - (100 / (1 + avgGain / avgLoss));
              }
          }

          let kdj = undefined;
          if (i >= 8) {
              let lowest = d.low; let highest = d.high;
              for(let j=0; j<9; j++) { lowest = Math.min(lowest, data[i-j].low); highest = Math.max(highest, data[i-j].high); }
              const rsv = (highest === lowest) ? 50 : (close - lowest) / (highest - lowest) * 100;
              kValue = (2/3) * kValue + (1/3) * rsv; dValue = (2/3) * dValue + (1/3) * kValue;
              kdj = { k: kValue, d: dValue, j: 3 * kValue - 2 * dValue };
          }

          let wr = undefined;
          if (i >= 13) {
              let h14 = -Infinity; let l14 = Infinity;
              for(let j=0; j<14; j++) { h14 = Math.max(h14, data[i-j].high); l14 = Math.min(l14, data[i-j].low); }
              wr = (h14 === l14) ? -50 : (h14 - close) / (h14 - l14) * -100;
          }

          let bias = undefined; if (ma20) bias = (close - ma20) / ma20 * 100;
          let roc = undefined; if (i >= 12) { const ref = data[i-12].close; if (ref) roc = (close - ref) / ref * 100; }
          let mtm = undefined; if (i >= 12) mtm = close - data[i-12].close;

          if (i > 0) { if (close > prev!.close) obv += d.volume; else if (close < prev!.close) obv -= d.volume; }
          obvHistory.push(obv);

          let obvMa = undefined;
          if (i >= 29) { let sumObv = 0; for(let k=0; k<30; k++) sumObv += obvHistory[i-k]; obvMa = sumObv / 30; }

          results.push({ ...d, ma5, ma10, ma20, ma60, ma20Slope, ma60Slope, macd: { diff, dea, macd }, atr, boll, rsi, kdj, wr, bias, roc, mtm, obv, obvMa });
      }
      return results;
  }
}

import * as d3 from 'd3';
import { KlinePoint, BoxSignal } from '../../../services/etf.service';
import { SelectionGroup, ScaleBand, ScaleLinear, calculateLR } from './types';

// --- 4. Volume Profile + 123 Painter ---
export function drawVolumeProfile(
    container: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    y: ScaleLinear,
    width: number
) {
    const yMin = y.domain()[0];
    const yMax = y.domain()[1];
    const binCount = 50;
    const binSize = (yMax - yMin) / binCount;
    const bins = new Array(binCount).fill(0);
    let maxVolBin = 0;
    let maxVolIdx = 0;

    data.forEach(d => {
        const idx = Math.floor((d.close - yMin) / binSize);
        if (idx >= 0 && idx < binCount) {
            bins[idx] += d.volume;
            if (bins[idx] > maxVolBin) {
                maxVolBin = bins[idx];
                maxVolIdx = idx;
            }
        }
    });

    const pocPrice = yMin + (maxVolIdx + 0.5) * binSize;
    const maxBarWidth = width * 0.2; 
    const vpGroup = container.append('g').attr('transform', `translate(${width}, 0)`);

    bins.forEach((vol, i) => {
        const barW = (vol / maxVolBin) * maxBarWidth;
        const barY = y(yMin + (i+1)*binSize);
        const barH = Math.abs(y(yMin + i*binSize) - barY);

        vpGroup.append('rect')
            .attr('x', -barW)
            .attr('y', barY)
            .attr('width', barW)
            .attr('height', barH)
            .attr('fill', i === maxVolIdx ? '#eab308' : '#64748b') 
            .attr('opacity', i === maxVolIdx ? 0.4 : 0.1);
    });

    container.append('line')
        .attr('x1', 0).attr('x2', width)
        .attr('y1', y(pocPrice)).attr('y2', y(pocPrice))
        .attr('stroke', '#eab308').attr('stroke-width', 1.5).attr('stroke-dasharray', '4,2');

    container.append('text')
        .attr('x', width - 5).attr('y', y(pocPrice) - 4)
        .text('POC (筹码峰)').attr('fill', '#eab308')
        .attr('font-size', '10px').attr('font-weight', 'bold').attr('text-anchor', 'end');

    // ZigZag / Wave Theory
    const zigzag: {x: number, y: number, date: string, type: 'HIGH'|'LOW'}[] = [];
    const lookback = Math.max(3, Math.floor(data.length / 20));

    for(let i=lookback; i<data.length-lookback; i++) {
            const d = data[i];
            const range = data.slice(i-lookback, i+lookback+1);
            const isHigh = range.every(item => item.high <= d.high);
            const isLow = range.every(item => item.low >= d.low);

            if (isHigh) zigzag.push({x: i, y: d.high, date: d.date, type: 'HIGH'});
            else if (isLow) zigzag.push({x: i, y: d.low, date: d.date, type: 'LOW'});
    }

    const cleanZigzag: typeof zigzag = [];
    zigzag.forEach(p => {
        if (cleanZigzag.length === 0) { cleanZigzag.push(p); return; }
        const last = cleanZigzag[cleanZigzag.length-1];
        if (last.type !== p.type) {
            cleanZigzag.push(p);
        } else {
            if (p.type === 'HIGH' && p.y > last.y) cleanZigzag[cleanZigzag.length-1] = p;
            if (p.type === 'LOW' && p.y < last.y) cleanZigzag[cleanZigzag.length-1] = p;
        }
    });

    const lineGen = d3.line<{x:number, y:number, date: string}>()
        .x(d => (x(d.date) ?? 0) + x.bandwidth()/2)
        .y(d => y(d.y));

    // Draw Thin Black Lines for Segments
    container.append('path')
        .datum(cleanZigzag)
        .attr('fill', 'none')
        .attr('stroke', '#000000') 
        .attr('stroke-width', 1)
        .attr('opacity', 0.8)
        .attr('d', (d) => lineGen(d.map(p => ({x: p.x, y: p.y, date: p.date}))));

    // Draw Wave Labels (1, 2, 3, 4, 5, A, B, C)
    const waveLabels = ['1', '2', '3', '4', '5', 'A', 'B', 'C'];

    if (cleanZigzag.length > 0) {
        cleanZigzag.forEach((p, idx) => {
            const val = x(p.date);
            if (val === undefined) return; 
            const px = val + x.bandwidth()/2;
            const py = y(p.y);
            const label = waveLabels[idx % waveLabels.length];

            // Offset logic: HIGH above candle, LOW below candle
            const yOffset = p.type === 'HIGH' ? -15 : 15;

            const g = container.append('g').attr('transform', `translate(${px}, ${py + yOffset})`);

            // Purple Hollow Circle
            g.append('circle')
                .attr('r', 7)
                .attr('fill', 'white')
                .attr('stroke', '#a855f7') // Purple
                .attr('stroke-width', 1.5);

            // Text inside circle
            g.append('text')
                .text(label)
                .attr('dy', '0.35em')
                .attr('text-anchor', 'middle')
                .attr('fill', '#a855f7')
                .attr('font-size', '9px')
                .attr('font-weight', 'bold');
        });
    }
}

// --- 5. Resonance Signal Painter (Box Strategy) ---
export function drawResonanceSignal(
    container: SelectionGroup,
    signal: BoxSignal,
    x: ScaleBand,
    y: ScaleLinear,
    width: number
) {
    if (!signal || !signal.valid) return;

    const boxStartX = x(signal.boxStartDate);
    const obsX = x(signal.obsDate);
    const entryX = x(signal.date);
    const yHigh = y(signal.boxHigh);
    const yLow = y(signal.boxLow);
    const yPoc = y(signal.poc);

    // Safety check for starting line coordinate
    let lineStart = 0;
    if (boxStartX !== undefined) lineStart = boxStartX;
    else if (entryX !== undefined) lineStart = Math.max(0, entryX - width * 0.1);

    if (entryX !== undefined || boxStartX !== undefined) {
            container.append('line').attr('x1', lineStart).attr('x2', width).attr('y1', yLow).attr('y2', yLow).attr('stroke', '#334155').attr('stroke-width', 2).attr('stroke-opacity', 0.8);
            container.append('line').attr('x1', lineStart).attr('x2', width).attr('y1', yHigh).attr('y2', yHigh).attr('stroke', '#334155').attr('stroke-width', 2).attr('stroke-opacity', 0.8);
            container.append('line').attr('x1', lineStart).attr('x2', width).attr('y1', yPoc).attr('y2', yPoc).attr('stroke', '#f97316').attr('stroke-width', 1).attr('stroke-dasharray', '4,2');
            if (boxStartX !== undefined) {
               container.append('text').attr('x', boxStartX + 5).attr('y', yPoc - 3).text('POC').attr('fill', '#f97316').attr('font-size', '10px');
            }
    }
    if (obsX !== undefined) {
            container.append('text').attr('x', obsX + x.bandwidth()/2).attr('y', yHigh - 10).text('👁').attr('font-size', '14px').attr('text-anchor', 'middle');
    }
    if (entryX !== undefined) {
        const cx = entryX + x.bandwidth()/2;
        const yEntry = y(signal.entryPrice);
        container.append('text').attr('x', cx).attr('y', yEntry + 15).text('🚩').attr('font-size', '14px').attr('text-anchor', 'middle');
        container.append('text').attr('x', cx).attr('y', yEntry + 28).text('建仓').attr('fill', '#ef4444').attr('font-size', '10px').attr('text-anchor', 'middle').attr('font-weight', 'bold');
    }

    const drawTarget = (val: number, label: string, color: string, icon: string) => {
        const yPos = y(val);
        container.append('line').attr('x1', 0).attr('x2', width).attr('y1', yPos).attr('y2', yPos).attr('stroke', color).attr('stroke-width', 1).attr('opacity', 0.8); 
        container.append('text').attr('x', 5).attr('y', yPos - 4).text(icon).attr('font-size', '14px').attr('text-anchor', 'start');
        container.append('text').attr('x', 25).attr('y', yPos - 4).text(`${label} : ${val.toFixed(3)}`).attr('fill', color).attr('font-size', '10px').attr('font-weight', 'bold').attr('text-anchor', 'start');
    };
    drawTarget(signal.tpA, '止盈A', '#ef4444', '🎯');
    drawTarget(signal.tpB, '止盈B', '#ef4444', '💰');
    drawTarget(signal.slA, '止损A', '#22c55e', '🛡');
    drawTarget(signal.slB, '止损B', '#22c55e', '🛑');
}

// --- 6. Vol/Price Momentum Painter ---
export function drawVolPriceMomentum(
    container: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    y: ScaleLinear,
    width: number
) {
    // 1. Bias Line (Keep as background context)
    const biasData = data.filter(d => d.ma60);
    if (biasData.length > 0) {
        const lineBias = d3.line<KlinePoint>()
            .x(d => (x(d.date) ?? 0) + x.bandwidth()/2)
            .y(d => y(d.ma60! * 1.05))
            .curve(d3.curveMonotoneX);
        container.append('path').datum(biasData).attr('fill', 'none').attr('stroke', '#a855f7').attr('stroke-width', 1).attr('stroke-dasharray', '4,4').attr('d', lineBias);
    }

    // 2. Signals & ATR Zone
    for(let i=5; i<data.length; i++) {
        const d = data[i];
        const val = x(d.date);
        if (val === undefined) continue;
        const xPos = val + x.bandwidth()/2;

        // ATR Zone (Background)
        if (d.ma20 && d.atr) {
            const upper = y(d.ma20 + 0.5 * d.atr);
            const lower = y(d.ma20 - 0.5 * d.atr);
            container.append('line').attr('x1', xPos).attr('x2', xPos).attr('y1', upper).attr('y2', lower).attr('stroke', '#cbd5e1').attr('stroke-width', 4).attr('opacity', 0.3);
        }

        // Resonance Logic
        const prev5Vol = data.slice(i-5, i).reduce((sum, item) => sum + item.volume, 0) / 5;
        const volRatio = prev5Vol > 0 ? d.volume / prev5Vol : 0;

        if (d.ma5 && d.ma10 && d.ma20) {
            // Arrow Shapes
            // Buy: Upward Divergence (5>10>20) + Vol > 1.5x
            if (d.ma5 > d.ma10 && d.ma10 > d.ma20 && volRatio > 1.5) {
                // Red Up Arrow
                const yBase = y(d.low) + 20;
                container.append('path')
                    .attr('d', `M 0 -6 L -4 0 L -1.5 0 L -1.5 6 L 1.5 6 L 1.5 0 L 4 0 Z`) // Arrow Path
                    .attr('transform', `translate(${xPos}, ${yBase})`)
                    .attr('fill', '#ef4444')
                    .attr('stroke', '#b91c1c')
                    .attr('stroke-width', 0.5);
            }
            // Sell: Downward Divergence (5<10<20) + Vol > 1.5x
            else if (d.ma5 < d.ma10 && d.ma10 < d.ma20 && volRatio > 1.5) {
                // Green Down Arrow
                const yBase = y(d.low) + 20; // User asked for below K line
                container.append('path')
                    .attr('d', `M 0 6 L -4 0 L -1.5 0 L -1.5 -6 L 1.5 -6 L 1.5 0 L 4 0 Z`) // Arrow Path
                    .attr('transform', `translate(${xPos}, ${yBase})`)
                    .attr('fill', '#22c55e')
                    .attr('stroke', '#15803d')
                    .attr('stroke-width', 0.5);
            }
        }
    }
}

// --- 7. MA Slope Painter ---
export function drawMASlope(
    container: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    y: ScaleLinear
) {
    for(let i=1; i<data.length; i++) {
        const d = data[i];
        const prev = data[i-1];
        if (d.ma5 && d.ma10 && d.ma20 && prev.ma5 && prev.ma10 && prev.ma20) {
            const s5 = d.ma5 - prev.ma5;
            const s10 = d.ma10 - prev.ma10;
            const s20 = d.ma20 - prev.ma20;
            if (s5 > 0 && s10 > 0 && s20 > 0 && d.ma5 > d.ma10 && d.ma10 > d.ma20) {
                const val = x(d.date);
                if (val === undefined) continue;
                const xPos = val + x.bandwidth()/2;
                const yLow = y(d.low);
                container.append('text').attr('x', xPos).attr('y', yLow + 25).text('⬆️').attr('fill', '#ec4899').attr('font-size', '10px').attr('text-anchor', 'middle');
            }
        }
    }
}

// --- 8. Chan Structure Painter ---
export function drawChanStruct(
    container: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    y: ScaleLinear
) {
    const fractals: {x: number, y: number, type: 'TOP'|'BTM', date: string}[] = [];
    for(let i=2; i<data.length-2; i++) {
        const d = data[i];
        const l = data[i-1]; const ll = data[i-2];
        const r = data[i+1]; const rr = data[i+2];
        if (d.high > l.high && d.high > ll.high && d.high > r.high && d.high > rr.high) {
            const val = x(d.date);
            if(val !== undefined) fractals.push({x: val + x.bandwidth()/2, y: y(d.high), type: 'TOP', date: d.date});
        }
        else if (d.low < l.low && d.low < ll.low && d.low < r.low && d.low < rr.low) {
            const val = x(d.date);
            if(val !== undefined) fractals.push({x: val + x.bandwidth()/2, y: y(d.low), type: 'BTM', date: d.date});
        }
    }
    const strokes: {x: number, y: number}[] = [];
    let lastType: 'TOP' | 'BTM' | null = null;
    fractals.forEach(f => {
        if (lastType === null || lastType !== f.type) {
            strokes.push({x: f.x, y: f.y});
            lastType = f.type;
        } else {
            const lastStroke = strokes[strokes.length-1];
            if (f.type === 'TOP' && f.y < lastStroke.y) { 
                    strokes[strokes.length-1] = {x: f.x, y: f.y};
            } else if (f.type === 'BTM' && f.y > lastStroke.y) { 
                    strokes[strokes.length-1] = {x: f.x, y: f.y};
            }
        }
    });
    if (strokes.length > 1) {
        const lineGen = d3.line<{x: number, y: number}>().x(d => d.x).y(d => d.y);
        container.append('path').datum(strokes).attr('d', lineGen).attr('fill', 'none').attr('stroke', '#334155').attr('stroke-width', 2);
    }
}

// --- 9. Strategic Buy/Sell Points (R0-R10) Painter ---
export function drawStrategyMarkers(
    container: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    y: ScaleLinear,
    width: number
) {
    const period = 20;
    let hasPosition = false;
    let entryPrice = 0;
    let entryIndex = -1;
    let waveHigh = -Infinity;
    let waveLow = Infinity;
    let r0Index = -1;

    for (let i = period; i < data.length; i++) {
        const curr = data[i];
        const prev = data[i-1];

        // 1. Calculate Channel
        const slice = data.slice(i - period + 1, i + 1);
        const lr = calculateLR(slice.map((d, idx) => ({ x: idx, y: d.close })));

        let maxDev = -Infinity;
        let minDev = Infinity;
        slice.forEach((d, idx) => {
            const regY = lr.slope * idx + lr.intercept;
            maxDev = Math.max(maxDev, d.high - regY);
            minDev = Math.min(minDev, d.low - regY);
        });

        const currentRegY = lr.slope * (period - 1) + lr.intercept;
        const topChannel = currentRegY + maxDev;
        const bottomChannel = currentRegY + minDev;
        const middleChannel = currentRegY;

        const val = x(curr.date);
        if (val === undefined) continue;
        const xPos = val + x.bandwidth()/2;

        // R0: Observation
        if (!hasPosition && curr.close > topChannel) {
             container.append('text')
                .attr('x', xPos).attr('y', y(curr.high) - 25)
                .text('👁️').attr('font-size', '12px').attr('text-anchor', 'middle')
                .attr('fill', '#a855f7');
             r0Index = i;
        }

        // R1: Entry Logic (Strict)
        const volAvg5 = data.slice(i-5, i).reduce((a,b)=>a+b.volume,0)/5;
        const prevVolAvg5 = data.slice(i-6, i-1).reduce((a,b)=>a+b.volume,0)/5;
        const volCond = curr.volume > 1.5 * volAvg5 && prev.volume > 1.5 * prevVolAvg5;
        const breakout = (curr.close > topChannel || prev.close > topChannel);

        if (!hasPosition) {
            if (breakout && volCond && lr.slope > 0) {
                 container.append('text')
                    .attr('x', xPos).attr('y', y(curr.low) + 20)
                    .text('🚩').attr('font-size', '14px').attr('text-anchor', 'middle');

                 hasPosition = true;
                 entryPrice = curr.close;
                 entryIndex = i;
                 waveHigh = curr.high;
                 waveLow = Math.min(...data.slice(Math.max(0, i-20), i).map(d=>d.low));
            }
        } 
        else {
            // HOLDING STATE
            waveHigh = Math.max(waveHigh, curr.high);
            const range = waveHigh - waveLow;

            // R2: Add Position
            if (i - entryIndex <= 10) {
                 const fib382 = waveHigh - range * 0.382;
                 if (curr.low <= fib382 && curr.low >= bottomChannel && curr.close < prev.close) {
                     container.append('text')
                        .attr('x', xPos).attr('y', y(curr.low) + 20)
                        .text('➕').attr('font-size', '12px').attr('text-anchor', 'middle')
                        .attr('fill', '#3b82f6');
                 }
            }

            // R4: Time Warning
            if (i - entryIndex > 20 && curr.high < waveHigh) { 
                 container.append('text')
                    .attr('x', xPos).attr('y', y(curr.high) - 35)
                    .text('⚠️').attr('font-size', '12px').attr('text-anchor', 'middle');
            }

            // R6: Take Profit Levels (Ladder)
            const drop326 = waveHigh - range * 0.326;
            const drop618 = waveHigh - range * 0.618;
            const drop100 = waveHigh - range * 1.0;
            const drop138 = waveHigh - range * 1.382;

            if (curr.close < drop138) { 
                 container.append('text').attr('x', xPos).attr('y', y(curr.high) - 10).text('💰').attr('font-size', '14px').attr('text-anchor', 'middle');
                 hasPosition = false; 
            } else if (curr.close < drop100) {
                 container.append('text').attr('x', xPos).attr('y', y(curr.high) - 10).text('🎯').attr('font-size', '12px').attr('text-anchor', 'middle').attr('fill', '#eab308'); 
            } else if (curr.close < drop618) {
                 container.append('text').attr('x', xPos).attr('y', y(curr.high) - 10).text('🎯').attr('font-size', '12px').attr('text-anchor', 'middle').attr('fill', '#eab308'); 
            } else if (curr.close < drop326) {
                 container.append('text').attr('x', xPos).attr('y', y(curr.high) - 10).text('🎯').attr('font-size', '12px').attr('text-anchor', 'middle').attr('fill', '#ef4444'); 
            }

            // R8: Hard Stop
            if ((curr.close - entryPrice) / entryPrice >= 0.30) {
                 container.append('text').attr('x', xPos).attr('y', y(curr.high) - 25).text('❌').attr('font-size', '14px').attr('text-anchor', 'middle').attr('fill', '#ef4444');
                 hasPosition = false;
            }

            // R9: Defensive Stop
            const stopA = entryPrice - range * 0.326;
            if (curr.close < stopA) {
                container.append('text').attr('x', xPos).attr('y', y(curr.low) + 30).text('🛡️').attr('font-size', '12px').attr('text-anchor', 'middle');
            }

            // R10: Extreme Cut
            const low30 = Math.min(...data.slice(Math.max(0, i-30), i).map(d=>d.low));
            if (curr.close < low30) {
                 container.append('text').attr('x', xPos).attr('y', y(curr.low) + 30).text('🚫').attr('font-size', '14px').attr('text-anchor', 'middle');
                 hasPosition = false;
            }
        }
    }
}

