  /**
   * Load All ETFs Logic
   * Primary: Eastmoney (push2)
   * Fallback: Static fallback if API fails
   */
  loadAllEtfs() {
    if (this.loading()) return;
    this.loading.set(true);
    this.error.set(null);

    // Primary: Eastmoney CLIST
    // Decreased PZ to 1500 to reduce chance of Script Error (JSONP truncation/timeout)
    const url = 'https://push2.eastmoney.com/api/qt/clist/get?pn=1&pz=1500&po=1&np=1&ut=bd1d9ddb04089700cf9c27f6f7426281&fltt=2&invt=2&wbp2u=|0|0|0|web&fid=f3&fs=b:MK0021&fields=f12,f13,f14,f2,f3,f4,f5,f6,f20,f21';

    this.http.jsonp<any>(url, 'cb').pipe(
        retry(2), // Retry twice
        timeout(15000), // Increased timeout
        catchError(err => {
            console.warn('Primary API (Eastmoney) failed or script error, switching to Fallback...', err);
            return this.loadFallbackEtfs();
        })
    ).subscribe({
        next: (res: any) => {
            if (res && res.data && res.data.diff) {
                this.processEastmoneyList(res.data.diff);
            } else if (Array.isArray(res)) {
                this.etfData.set(res);
                this.fetchHistories(res);
            } else {
                this.loadFallbackEtfs().subscribe(fallbackData => {
                    this.etfData.set(fallbackData);
                    this.fetchHistories(fallbackData);
                });
            }
        },
        error: (err) => {
            console.error('Final Load Error:', err);
            this.error.set('无法连接到市场数据源，请检查网络 (Script Error/Timeout).');
            this.loadFallbackEtfs().subscribe(fallbackData => {
                this.etfData.set(fallbackData);
                this.loading.set(false);
            });
        }
    });
  }

  private processEastmoneyList(diff: any) {
      const rawList = Array.isArray(diff) ? diff : Object.values(diff);
      const staticDefMap = new Map<string, ETFDefinition>();
      ETF_LIST.forEach(def => staticDefMap.set(def.code, def));

      const fullList: ETFAnalysis[] = rawList.map((raw: any) => {
          const code = raw.f12;
          const name = raw.f14;
          const price = this.parseRawNumber(raw.f2);
          const changePercent = this.parseRawNumber(raw.f3);
          let marketCap = this.parseRawNumber(raw.f20); 
          if (marketCap <= 0) marketCap = this.parseRawNumber(raw.f21);

          if (price <= 0) return null;

          const staticDef = staticDefMap.get(code);
          const industry = staticDef?.industry || this.classifyETF(name);
          const displayName = staticDef?.name || name;

          const def: ETFDefinition = { code, name: displayName, industry };
          return this.createEtfItem(def, price, changePercent, marketCap);
      }).filter((item): item is ETFAnalysis => item !== null);

      this.etfData.set(fullList);
      this.fetchHistories(fullList);
  }

  private loadFallbackEtfs(): Observable<ETFAnalysis[]> {
      return of(ETF_LIST.map(def => this.createEtfItem(def, 0, 0, 0))); 
  }

