                        <span class="w-2 h-2 md:w-3 md:h-0.5 rounded-full md:rounded-none bg-orange-500"></span> <span class="hidden md:inline">MA20</span>
                     </button>
                     <button (click)="toggleMA('ma60')" 
                             [class.opacity-100]="showMA60()" [class.opacity-40]="!showMA60()"
                             class="flex items-center gap-1 hover:opacity-80 transition-opacity focus:outline-none">
                        <span class="w-2 h-2 md:w-3 md:h-0.5 rounded-full md:rounded-none bg-blue-500"></span> <span class="hidden md:inline">MA60</span>
                     </button>
                 </div>

                 <span class="w-px h-3 bg-gray-300 mx-1 hidden sm:block"></span>

                 <!-- Drawing Tools Dropdown -->
                 <div class="relative">
                    <button (click)="toggleDrawingsMenu()" 
                            class="px-2 md:px-3 py-1 md:py-1.5 bg-white border border-gray-200 hover:bg-gray-50 text-slate-700 rounded-lg shadow-sm flex items-center gap-1 md:gap-2 transition-colors text-[10px] md:text-xs"
                            [class.text-blue-600]="showDrawingsMenu()"
                            [class.border-blue-200]="showDrawingsMenu()">
                       <i class="fa-solid fa-layer-group"></i> <span class="hidden sm:inline">画线显示</span>
                       <i class="fa-solid fa-chevron-down text-[8px] md:text-[10px]"></i>
                    </button>

                    @if (showDrawingsMenu()) {
                      <div class="fixed inset-0 z-40" (click)="showDrawingsMenu.set(false)"></div>
                      <div class="absolute right-0 top-full mt-2 w-48 md:w-56 bg-white rounded-xl shadow-xl border border-gray-100 z-50 overflow-hidden animate-[fadeIn_0.1s_ease-out]">
                         <div class="p-1 space-y-0.5 max-h-[300px] md:max-h-[400px] overflow-y-auto">
                            <!-- Standard Tools -->
                            <div class="px-3 py-1 text-[10px] text-gray-400 font-bold uppercase tracking-wider">基础画线</div>
                            <button (click)="toggleStrategyMarkers()" class="w-full text-left px-3 py-2 text-xs flex items-center justify-between rounded-lg hover:bg-gray-50 transition-colors group">
                               <span class="text-slate-700 font-medium">策略买卖点 (R0-R10)</span>
                               @if (showStrategyMarkers()) { <i class="fa-solid fa-check text-red-500"></i> }
                            </button>
                            <button (click)="toggleSupRes()" class="w-full text-left px-3 py-2 text-xs flex items-center justify-between rounded-lg hover:bg-gray-50 transition-colors group">
                               <span class="text-slate-700 font-medium">智能支撑/压力 (线性回归)</span>
                               @if (showSupRes()) { <i class="fa-solid fa-check text-indigo-500"></i> }
                            </button>
                            <button (click)="toggleTrendChannel()" class="w-full text-left px-3 py-2 text-xs flex items-center justify-between rounded-lg hover:bg-gray-50 transition-colors group">
                               <span class="text-slate-700 font-medium">平行趋势线 (通道)</span>
                               @if (showTrendChannel()) { <i class="fa-solid fa-check text-blue-500"></i> }
                            </button>
                            <button (click)="toggleFib()" class="w-full text-left px-3 py-2 text-xs flex items-center justify-between rounded-lg hover:bg-gray-50 transition-colors group">
                               <span class="text-slate-700 font-medium">黄金分割 + 拓展线</span>
                               @if (showFib()) { <i class="fa-solid fa-check text-orange-500"></i> }
                            </button>

                            <div class="h-px bg-gray-100 my-1"></div>

                            <!-- Advanced Tools -->
                            <div class="px-3 py-1 text-[10px] text-gray-400 font-bold uppercase tracking-wider">高级共振</div>
                            <button (click)="toggleResonance()" class="w-full text-left px-3 py-2 text-xs flex items-center justify-between rounded-lg hover:bg-gray-50 transition-colors group">
                               <span class="text-slate-700 font-medium">多周期共振标注 (箱体+POC)</span>
                               @if (showResonance()) { <i class="fa-solid fa-check text-yellow-600"></i> }
                            </button>
                            <button (click)="toggleVolume123()" class="w-full text-left px-3 py-2 text-xs flex items-center justify-between rounded-lg hover:bg-gray-50 transition-colors group">
                               <span class="text-slate-700 font-medium">成交量分布 + 波浪理论</span>
                               @if (showVolume123()) { <i class="fa-solid fa-check text-purple-500"></i> }
                            </button>
                            <button (click)="toggleVolPrice()" class="w-full text-left px-3 py-2 text-xs flex items-center justify-between rounded-lg hover:bg-gray-50 transition-colors group">
                               <span class="text-slate-700 font-medium">量价结合 (动量+波动率)</span>
                               @if (showVolPrice()) { <i class="fa-solid fa-check text-red-500"></i> }
                            </button>
                            <button (click)="toggleMASlope()" class="w-full text-left px-3 py-2 text-xs flex items-center justify-between rounded-lg hover:bg-gray-50 transition-colors group">
                               <span class="text-slate-700 font-medium">均线斜率共振</span>
                               @if (showMASlope()) { <i class="fa-solid fa-check text-pink-500"></i> }
                            </button>
                         </div>
                      </div>
                    }
                 </div>
             </div>
           </div>
        </div>

        <div #chartContainer class="flex-grow w-full h-[400px] md:h-[650px] relative"></div>

        @if (!data()) {
          <div class="absolute inset-0 flex items-center justify-center bg-white/80">
            <div class="text-center">
               <i class="fa-solid fa-circle-notch fa-spin text-3xl md:text-4xl text-blue-500 mb-2"></i>
               <p class="text-gray-500 text-xs md:text-sm">正在加载市场数据...</p>
            </div>
          </div>
        }
      </div>

      <!-- Analysis Grid -->
      <div class="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-6">
        <!-- Fibonacci Module -->
        <div class="bg-white p-4 md:p-6 rounded-xl shadow-sm border border-gray-100">
           <div class="flex justify-between items-center mb-4">
             <h3 class="font-bold text-slate-700 flex items-center gap-2 text-sm md:text-base">
                <i class="fa-solid fa-list-ol text-blue-500"></i> 关键点位 (黄金分割)
             </h3>
             <span class="text-[10px] md:text-xs px-2 py-1 rounded bg-gray-100 text-gray-500 font-medium">
                {{ data()?.trend === 'DOWN' ? '下降趋势 (压力/反弹)' : '上升/震荡 (支撑/回调)' }}
             </span>
           </div>

           <div class="space-y-3">
              @for (level of fibLevels(); track level.label) {
                  <div class="flex justify-between items-center p-2 rounded text-xs md:text-sm transition-colors"
                       [ngClass]="level.bgClass || 'bg-gray-50'"
                       [class.border-l-4]="level.borderClass"
                       [ngClass]="level.borderClass || 'border-transparent'">
                     <span class="font-medium" [ngClass]="level.textClass || 'text-gray-500'">
                       @if(level.isExtension) { <i class="fa-solid fa-bolt mr-1 text-[10px]"></i> }
                       {{ level.label }}
                     </span>
                     <span class="font-mono font-bold" [ngClass]="level.textClass || 'text-slate-700'">{{ level.val | number:'1.3-3' }}</span>
                  </div>
              }
           </div>

           <div class="mt-4 text-[10px] md:text-xs text-gray-400 leading-relaxed border-t border-gray-100 pt-3">
               <i class="fa-solid fa-info-circle mr-1"></i> 基于近{{ selectedRange() }}个交易日高低点。上升趋势关注回撤支撑 (38.2%/61.8%)，下降趋势关注反弹压力 (-38.2%/-61.8%)。带⚡标记为趋势拓展目标位。
           </div>
        </div>

        <!-- Analysis Summary -->
        <div class="bg-white p-4 md:p-6 rounded-xl shadow-sm border border-gray-100 flex flex-col justify-between">
          <div>
            <h4 class="text-xs md:text-sm font-bold text-gray-500 uppercase mb-3">综合分析摘要</h4>
            <div class="grid grid-cols-2 gap-4 mb-6">
              <div class="p-4 bg-gray-50 rounded-lg text-center">
                <p class="text-[10px] md:text-xs text-gray-400 mb-1">AI 投资建议</p>
                <p class="text-lg md:text-xl font-bold" [class.text-red-600]="data()?.suggestion?.includes('BUY')" [class.text-green-600]="data()?.suggestion?.includes('SELL')">
                  {{ translateSuggestion(data()?.suggestion) }}
                </p>
              </div>
              <div class="p-4 bg-gray-50 rounded-lg text-center">
                <p class="text-[10px] md:text-xs text-gray-400 mb-1">技术评分</p>
                <p class="text-xl md:text-2xl font-bold text-blue-600">{{ data()?.score }}<span class="text-xs md:text-sm text-gray-400 font-normal">/100</span></p>
              </div>
            </div>

            <div class="space-y-2">
              <div class="flex justify-between text-xs md:text-sm">
                <span class="text-gray-500">趋势判断</span>
                <span class="font-bold" 
                  [class.text-red-600]="data()?.trend === 'UP'" 
                  [class.text-green-600]="data()?.trend === 'DOWN'">
                  {{ data()?.trend === 'UP' ? '上涨趋势' : (data()?.trend === 'DOWN' ? '下跌趋势' : '震荡整理') }}
                </span>
              </div>
              <div class="flex justify-between text-xs md:text-sm">
                <span class="text-gray-500">成交量状态</span>
                <span class="font-bold" [class.text-red-600]="data()?.isHighVolume">
                  {{ data()?.isHighVolume ? '放量活跃' : '缩量/平量' }}
                </span>
              </div>
               <div class="flex justify-between text-xs md:text-sm">
                <span class="text-gray-500">黄金值信号</span>
                <span class="font-bold" [class.text-yellow-600]="data()?.isGolden">
                  {{ data()?.isGolden ? '触发 (回调到位)' : '无' }}
                </span>
              </div>
            </div>
          </div>
        </div>
      </div>

      <!-- Volatility & Signals -->
      <div class="bg-white p-4 md:p-6 rounded-xl shadow-sm border border-gray-100">
         <h4 class="text-xs md:text-sm font-bold text-gray-500 uppercase mb-4 flex items-center gap-2">
            <i class="fa-solid fa-chart-bar text-purple-500"></i> 近30日日内振幅 (Intraday Amplitude)
         </h4>
         <div class="h-48 md:h-64 flex items-end justify-between gap-1 overflow-x-auto pb-10 pt-8 relative px-2">
            @for (point of recentHistory(); track point.date) {
               <div class="flex-1 min-w-[16px] md:min-w-[24px] flex flex-col justify-end items-center group relative h-full">
                   <div class="mb-2 transform -rotate-45 text-[9px] md:text-xs font-bold text-slate-500 whitespace-nowrap origin-bottom-left" style="margin-left: 8px;">
                      {{ ((point.high - point.low) / point.low * 100) | number:'1.2-2' }}%
                   </div>
                   <div class="w-full max-w-[20px] rounded-t-sm transition-all relative hover:opacity-80 border-t border-x border-black/5"
                        [style.height.%]="getVolatilityPercent(point)"
                        [class.bg-red-400]="point.close > point.open"
                        [class.bg-green-400]="point.close <= point.open">
                   </div>
                   <div class="absolute -bottom-8 text-[9px] md:text-[10px] text-gray-400 transform -rotate-45 whitespace-nowrap origin-top-left ml-2">
                      {{ point.date | slice:5:7 }}/{{ point.date | slice:8:10 }}
                   </div>
               </div>
            }
         </div>
      </div>

      <!-- Detailed Signal Factors -->
      <div class="bg-white p-4 md:p-6 rounded-xl shadow-sm border border-gray-100">
        <h3 class="font-bold text-slate-700 mb-4 flex items-center gap-2 text-sm md:text-base">
          <i class="fa-solid fa-list-check text-blue-500"></i> 信号因子详情
        </h3>
        <div class="grid grid-cols-1 md:grid-cols-2 gap-4 md:gap-6">
          <div class="p-4 md:p-5 rounded-xl bg-red-50 border border-red-100">
             <h4 class="font-bold text-red-800 mb-4 flex items-center gap-2 text-sm md:text-base">
               <i class="fa-solid fa-circle-arrow-up"></i> 买入信号 ({{ data()?.buySignals }})
             </h4>
             @if (data()?.buyFactors?.length) {
               <ul class="space-y-3">
                 @for (factor of data()?.buyFactors; track factor) {
                   <li class="flex items-start gap-2 text-xs md:text-sm text-slate-700">
                     <i class="fa-solid fa-check-circle text-red-500 mt-0.5"></i> <span>{{ factor }}</span>
                   </li>
                 }
               </ul>
             }
          </div>
          <div class="p-4 md:p-5 rounded-xl bg-green-50 border border-green-100">
             <h4 class="font-bold text-green-800 mb-4 flex items-center gap-2 text-sm md:text-base">
               <i class="fa-solid fa-circle-arrow-down"></i> 卖出信号 ({{ data()?.sellSignals }})
             </h4>
             @if (data()?.sellFactors?.length) {
               <ul class="space-y-3">
                 @for (factor of data()?.sellFactors; track factor) {
                   <li class="flex items-start gap-2 text-xs md:text-sm text-slate-700">
                     <i class="fa-solid fa-circle-exclamation text-green-500 mt-0.5"></i> <span>{{ factor }}</span>
                   </li>
                 }
               </ul>
             }
          </div>
        </div>
      </div>
    </div>

    <!-- Advanced Strategy Modal -->
    @if (showStrategyModal()) {
       <div class="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm p-0 md:p-4" (click)="closeStrategy()">
         <div class="bg-white w-full h-full md:w-[95vw] md:h-[90vh] md:rounded-2xl shadow-2xl flex flex-col overflow-hidden" (click)="$event.stopPropagation()">
            <!-- Modal Header -->
            <div class="flex justify-between items-center px-4 py-3 md:px-6 md:py-4 border-b border-gray-200 bg-slate-50 flex-shrink-0">
               <h3 class="text-base md:text-xl font-bold text-slate-800 flex items-center gap-2 md:gap-3">
                  <i class="fa-solid fa-chess-board text-indigo-600"></i> 
                  <span>策略回测 <span class="hidden md:inline">系统</span> <span class="text-xs md:text-sm font-normal text-gray-500 ml-1 md:ml-2">Code: {{ code() }}</span></span>
               </h3>
               <button (click)="closeStrategy()" class="text-gray-400 hover:text-slate-600 transition-colors bg-white rounded-full p-2 hover:bg-gray-200 w-8 h-8 md:w-10 md:h-10 flex items-center justify-center">
                  <i class="fa-solid fa-times text-lg md:text-xl"></i>
               </button>
            </div>

            <!-- Modal Body (The Retracement Split Layout) -->
            <div class="flex flex-col lg:flex-row h-full overflow-hidden bg-gray-50">
                <!-- Left Panel: Configuration -->
                <div class="w-full lg:w-80 flex-shrink-0 bg-white border-b lg:border-b-0 lg:border-r border-gray-200 overflow-y-auto custom-scrollbar p-4 md:p-5 flex flex-col gap-4 md:gap-6 shadow-[0_4px_12px_-4px_rgba(0,0,0,0.05)] lg:shadow-[4px_0_12px_-4px_rgba(0,0,0,0.05)] z-20 h-auto max-h-[40vh] lg:max-h-none lg:h-full">
                    <!-- Config Content -->
                    <div class="space-y-3">
                       <div class="text-[10px] font-bold text-gray-400 uppercase tracking-wider flex justify-between">
                          <span>基础设置</span>
                          <span class="text-indigo-500 cursor-pointer hover:underline" (click)="resetStrategyConfig()">重置默认</span>
                       </div>
                       <div class="grid grid-cols-2 gap-3">
                          <div>
                             <label class="text-xs text-gray-500 block mb-1">初始资金</label>
                             <input [(ngModel)]="strategyConfig.initialCapital" type="number" class="w-full px-2 py-1.5 border border-gray-200 rounded text-xs outline-none focus:border-indigo-500 transition-colors">
                          </div>
                          <div>
                             <label class="text-xs text-gray-500 block mb-1">佣金费率</label>
                             <input [(ngModel)]="strategyConfig.commission" type="number" step="0.0001" class="w-full px-2 py-1.5 border border-gray-200 rounded text-xs outline-none focus:border-indigo-500 transition-colors">
                          </div>
                       </div>
                       <div class="grid grid-cols-2 gap-3">
                          <div>
                             <label class="text-xs text-gray-500 block mb-1">开始日期</label>
                             <input [(ngModel)]="strategyConfig.startDate" type="date" class="w-full px-2 py-1.5 border border-gray-200 rounded text-xs outline-none focus:border-indigo-500 transition-colors">
                          </div>
                          <div>
                             <label class="text-xs text-gray-500 block mb-1">结束日期</label>
                             <input [(ngModel)]="strategyConfig.endDate" type="date" class="w-full px-2 py-1.5 border border-gray-200 rounded text-xs outline-none focus:border-indigo-500 transition-colors">
                          </div>
                       </div>
                    </div>

                    <div class="hidden md:block border-t border-gray-100"></div>

                    <div class="space-y-3 hidden md:block">
                       <div class="text-[10px] font-bold text-gray-400 uppercase tracking-wider">趋势与波段 (Golden Fib)</div>
                       <div class="flex justify-between items-center">
                          <label class="text-xs text-gray-600">趋势周期 (短/长)</label>
                          <div class="flex gap-2 w-32">
                             <input [(ngModel)]="strategyConfig.trendShortN" type="number" class="w-full px-2 py-1.5 border border-gray-200 rounded-lg text-xs text-center outline-none focus:border-indigo-500" placeholder="10">
                             <input [(ngModel)]="strategyConfig.trendLongM" type="number" class="w-full px-2 py-1.5 border border-gray-200 rounded-lg text-xs text-center outline-none focus:border-indigo-500" placeholder="20">
                          </div>
                       </div>
                       <div class="flex justify-between items-center">
                          <label class="text-xs text-gray-600">首加回调 (Add1)</label>
                          <div class="relative w-20">
                             <input [(ngModel)]="strategyConfig.fibCallback1" type="number" step="0.001" class="w-full px-2 py-1.5 border border-gray-200 rounded-lg text-xs text-right pr-5 outline-none focus:border-indigo-500">
                             <span class="absolute right-2 top-1.5 text-[10px] text-gray-400">%</span>
                          </div>
                       </div>
                       <div class="flex justify-between items-center">
                          <label class="text-xs text-gray-600">二加回调 (Add2)</label>
                          <div class="relative w-20">
                             <input [(ngModel)]="strategyConfig.fibCallback2" type="number" step="0.001" class="w-full px-2 py-1.5 border border-gray-200 rounded-lg text-xs text-right pr-5 outline-none focus:border-indigo-500">
                             <span class="absolute right-2 top-1.5 text-[10px] text-gray-400">%</span>
                          </div>
                       </div>
                    </div>

                    <div class="hidden md:block border-t border-gray-100"></div>

                    <div class="space-y-3 hidden md:block">
                       <div class="text-[10px] font-bold text-gray-400 uppercase tracking-wider flex justify-between items-center">
                          <span>仓位管理</span>
                          <div class="flex bg-gray-100 rounded p-0.5 border border-gray-200">
                             <button (click)="strategyConfig.posMode='PERCENT'" [class.bg-white]="strategyConfig.posMode==='PERCENT'" [class.shadow-sm]="strategyConfig.posMode==='PERCENT'" class="px-2 py-0.5 text-[10px] rounded transition-all">比例</button>
                             <button (click)="strategyConfig.posMode='FIXED'" [class.bg-white]="strategyConfig.posMode==='FIXED'" [class.shadow-sm]="strategyConfig.posMode==='FIXED'" class="px-2 py-0.5 text-[10px] rounded transition-all">金额</button>
                          </div>
                       </div>

                       <div class="grid grid-cols-2 gap-3 text-center">
                          <div>
                             <label class="text-[10px] text-gray-500 mb-1">底仓 {{strategyConfig.posMode==='PERCENT'?'%':'元'}}</label>
                             <input [(ngModel)]="strategyConfig.posInitial" type="number" class="w-full px-2 py-1.5 border border-gray-200 rounded-lg text-xs text-center outline-none focus:border-indigo-500">
                          </div>
                          <div>
                             <label class="text-[10px] text-gray-500 mb-1">总仓上限 %</label>
                             <input [(ngModel)]="strategyConfig.posMax" type="number" class="w-full px-2 py-1.5 border border-gray-200 rounded-lg text-xs text-center outline-none focus:border-indigo-500">
                          </div>
                       </div>
                    </div>

                    <div class="mt-auto pt-2 lg:pt-4 pb-2">
                       <button (click)="runAdvancedStrategy()" [disabled]="isStrategyLoading()" 
                               class="w-full py-2.5 md:py-3 bg-indigo-600 hover:bg-indigo-700 text-white font-bold rounded-lg md:rounded-xl shadow-lg shadow-indigo-100 transition-all active:scale-95 disabled:opacity-70 disabled:cursor-not-allowed flex items-center justify-center gap-2 text-sm">
                          @if (isStrategyLoading()) { 
                             <i class="fa-solid fa-circle-notch fa-spin"></i> 计算中...
                          } @else { 
                             <i class="fa-solid fa-rocket"></i> 执行回测 
                          }
                       </button>

                       @if (strategyErrorMsg()) {
                          <div class="mt-2 text-xs text-red-500 text-center bg-red-50 p-2 rounded border border-red-100">{{ strategyErrorMsg() }}</div>
                       }
                    </div>
                </div>

                <!-- Right Panel: Results -->
                <div class="flex-grow flex flex-col h-full overflow-hidden bg-gray-50 relative">
                     @if (!strategyResult()) {
                        <div class="flex flex-col items-center justify-center h-full text-gray-400 p-6 text-center">
                           <div class="w-16 h-16 md:w-20 md:h-20 bg-gray-100 rounded-full flex items-center justify-center mb-4">
                               <i class="fa-solid fa-chart-pie text-2xl md:text-3xl text-gray-300"></i>
                           </div>
                           <p class="text-sm">配置参数并点击左侧“执行回测”以开始</p>
                        </div>
                     } @else {
                        <!-- Stats Header -->
                        <div class="bg-white border-b border-gray-200 p-3 md:p-4 shadow-sm z-10 flex-shrink-0 grid grid-cols-3 md:grid-cols-6 gap-2 md:gap-4 overflow-x-auto">
                           <div class="text-center lg:text-left">
                              <p class="text-[9px] md:text-[10px] text-gray-400 uppercase tracking-wide">期末总资产</p>
                              <p class="text-sm md:text-lg font-mono font-bold text-slate-800">{{ strategyResult()!.finalBalance | number:'1.0-0' }}</p>
                           </div>
                           <div class="text-center lg:text-left">
                              <p class="text-[9px] md:text-[10px] text-gray-400 uppercase tracking-wide">总收益率</p>
                              <p class="text-sm md:text-lg font-mono font-bold" [class.text-red-500]="strategyResult()!.totalReturn > 0" [class.text-green-500]="strategyResult()!.totalReturn < 0">
                                 {{ strategyResult()!.totalReturn > 0 ? '+' : ''}}{{ strategyResult()!.totalReturn | number:'1.2-2' }}%
                              </p>
                           </div>
                           <div class="text-center lg:text-left">
                              <p class="text-[9px] md:text-[10px] text-gray-400 uppercase tracking-wide">最大回撤</p>
                              <p class="text-sm md:text-lg font-mono font-bold text-slate-700">{{ strategyResult()!.maxDrawdown | number:'1.2-2' }}%</p>
                           </div>
                           <div class="text-center lg:text-left">
