                           </div>
                        </div>
                     }
                </div>
            </div>
         </div>
       </div>
    }
  `,
  styles: [`
    .custom-scrollbar::-webkit-scrollbar { width: 4px; height: 4px; }
    .custom-scrollbar::-webkit-scrollbar-track { background: transparent; }
    .custom-scrollbar::-webkit-scrollbar-thumb { background: #cbd5e1; border-radius: 2px; }
  `]
})
export class DetailComponent implements OnInit {
  private route: ActivatedRoute = inject(ActivatedRoute);
  private etfService = inject(EtfService);
  private router = inject(Router);

  // ViewChilds
  chartContainer = viewChild<ElementRef>('chartContainer');
  strategyChartContainer = viewChild<ElementRef>('strategyChartContainer');

  code = signal<string>('');
  data = signal<ETFAnalysis | null>(null);

  // Moving Average Visibility Signals
  showMA5 = signal(true);
  showMA20 = signal(false);
  showMA60 = signal(false);

  // Overlay Visibility Signals
  showTrendChannel = signal(true);
  showFib = signal(true);
  // Grid and Chan removed as per request
  showSupRes = signal(false); 
  showVolume123 = signal(false);
  showResonance = signal(false); 
  showVolPrice = signal(false);
  showMASlope = signal(false);
  showStrategyMarkers = signal(false); // New Signal for R0-R10 Markers

  showDrawingsMenu = signal(false);

  ranges = [30, 60, 90, 120];
  selectedRange = signal<number>(60); 

  // --- Advanced Strategy State ---
  showStrategyModal = signal(false);
  isStrategyLoading = signal(false);
  strategyErrorMsg = signal<string | null>(null);

  strategyConfig: StrategyConfig = {
    etfCode: '', 
    startDate: '2020-01-01',
    endDate: new Date().toISOString().split('T')[0],
    initialCapital: 100000,
    commission: 0.0003,
    trendShortN: 10,
    trendLongM: 20,
    trendSlopeThreshold: 0.05, 
    fibCallback1: 0.328,
    fibCallback2: 0.618,
    fibExtension: 1.0,
    volBreakoutRatio: 1.5,
    volShrinkRatio: 0.6,
    posMode: 'PERCENT',
    posInitial: 30, 
    posAdd1: 0.3, 
    posAdd2: 0.7, 
    posMax: 80, 
    stopLossPct: 0.05,
    takeProfitPct: 0.30
  };

  strategyResult = signal<BacktestStats | null>(null);
  strategyLogs = signal<TradeLog[]>([]);
  strategyChartData = signal<{history: KlinePoint[], markers: any[], channels: ChannelPoint[]} | null>(null);

  resizeObserver: ResizeObserver | null = null;

  constructor() {
    effect(() => {
      const d = this.data();
      const container = this.chartContainer();

      // Trigger re-render on any signal change
      this.showMA5(); this.showMA20(); this.showMA60();
      // Grid removed
      this.showFib(); this.showTrendChannel(); this.showSupRes(); this.showVolume123();
      this.showResonance(); this.showVolPrice(); this.showMASlope();
      // Chan removed
      this.showStrategyMarkers();
      this.selectedRange();

      if (d && container) {
        setTimeout(() => this.renderChart(d, container), 0);
      }
    });

    // Effect for Strategy Chart
    effect(() => {
        const d = this.strategyChartData();
        const container = this.strategyChartContainer();
        if (this.showStrategyModal() && d && container) {
            setTimeout(() => this.renderStrategyChart(d, container), 0);
        }
    });

    // Resize Observer for Main Chart to handle mobile rotation
    effect(() => {
       const container = this.chartContainer();
       if (container) {
           if (this.resizeObserver) this.resizeObserver.disconnect();
           this.resizeObserver = new ResizeObserver(() => {
               const d = this.data();
               if(d) this.renderChart(d, container);
           });
           this.resizeObserver.observe(container.nativeElement);
       }
    });
  }

  ngOnInit() {
    this.route.paramMap.subscribe(params => {
      const c = params.get('code');
      if (c) {
        this.code.set(c);
        this.strategyConfig.etfCode = c;
        this.loadData(c);
      }
    });
  }

  ngOnDestroy() {
      if (this.resizeObserver) this.resizeObserver.disconnect();
  }

  loadData(code: string) {
    this.data.set(null);
    this.etfService.getEtfDetails(code).subscribe(res => {
      this.data.set(res);
    });
  }

  setRange(r: number) { this.selectedRange.set(r); }

  toggleMA(type: 'ma5' | 'ma20' | 'ma60') {
    if (type === 'ma5') this.showMA5.update(v => !v);
    if (type === 'ma20') this.showMA20.update(v => !v);
    if (type === 'ma60') this.showMA60.update(v => !v);
  }

  toggleDrawingsMenu() { this.showDrawingsMenu.update(v => !v); }
  toggleTrendChannel() { this.showTrendChannel.update(v => !v); }
  toggleFib() { this.showFib.update(v => !v); }
  toggleSupRes() { this.showSupRes.update(v => !v); }
  toggleVolume123() { this.showVolume123.update(v => !v); }
  toggleResonance() { this.showResonance.update(v => !v); }
  toggleVolPrice() { this.showVolPrice.update(v => !v); }
  toggleMASlope() { this.showMASlope.update(v => !v); }
  toggleStrategyMarkers() { this.showStrategyMarkers.update(v => !v); }

  // --- Strategy Methods ---
  openStrategy() {
      this.strategyConfig.etfCode = this.code();
      this.showStrategyModal.set(true);
      // Auto run if first open
      if (!this.strategyResult()) {
          this.runAdvancedStrategy();
      }
  }
  closeStrategy() { this.showStrategyModal.set(false); }

  resetStrategyConfig() {
      this.strategyConfig = {
        ...this.strategyConfig,
        trendShortN: 10, trendLongM: 20,
        fibCallback1: 0.328, fibCallback2: 0.618,
        volBreakoutRatio: 1.5, volShrinkRatio: 0.6,
        posMode: 'PERCENT', posInitial: 30, posAdd1: 0.3, posAdd2: 0.7, posMax: 80,
        stopLossPct: 0.05, takeProfitPct: 0.30
      };
  }

  runAdvancedStrategy() {
    if (!this.strategyConfig.etfCode) return;
    this.isStrategyLoading.set(true);
    this.strategyErrorMsg.set(null);
    this.strategyResult.set(null);

    this.etfService.getBacktestData(this.strategyConfig.etfCode).subscribe({
       next: (data) => {
          if (!data || data.history.length < 100) {
             this.strategyErrorMsg.set('数据不足，无法执行长周期回测');
             this.isStrategyLoading.set(false);
             return;
          }
          setTimeout(() => {
             this.executeAdvancedStrategy(data.history);
             this.isStrategyLoading.set(false);
          }, 100);
       },
       error: () => {
          this.strategyErrorMsg.set('数据获取失败');
          this.isStrategyLoading.set(false);
       }
    });
  }

  private executeAdvancedStrategy(fullHistory: KlinePoint[]) {
     const history = fullHistory.filter(d => d.date >= this.strategyConfig.startDate && d.date <= this.strategyConfig.endDate);
     if (history.length < 50) {
         this.strategyErrorMsg.set('选定区间内数据不足 (需要至少50天)');
         return;
     }

     let cash = this.strategyConfig.initialCapital;
     let shares = 0;
     let entryPrice = 0; 
     const tradeLogs: TradeLog[] = [];
     const markers: any[] = [];
     const equityCurve: {date: string, value: number}[] = [];
     const channels: ChannelPoint[] = [];

     let waveHigh = -Infinity;
     let waveLow = Infinity;
     let lastAction: TradeAction | 'NONE' = 'NONE';

     const M = this.strategyConfig.trendLongM;

     // Linear Regression Channel Helper
     const getSlopeAndChannel = (idx: number, period: number): {slope: number, top: number, bottom: number, middle: number} => {
         if (idx < period - 1) return { slope: 0, top: history[idx].high, bottom: history[idx].low, middle: history[idx].close };

         let sumX=0, sumY=0, sumXY=0, sumXX=0;
         const startIndex = idx - period + 1;

         for(let i=0; i<period; i++) {
             const p = history[startIndex + i];
             const x = i;
             const y = p.close;
             sumX += x; sumY += y; sumXY += x*y; sumXX += x*x;
         }

         const slope = (period * sumXY - sumX * sumY) / (period * sumXX - sumX * sumX);
         const intercept = (sumY - slope * sumX) / period;

         let maxDevHigh = -Infinity;
         let minDevLow = Infinity;

         for(let i=0; i<period; i++) {
             const p = history[startIndex + i];
             const regY = slope * i + intercept;
             maxDevHigh = Math.max(maxDevHigh, p.high - regY);
             minDevLow = Math.min(minDevLow, p.low - regY);
         }

         const currentX = period - 1;
         const currentMid = slope * currentX + intercept;

         return {
             slope: slope / history[idx].close, 
             middle: currentMid,
             top: currentMid + maxDevHigh,
             bottom: currentMid + minDevLow
         };
     };

     const buy = (idx: number, type: TradeAction, reason: string) => {
         const p = history[idx].close;
         let budget = 0;
         const totalAsset = cash + shares * p;

         if (type === '建') {
             if (this.strategyConfig.posMode === 'FIXED') budget = this.strategyConfig.posInitial;
             else budget = this.strategyConfig.initialCapital * (this.strategyConfig.posInitial / 100);
         } else if (type.includes('加')) {
             const initialBase = this.strategyConfig.posMode === 'FIXED' ? this.strategyConfig.posInitial : (this.strategyConfig.initialCapital * this.strategyConfig.posInitial/100);
             const multiplier = type === '加1' ? this.strategyConfig.posAdd1 : this.strategyConfig.posAdd2;
             budget = initialBase * multiplier;
         }

         const maxAsset = totalAsset * (this.strategyConfig.posMax / 100);
         const currentPosVal = shares * p;
         if (currentPosVal >= maxAsset) return; 

         budget = Math.min(budget, cash);
         budget = Math.min(budget, maxAsset - currentPosVal);

         const tradeShares = Math.floor(budget / p / 100) * 100;
         if (tradeShares <= 0) return;

         const cost = tradeShares * p;
         const fee = cost * this.strategyConfig.commission;

         if (cash < cost + fee) return;

         cash -= (cost + fee);
         entryPrice = (entryPrice * shares + cost) / (shares + tradeShares);
         shares += tradeShares;

         tradeLogs.push({
             date: history[idx].date, action: type, price: p, shares: tradeShares, amount: cost, reason,
             totalPosPercent: (shares*p)/(cash + shares*p)
         });
         markers.push({date: history[idx].date, type: 'BUY', label: type, price: p, reason: reason});
         lastAction = type;

         if (type === '建') {
             waveHigh = p; 
             waveLow = history.slice(Math.max(0, idx-30), idx).reduce((min, cur) => Math.min(min, cur.low), Infinity);
         }
     };

     const sell = (idx: number, type: TradeAction, reason: string, ratio: number = 1.0) => {
         if (shares === 0) return;
         const p = history[idx].close;
         const actualShares = Math.min(shares, Math.max(100, Math.floor(shares * ratio / 100) * 100));

         if (actualShares <= 0) return;

         const revenue = actualShares * p;
         const fee = revenue * this.strategyConfig.commission;
         const cost = actualShares * entryPrice;
         const pnl = revenue - fee - cost;

         cash += (revenue - fee);
         shares -= actualShares;
         if (shares < 100) { 
             const dustRev = shares * p;
             cash += dustRev;
             shares = 0;
         }

         tradeLogs.push({
             date: history[idx].date, action: type, price: p, shares: actualShares, amount: revenue, reason,
             pnlAmount: pnl, pnlRatio: (p - entryPrice)/entryPrice * 100,
             totalPosPercent: (shares*p)/(cash + shares*p)
         });
         markers.push({date: history[idx].date, type: 'SELL', label: type, price: p, reason: reason});
         lastAction = type;

         if (shares === 0) {
             lastAction = 'NONE';
             waveHigh = -Infinity;
         }
     };

     for (let i = M; i < history.length; i++) {
         const today = history[i];

         if (shares > 0) {
             if (today.high > waveHigh) waveHigh = today.high;
         }

         const channelInfo = getSlopeAndChannel(i, this.strategyConfig.trendLongM);
         channels.push({ date: today.date, ...channelInfo });

         const slopeShort = getSlopeAndChannel(i, this.strategyConfig.trendShortN).slope;
         const volAvg = history.slice(i-5, i).reduce((a,b)=>a+b.volume,0)/5;
         const volRatio = today.volume / (volAvg || 1);

         // 1. ENTRY
         if (shares === 0) {
             const recentHigh = Math.max(...history.slice(i-this.strategyConfig.trendShortN, i).map(d => d.high));
             if (today.close > recentHigh && channelInfo.slope > 0 && volRatio > this.strategyConfig.volBreakoutRatio) {
                 buy(i, '建', '突破新高+放量');
             }
         } 
         // 2. HOLDING
         else {
             const range = waveHigh - waveLow;
             const fib1 = waveHigh - range * this.strategyConfig.fibCallback1; 
             const fib2 = waveHigh - range * this.strategyConfig.fibCallback2; 

             // A. STOP LOSS
             if (today.close < entryPrice * (1 - this.strategyConfig.stopLossPct)) {
                 sell(i, '止损', '硬损触发');
                 continue;
             }
             if (range > 0 && today.close < waveHigh - range * 1.2) { 
                 sell(i, '清仓', '趋势破坏');
                 continue;
             }

             // B. ADD POSITIONS
             if (volRatio < this.strategyConfig.volShrinkRatio) {
                 if (today.low <= fib1 && today.close > fib1 * 0.98 && (lastAction as string) === '建') {
                     buy(i, '加1', '回调Fib1+缩量');
                 } else if (today.low <= fib2 && today.close > fib2 * 0.98 && ((lastAction as string) === '建' || (lastAction as string) === '加1')) {
                     buy(i, '加2', '回调Fib2+缩量');
                 }
             }

             // C. TAKE PROFIT
             if ((today.close - entryPrice) / entryPrice > this.strategyConfig.takeProfitPct) {
                 sell(i, '止盈2', '达到硬性止盈位');
                 continue;
             }
             const extPrice = waveHigh + range * this.strategyConfig.fibExtension;
             if (today.high >= extPrice) {
                 sell(i, '止盈1', '触及延伸目标位', 50); 
             }

             if (slopeShort < -0.02) { 
                 sell(i, '清仓', '短期趋势反转');
             }
         }

         equityCurve.push({date: today.date, value: cash + shares * today.close});
     }

     const finalBal = equityCurve[equityCurve.length-1].value;
     let peak = this.strategyConfig.initialCapital;
     let maxDd = 0;
     equityCurve.forEach(e => {
         if (e.value > peak) peak = e.value;
         const dd = (peak - e.value) / peak;
         if (dd > maxDd) maxDd = dd;
     });

     const totalTrades = tradeLogs.filter(t => t.pnlAmount !== undefined).length;
     const winningTrades = tradeLogs.filter(t => t.pnlAmount && t.pnlAmount > 0).length;

     this.strategyLogs.set(tradeLogs.reverse());
     this.strategyChartData.set({ history, markers, channels });
     this.strategyResult.set({
         finalBalance: finalBal,
         totalReturn: (finalBal - this.strategyConfig.initialCapital) / this.strategyConfig.initialCapital * 100,
         maxDrawdown: maxDd * 100,
         winRate: totalTrades > 0 ? (winningTrades / totalTrades) * 100 : 0,
         tradeCount: totalTrades,
         avgHoldDays: totalTrades > 0 ? Math.floor(history.length / totalTrades / 2) : 0, // Approx
         equityCurve,
         marketTypeStats: { bull: {wins:0,total:0}, bear: {wins:0,total:0}, sideways: {wins:0,total:0} }
     });
  }

  // --- Helpers for Template ---

  avgVolatility30d = computed(() => {
    const hist = this.data()?.history || [];
    if (hist.length < 30) return 0;
    const recent = hist.slice(-30);
    const sum = recent.reduce((acc, curr) => acc + (curr.high - curr.low) / curr.low, 0);
    return (sum / recent.length) * 100;
  });

  recentHistory = computed(() => {
    return this.data()?.history.slice(-30) || [];
  });

  fibLevels = computed<FibLevel[]>(() => {
    const d = this.data();
    if (!d || !d.history.length) return [];

    const range = this.selectedRange();
    const hist = d.history.slice(-range);
    const high = Math.max(...hist.map(k => k.high));
    const low = Math.min(...hist.map(k => k.low));
    const diff = high - low;

    const levels: FibLevel[] = [];

    if (d.trend === 'DOWN') {
        levels.push({ val: low, label: '0% (低点)', color: '#22c55e', dash: 'solid', isBase: true });
        levels.push({ val: high, label: '100% (高点)', color: '#ef4444', dash: 'solid' });
        levels.push({ val: low + diff * 0.382, label: '38.2% 压力', color: '#f97316', dash: '5,3' });
        levels.push({ val: low + diff * 0.5, label: '50.0% 中枢', color: '#94a3b8', dash: '3,3' });
        levels.push({ val: low + diff * 0.618, label: '61.8% 强压', color: '#ef4444', dash: '5,3' });
        levels.push({ val: low - diff * 0.382, label: '138.2% 拓展', color: '#22c55e', dash: '2,2', isExtension: true });
    } else {
        levels.push({ val: high, label: '0% (高点)', color: '#ef4444', dash: 'solid', isBase: true });
        levels.push({ val: low, label: '100% (低点)', color: '#22c55e', dash: 'solid' });
        levels.push({ val: high - diff * 0.382, label: '38.2% 支撑', color: '#f97316', dash: '5,3' });
        levels.push({ val: high - diff * 0.5, label: '50.0% 中枢', color: '#94a3b8', dash: '3,3' });
        levels.push({ val: high - diff * 0.618, label: '61.8% 强撑', color: '#22c55e', dash: '5,3' });
        levels.push({ val: high + diff * 0.382, label: '138.2% 拓展', color: '#ef4444', dash: '2,2', isExtension: true });
    }

    return levels;
  });

  getVolatilityPercent(point: KlinePoint): number {
      const hist = this.recentHistory();
      if (!hist.length) return 0;
      const maxAmp = Math.max(...hist.map(p => (p.high - p.low)/p.low));
      const currentAmp = (point.high - point.low) / point.low;
      return maxAmp > 0 ? (currentAmp / maxAmp) * 100 : 0;
  }

  translateSuggestion(s: string | undefined): string {
    if (!s) return '';
    const map: Record<string, string> = {
      'OBSERVE': '👁 观察点',
      'BUY_POINT': '🚩 建仓点',
      'HOLD': '✊ 持仓待涨',
      'TAKE_PROFIT_REDUCE': '🎯 止盈A',
      'TAKE_PROFIT_CLEAR': '💰 止盈B',
      'STOP_LOSS_REDUCE': '🛡 止损A',
      'STOP_LOSS_CLEAR': '❌ 清仓点',
      'WAIT': '⏳ 观望'
    };
    return map[s] || s;
  }

  // --- Chart Rendering ---

  renderChart(data: ETFAnalysis, containerRef: ElementRef) {
    const element = containerRef.nativeElement;
    d3.select(element).selectAll('*').remove();

    if (!data.history || data.history.length === 0) return;

    const range = this.selectedRange();
    const history = data.history.slice(-range);

    const margin = { top: 20, right: 50, bottom: 30, left: 10 };
    const width = element.clientWidth - margin.left - margin.right;
    const height = element.clientHeight - margin.top - margin.bottom;

    const mainH = height * 0.65;
    const volH = height * 0.15;
    const macdH = height * 0.15;
    const gap = height * 0.025;

    const svg = d3.select(element).append('svg')
      .attr('width', width + margin.left + margin.right)
      .attr('height', height + margin.top + margin.bottom)
      .append('g')
      .attr('transform', `translate(${margin.left},${margin.top})`);

    const x = d3.scaleBand()
      .domain(history.map(d => d.date))
      .range([0, width])
      .padding(0.2);

    // Initial Y Domain from Data
    let yMin = d3.min(history, d => d.low)! * 0.98;
    let yMax = d3.max(history, d => d.high)! * 1.02;

    // Expand Domain for Fib Extensions
    if (this.showFib()) {
       const fibs = this.fibLevels();
       if (fibs.length > 0) {
           const minFib = Math.min(...fibs.map(f => f.val));
           const maxFib = Math.max(...fibs.map(f => f.val));
           yMin = Math.min(yMin, minFib * 0.99); // Expand down if needed
           yMax = Math.max(yMax, maxFib * 1.01); // Expand up if needed
       }
    }

    const y = d3.scaleLinear().domain([yMin, yMax]).range([mainH, 0]);

    const volMax = d3.max(history, d => d.volume)!;
    const yVol = d3.scaleLinear().domain([0, volMax]).range([mainH + volH + gap, mainH + gap]);

    const macdVals = history.flatMap(d => [d.macd?.diff || 0, d.macd?.dea || 0, d.macd?.macd || 0]);
    const macdLimit = Math.max(Math.abs(d3.min(macdVals) || 0), Math.abs(d3.max(macdVals) || 0));
    const macdTop = mainH + volH + 2 * gap;
    const yMacd = d3.scaleLinear().domain([-macdLimit, macdLimit]).range([height, macdTop]);

    // Axis
    const xAxis = d3.axisBottom(x)
       .tickValues(x.domain().filter((d, i) => i % Math.floor(history.length / 5) === 0))
       .tickFormat(d => d.slice(5)); 

    svg.append('g').attr('transform', `translate(0,${height})`).call(xAxis).attr('class', 'text-gray-400 text-[10px]');
    svg.append('g').attr('transform', `translate(${width},0)`).call(d3.axisRight(y).ticks(5)).attr('class', 'text-gray-400 text-[10px]');

    // Layers
    if (this.showTrendChannel()) drawTrendChannel(svg, history, x, y, width);

    if (this.showFib()) {
       const fibs = this.fibLevels(); // Recalculate based on current computed
       drawFibonacci(svg, fibs, width, y, 0, mainH); // Pass mainH instead of height for correct scaling
    }

    drawBaseLayer(svg, history, x, y, width, {
        showGrid: false, // Removed Grid Toggle
        showMA5: this.showMA5(),
        showMA20: this.showMA20(),
        showMA60: this.showMA60()
    });

    if (this.showSupRes()) drawSupRes(svg, history, x, y, width, svg);
    if (this.showVolume123()) drawVolumeProfile(svg, history, x, y, width);
    if (this.showResonance() && data.boxSignal) drawResonanceSignal(svg, data.boxSignal, x, y, width);
    if (this.showVolPrice()) drawVolPriceMomentum(svg, history, x, y, width);
    if (this.showMASlope()) drawMASlope(svg, history, x, y);
    // Chan structure removed
    if (this.showStrategyMarkers()) drawStrategyMarkers(svg, history, x, y, width);

    const volGroup = svg.append('g');
    const macdGroup = svg.append('g');
    drawSubCharts(volGroup, macdGroup, history, x, yVol, yMacd, mainH + volH + gap, height - macdTop, width, macdTop);

    // Crosshair
    const tooltip = d3.select(element).append('div')
         .attr('class', 'chart-tooltip')
         .style('display', 'none')
         .style('pointer-events', 'none')
         .style('position', 'absolute')
         .style('z-index', '20')
         .style('background', 'rgba(255,255,255,0.95)')
         .style('padding', '8px')
         .style('border', '1px solid #e2e8f0')
         .style('border-radius', '4px')
         .style('box-shadow', '0 4px 6px -1px rgba(0, 0, 0, 0.1)')
         .style('font-size', '10px');

    const crosshairX = svg.append('line').attr('stroke', '#94a3b8').attr('stroke-width', 1).attr('stroke-dasharray', '3,3').style('display', 'none').style('pointer-events', 'none');
    const crosshairY = svg.append('line').attr('stroke', '#94a3b8').attr('stroke-width', 1).attr('stroke-dasharray', '3,3').style('display', 'none').style('pointer-events', 'none');

    svg.append('rect')
       .attr('width', width).attr('height', height)
       .attr('fill', 'transparent')
       .style('cursor', 'crosshair')
       .on('mousemove', (event) => {
           const [mx, my] = d3.pointer(event);
           const step = x.step();
           const index = Math.floor(mx / step);
           if (index >= 0 && index < history.length) {
               const d = history[index];
               const xPos = (x(d.date) ?? 0) + x.bandwidth()/2;

               crosshairX.attr('x1', xPos).attr('x2', xPos).attr('y1', 0).attr('y2', height).style('display', null);
               crosshairY.attr('x1', 0).attr('x2', width).attr('y1', my).attr('y2', my).style('display', null);

               let html = `<div class="font-bold mb-1">${d.date}</div>`;
               html += `<div class="flex justify-between gap-4"><span>收盘:</span><span>${d.close.toFixed(3)}</span></div>`;
               html += `<div class="flex justify-between gap-4"><span>涨跌:</span><span class="${d.close>d.open?'text-red-500':'text-green-500'}">${((d.close-d.open)/d.open*100).toFixed(2)}%</span></div>`;
               html += `<div class="flex justify-between gap-4"><span>成交:</span><span>${(d.volume/10000).toFixed(0)}万</span></div>`;

               const box = element.getBoundingClientRect();
               let left = mx + 20;
               let top = my + 20;
               if (left + 150 > width) left = mx - 140;

               tooltip.html(html)
                 .style('display', 'block')
                 .style('left', `${left}px`)
                 .style('top', `${top}px`);
           } else {
               crosshairX.style('display', 'none');
               crosshairY.style('display', 'none');
               tooltip.style('display', 'none');
           }
       })
       .on('mouseleave', () => {
           crosshairX.style('display', 'none');
           crosshairY.style('display', 'none');
           tooltip.style('display', 'none');
       });
  }

  private renderStrategyChart(data: {history: KlinePoint[], markers: any[], channels: ChannelPoint[]}, containerRef: ElementRef) {
     const element = containerRef.nativeElement;
     d3.select(element).selectAll('*').remove();

     const { history, markers, channels } = data;
     if (!history.length) return;

     const margin = { top: 20, right: 40, bottom: 20, left: 10 };
     const width = element.clientWidth - margin.left - margin.right;
     const height = element.clientHeight - margin.top - margin.bottom;

     const svg = d3.select(element).append('svg')
        .attr('width', width + margin.left + margin.right)
        .attr('height', height + margin.top + margin.bottom)
        .append('g')
        .attr('transform', `translate(${margin.left},${margin.top})`);

     const x = d3.scaleBand().domain(history.map(d => d.date)).range([0, width]).padding(0.2);
     const yMin = d3.min(history, d => d.low)! * 0.95;
     const yMax = d3.max(history, d => d.high)! * 1.05;
     const y = d3.scaleLinear().domain([yMin, yMax]).range([height, 0]);

     const xAxis = d3.axisBottom(x)
        .tickValues(x.domain().filter((d, i) => i % Math.floor(history.length / 5) === 0))
        .tickFormat(d => d.slice(2)); 

     svg.append('g').attr('transform', `translate(0,${height})`).call(xAxis).attr('class', 'text-gray-400 text-[9px]');
     svg.append('g').attr('transform', `translate(${width},0)`).call(d3.axisRight(y).ticks(5)).attr('class', 'text-gray-400 text-[9px]');

     // Trend Channels
     const channelSegments: { type: 'UP'|'DOWN', points: ChannelPoint[] }[] = [];
     let currentSegment: { type: 'UP'|'DOWN', points: ChannelPoint[] } | null = null;

     channels.forEach(pt => {
         const type = pt.slope >= 0 ? 'UP' : 'DOWN';
         if (!currentSegment || currentSegment.type !== type) {
             if (currentSegment) channelSegments.push(currentSegment);
             currentSegment = { type, points: [pt] };
         } else {
             currentSegment.points.push(pt);
         }
     });
     if (currentSegment) channelSegments.push(currentSegment);

     const areaGen = d3.area<ChannelPoint>().x(d => (x(d.date) ?? 0) + x.bandwidth()/2).y0(d => y(d.bottom)).y1(d => y(d.top)).curve(d3.curveMonotoneX);
     const lineTop = d3.line<ChannelPoint>().x(d => (x(d.date) ?? 0) + x.bandwidth()/2).y(d => y(d.top)).curve(d3.curveMonotoneX);
     const lineBottom = d3.line<ChannelPoint>().x(d => (x(d.date) ?? 0) + x.bandwidth()/2).y(d => y(d.bottom)).curve(d3.curveMonotoneX);

     channelSegments.forEach(seg => {
         svg.append('path').datum(seg.points).attr('fill', seg.type === 'UP' ? '#fecaca' : '#bbf7d0').attr('fill-opacity', 0.4).attr('d', areaGen);
         const borderColor = seg.type === 'UP' ? '#ef4444' : '#22c55e';
         svg.append('path').datum(seg.points).attr('fill', 'none').attr('stroke', borderColor).attr('stroke-width', 1).attr('stroke-dasharray', '2,2').attr('d', lineTop);
         svg.append('path').datum(seg.points).attr('fill', 'none').attr('stroke', borderColor).attr('stroke-width', 1).attr('stroke-dasharray', '2,2').attr('d', lineBottom);
     });

     // Candles
     const candles = svg.selectAll('.candle').data(history).enter().append('g');
     candles.append('line').attr('x1', d => (x(d.date) ?? 0) + x.bandwidth()/2).attr('x2', d => (x(d.date) ?? 0) + x.bandwidth()/2).attr('y1', d => y(d.high)).attr('y2', d => y(d.low)).attr('stroke', d => d.close > d.open ? '#ef4444' : '#22c55e');
     candles.append('rect').attr('x', d => x(d.date) ?? 0).attr('y', d => y(Math.max(d.open, d.close))).attr('width', x.bandwidth()).attr('height', d => Math.max(1, Math.abs(y(d.open) - y(d.close)))).attr('fill', d => d.close > d.open ? '#ef4444' : '#22c55e');

     // Markers
     markers.forEach(m => {
         const mx = x(m.date);
         if (mx === undefined) return;
         const cx = mx + x.bandwidth()/2;
         const cy = y(m.price);
         const isBuy = m.type === 'BUY';
         const color = isBuy ? '#10b981' : (m.label.includes('止盈') ? '#f97316' : '#3b82f6');
         svg.append('circle').attr('cx', cx).attr('cy', isBuy ? cy + 10 : cy - 10).attr('r', 3).attr('fill', color);
         svg.append('text').attr('x', cx).attr('y', isBuy ? cy + 20 : cy - 12).text(m.label).attr('fill', color).attr('font-size', '8px').attr('text-anchor', 'middle').attr('font-weight', 'bold');
     });

     // Tooltip
     const tooltip = d3.select(element).append('div').attr('class', 'chart-tooltip').style('display', 'none').style('pointer-events', 'none').style('position', 'absolute').style('z-index', '20').style('background', 'rgba(255,255,255,0.95)').style('padding', '6px').style('border', '1px solid #e2e8f0').style('border-radius', '4px').style('box-shadow', '0 4px 6px -1px rgba(0, 0, 0, 0.1)').style('font-size', '10px');
     const crosshairX = svg.append('line').attr('stroke', '#94a3b8').attr('stroke-width', 1).attr('stroke-dasharray', '3,3').style('display', 'none').style('pointer-events', 'none');
     const crosshairY = svg.append('line').attr('stroke', '#94a3b8').attr('stroke-width', 1).attr('stroke-dasharray', '3,3').style('display', 'none').style('pointer-events', 'none');

     svg.append('rect').attr('width', width).attr('height', height).attr('fill', 'transparent').style('cursor', 'crosshair')
       .on('mousemove', (event) => {
           const [mx, my] = d3.pointer(event);
           const step = x.step();
           const index = Math.floor(mx / step);
           if (index >= 0 && index < history.length) {
               const d = history[index];
               const xPos = (x(d.date) ?? 0) + x.bandwidth()/2;

               crosshairX.attr('x1', xPos).attr('x2', xPos).attr('y1', 0).attr('y2', height).style('display', null);
               crosshairY.attr('x1', 0).attr('x2', width).attr('y1', my).attr('y2', my).style('display', null);

               const m = markers.find(mark => mark.date === d.date);

               let html = `<div class="font-bold mb-1">${d.date}</div>`;
               html += `<div class="flex justify-between gap-4"><span>收盘:</span><span>${d.close.toFixed(3)}</span></div>`;

               if (m) {
                   html += `<div class="mt-2 pt-1 border-t border-gray-200 font-bold ${m.type==='BUY'?'text-red-600':'text-green-600'}">${m.label}</div>`;
                   if (m.reason) html += `<div class="text-gray-500 max-w-[150px] whitespace-normal">${m.reason}</div>`;
               }

               let left = mx + 20;
               let top = my + 20;
               if (left + 150 > width) left = mx - 140;

               tooltip.html(html)
                 .style('display', 'block')
                 .style('left', `${left}px`)
                 .style('top', `${top}px`);
           } else {
               crosshairX.style('display', 'none');
               crosshairY.style('display', 'none');
               tooltip.style('display', 'none');
           }
       })
       .on('mouseleave', () => {
           crosshairX.style('display', 'none');
           crosshairY.style('display', 'none');
           tooltip.style('display', 'none');
       });
  }
}

import * as d3 from 'd3';
import { KlinePoint, BoxSignal } from '../../../services/etf.service';
import { SelectionGroup, ScaleBand, ScaleLinear } from './types';

// --- 4. Volume Profile + 123 Painter ---
export function drawVolumeProfile(
    container: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    y: ScaleLinear,
    width: number
) {
    const yMin = y.domain()[0];
    const yMax = y.domain()[1];
    const binCount = 50;
    const binSize = (yMax - yMin) / binCount;
    const bins = new Array(binCount).fill(0);
    let maxVolBin = 0;
    let maxVolIdx = 0;

    data.forEach(d => {
        const idx = Math.floor((d.close - yMin) / binSize);
        if (idx >= 0 && idx < binCount) {
            bins[idx] += d.volume;
            if (bins[idx] > maxVolBin) {
                maxVolBin = bins[idx];
                maxVolIdx = idx;
            }
        }
    });

    const pocPrice = yMin + (maxVolIdx + 0.5) * binSize;
    const maxBarWidth = width * 0.2; 
    const vpGroup = container.append('g').attr('transform', `translate(${width}, 0)`);

    bins.forEach((vol, i) => {
        const barW = (vol / maxVolBin) * maxBarWidth;
        const barY = y(yMin + (i+1)*binSize);
        const barH = Math.abs(y(yMin + i*binSize) - barY);

        vpGroup.append('rect')
            .attr('x', -barW)
            .attr('y', barY)
            .attr('width', barW)
            .attr('height', barH)
            .attr('fill', i === maxVolIdx ? '#eab308' : '#64748b') 
            .attr('opacity', i === maxVolIdx ? 0.4 : 0.1);
    });

    container.append('line')
        .attr('x1', 0).attr('x2', width)
        .attr('y1', y(pocPrice)).attr('y2', y(pocPrice))
        .attr('stroke', '#eab308').attr('stroke-width', 1.5).attr('stroke-dasharray', '4,2');

    container.append('text')
        .attr('x', width - 5).attr('y', y(pocPrice) - 4)
        .text('POC (筹码峰)').attr('fill', '#eab308')
        .attr('font-size', '10px').attr('font-weight', 'bold').attr('text-anchor', 'end');

    // ZigZag / Wave Theory
    const zigzag: {x: number, y: number, date: string, type: 'HIGH'|'LOW'}[] = [];
    const lookback = Math.max(3, Math.floor(data.length / 20));

    for(let i=lookback; i<data.length-lookback; i++) {
            const d = data[i];
            const range = data.slice(i-lookback, i+lookback+1);
            const isHigh = range.every(item => item.high <= d.high);
            const isLow = range.every(item => item.low >= d.low);

            if (isHigh) zigzag.push({x: i, y: d.high, date: d.date, type: 'HIGH'});
            else if (isLow) zigzag.push({x: i, y: d.low, date: d.date, type: 'LOW'});
    }

    const cleanZigzag: typeof zigzag = [];
    zigzag.forEach(p => {
        if (cleanZigzag.length === 0) { cleanZigzag.push(p); return; }
        const last = cleanZigzag[cleanZigzag.length-1];
        if (last.type !== p.type) {
            cleanZigzag.push(p);
        } else {
            if (p.type === 'HIGH' && p.y > last.y) cleanZigzag[cleanZigzag.length-1] = p;
            if (p.type === 'LOW' && p.y < last.y) cleanZigzag[cleanZigzag.length-1] = p;
        }
    });

    const lineGen = d3.line<{x:number, y:number, date: string}>()
        .x(d => x(d.date)! + x.bandwidth()/2)
        .y(d => y(d.y));

    // Draw Thin Black Lines for Segments
    container.append('path')
        .datum(cleanZigzag)
        .attr('fill', 'none')
        .attr('stroke', '#000000') 
        .attr('stroke-width', 1)
        .attr('opacity', 0.8)
        .attr('d', (d) => lineGen(d.map(p => ({x: p.x, y: p.y, date: p.date}))));

    // Draw Wave Labels (1, 2, 3, 4, 5, A, B, C)
    const waveLabels = ['1', '2', '3', '4', '5', 'A', 'B', 'C'];

    if (cleanZigzag.length > 0) {
        cleanZigzag.forEach((p, idx) => {
            const px = x(p.date)! + x.bandwidth()/2;
            const py = y(p.y);
            const label = waveLabels[idx % waveLabels.length];

            // Offset logic: HIGH above candle, LOW below candle
            const yOffset = p.type === 'HIGH' ? -15 : 15;

            const g = container.append('g').attr('transform', `translate(${px}, ${py + yOffset})`);

            // Purple Hollow Circle
            g.append('circle')
                .attr('r', 7)
                .attr('fill', 'white')
                .attr('stroke', '#a855f7') // Purple
                .attr('stroke-width', 1.5);

            // Text inside circle
            g.append('text')
                .text(label)
                .attr('dy', '0.35em')
                .attr('text-anchor', 'middle')
                .attr('fill', '#a855f7')
                .attr('font-size', '9px')
                .attr('font-weight', 'bold');
        });
    }
}

// --- 5. Resonance Signal Painter (Box Strategy) ---
export function drawResonanceSignal(
    container: SelectionGroup,
    signal: BoxSignal,
    x: ScaleBand,
    y: ScaleLinear,
    width: number
) {
    if (!signal || !signal.valid) return;

    const boxStartX = x(signal.boxStartDate);
    const obsX = x(signal.obsDate);
    const entryX = x(signal.date);
    const yHigh = y(signal.boxHigh);
    const yLow = y(signal.boxLow);
    const yPoc = y(signal.poc);
    const lineStart = boxStartX !== undefined ? boxStartX : (entryX !== undefined ? 0 : 0);

    if (entryX !== undefined || (boxStartX !== undefined)) {
            container.append('line').attr('x1', lineStart).attr('x2', width).attr('y1', yLow).attr('y2', yLow).attr('stroke', '#334155').attr('stroke-width', 2).attr('stroke-opacity', 0.8);
            container.append('line').attr('x1', lineStart).attr('x2', width).attr('y1', yHigh).attr('y2', yHigh).attr('stroke', '#334155').attr('stroke-width', 2).attr('stroke-opacity', 0.8);
            container.append('line').attr('x1', lineStart).attr('x2', width).attr('y1', yPoc).attr('y2', yPoc).attr('stroke', '#f97316').attr('stroke-width', 1).attr('stroke-dasharray', '4,2');
            if (boxStartX !== undefined) {
            container.append('text').attr('x', boxStartX + 5).attr('y', yPoc - 3).text('POC').attr('fill', '#f97316').attr('font-size', '10px');
            }
    }
    if (obsX !== undefined) {
            container.append('text').attr('x', obsX + x.bandwidth()/2).attr('y', yHigh - 10).text('👁').attr('font-size', '14px').attr('text-anchor', 'middle');
    }
    if (entryX !== undefined) {
        const cx = entryX + x.bandwidth()/2;
        const yEntry = y(signal.entryPrice);
        container.append('text').attr('x', cx).attr('y', yEntry + 15).text('🚩').attr('font-size', '14px').attr('text-anchor', 'middle');
        container.append('text').attr('x', cx).attr('y', yEntry + 28).text('建仓').attr('fill', '#ef4444').attr('font-size', '10px').attr('text-anchor', 'middle').attr('font-weight', 'bold');
    }

    const drawTarget = (val: number, label: string, color: string, icon: string) => {
        const yPos = y(val);
        container.append('line').attr('x1', 0).attr('x2', width).attr('y1', yPos).attr('y2', yPos).attr('stroke', color).attr('stroke-width', 1).attr('opacity', 0.8); 
        container.append('text').attr('x', 5).attr('y', yPos - 4).text(icon).attr('font-size', '14px').attr('text-anchor', 'start');
        container.append('text').attr('x', 25).attr('y', yPos - 4).text(`${label} : ${val.toFixed(3)}`).attr('fill', color).attr('font-size', '10px').attr('font-weight', 'bold').attr('text-anchor', 'start');
    };
    drawTarget(signal.tpA, '止盈A', '#ef4444', '🎯');
    drawTarget(signal.tpB, '止盈B', '#ef4444', '💰');
    drawTarget(signal.slA, '止损A', '#22c55e', '🛡');
    drawTarget(signal.slB, '止损B', '#22c55e', '🛑');
}

// --- 6. Vol/Price Momentum Painter ---
export function drawVolPriceMomentum(
    container: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    y: ScaleLinear,
    width: number
) {
    const lastPt = data[data.length-1];
    if (lastPt.boll && lastPt.boll.width <= 0.10) { // Arbitrary small width
            // Squeeze Logic visualization is simpler as a badge usually
            return;
    }

    // Bias Line
    const biasData = data.filter(d => d.ma60);
    if (biasData.length > 0) {
        const lineBias = d3.line<KlinePoint>().x(d => x(d.date)! + x.bandwidth()/2).y(d => y(d.ma60! * 1.05)).curve(d3.curveMonotoneX);
        container.append('path').datum(biasData).attr('fill', 'none').attr('stroke', '#a855f7').attr('stroke-width', 1).attr('stroke-dasharray', '4,4').attr('d', lineBias);
    }

    for(let i=0; i<data.length; i++) {
        const d = data[i];
        const xPos = x(d.date)! + x.bandwidth()/2;

        // ATR Zone
        if (d.ma20 && d.atr) {
            const upper = y(d.ma20 + 0.5 * d.atr);
            const lower = y(d.ma20 - 0.5 * d.atr);
            container.append('line').attr('x1', xPos).attr('x2', xPos).attr('y1', upper).attr('y2', lower).attr('stroke', '#cbd5e1').attr('stroke-width', 4).attr('opacity', 0.3);
        }

        // Rocket
        if (d.ma20Slope !== undefined && d.ma60Slope !== undefined) {
            if (d.ma20Slope > d.ma60Slope && d.ma60Slope > 0.2 && d.close > d.open) {
                    container.append('text').attr('x', xPos).attr('y', y(d.low) + 20).text('🚀').attr('font-size', '10px').attr('text-anchor', 'middle');
            }
        }

        // Volume Spikes
        const startV = Math.max(0, i - 20);
        const sub = data.slice(startV, i);
        const avgVol = sub.length ? sub.reduce((a,b)=>a+b.volume,0)/sub.length : d.volume;

        if (d.volume > 3 * avgVol && d.close > d.open) {
            container.append('text').attr('x', xPos).attr('y', y(d.high) - 5).text('🔥').attr('font-size', '12px').attr('text-anchor', 'middle');
        }
        if (d.volume < 0.5 * avgVol && d.close < d.open) {
                container.append('text').attr('x', xPos).attr('y', y(d.low) + 15).text('🧊').attr('font-size', '12px').attr('text-anchor', 'middle');
        }
    }
}

// --- 7. MA Slope Painter ---
export function drawMASlope(
    container: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    y: ScaleLinear
) {
    for(let i=1; i<data.length; i++) {
        const d = data[i];
        const prev = data[i-1];
        if (d.ma5 && d.ma10 && d.ma20 && prev.ma5 && prev.ma10 && prev.ma20) {
            const s5 = d.ma5 - prev.ma5;
            const s10 = d.ma10 - prev.ma10;
            const s20 = d.ma20 - prev.ma20;
            if (s5 > 0 && s10 > 0 && s20 > 0 && d.ma5 > d.ma10 && d.ma10 > d.ma20) {
                const xPos = x(d.date)! + x.bandwidth()/2;
                const yLow = y(d.low);
                container.append('text').attr('x', xPos).attr('y', yLow + 25).text('⬆️').attr('fill', '#ec4899').attr('font-size', '10px').attr('text-anchor', 'middle');
            }
        }
    }
}

// --- 8. Chan Structure Painter ---
export function drawChanStruct(
    container: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    y: ScaleLinear
) {
    const fractals: {x: number, y: number, type: 'TOP'|'BTM', date: string}[] = [];
    for(let i=2; i<data.length-2; i++) {
        const d = data[i];
        const l = data[i-1]; const ll = data[i-2];
        const r = data[i+1]; const rr = data[i+2];
        if (d.high > l.high && d.high > ll.high && d.high > r.high && d.high > rr.high) {
            fractals.push({x: x(d.date)! + x.bandwidth()/2, y: y(d.high), type: 'TOP', date: d.date});
        }
        else if (d.low < l.low && d.low < ll.low && d.low < r.low && d.low < rr.low) {
            fractals.push({x: x(d.date)! + x.bandwidth()/2, y: y(d.low), type: 'BTM', date: d.date});
        }
    }
    const strokes: {x: number, y: number}[] = [];
    let lastType: 'TOP' | 'BTM' | null = null;
    fractals.forEach(f => {
        if (lastType === null || lastType !== f.type) {
            strokes.push({x: f.x, y: f.y});
            lastType = f.type;
        } else {
            const lastStroke = strokes[strokes.length-1];
            if (f.type === 'TOP' && f.y < lastStroke.y) { 
                    strokes[strokes.length-1] = {x: f.x, y: f.y};
            } else if (f.type === 'BTM' && f.y > lastStroke.y) { 
                    strokes[strokes.length-1] = {x: f.x, y: f.y};
            }
        }
    });
    if (strokes.length > 1) {
        const lineGen = d3.line<{x: number, y: number}>().x(d => d.x).y(d => d.y);
        container.append('path').datum(strokes).attr('d', lineGen).attr('fill', 'none').attr('stroke', '#334155').attr('stroke-width', 2);
    }
}

// --- 11. Strategy Markers Painter ---
export function drawStrategyMarkers(
    container: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    y: ScaleLinear,
    width: number
) {
    // Identify simple strategy points for visualization
    for (let i = 20; i < data.length; i++) {
        const d = data[i];
        // Example Strategy: Breakout of 20-day high with volume
        const lookback = data.slice(i-20, i);
        const highest = Math.max(...lookback.map(p => p.high));
        const volAvg = lookback.slice(-5).reduce((a, b) => a + b.volume, 0) / 5;

        if (d.close > highest && d.volume > 1.5 * volAvg) {
             const cx = x(d.date)! + x.bandwidth()/2;
             const cy = y(d.low);

             container.append('circle')
                .attr('cx', cx).attr('cy', cy + 12)
                .attr('r', 3).attr('fill', '#ef4444');

             container.append('text')
                .attr('x', cx).attr('y', cy + 22)
                .text('B')
                .attr('fill', '#ef4444').attr('font-size', '9px').attr('text-anchor', 'middle').attr('font-weight', 'bold');
        }
    }
}

import * as d3 from 'd3';
import { KlinePoint } from '../../../services/etf.service';
import { SelectionGroup, ScaleBand, ScaleLinear, FibLevel, calculateLR } from './types';

// --- 1. Base Layer Painter (Candles, MAs) ---
export function drawBaseLayer(
    container: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    y: ScaleLinear,
    width: number,
    options: { showMA5: boolean, showMA20: boolean, showMA60: boolean }
) {
    // Candles
    const candles = container.selectAll('.candle').data(data).enter().append('g').attr('class', 'candle');
    candles.append('line')
        .attr('x1', d => x(d.date)! + x.bandwidth() / 2)
        .attr('x2', d => x(d.date)! + x.bandwidth() / 2)
        .attr('y1', d => y(d.high))
        .attr('y2', d => y(d.low))
        .attr('stroke', d => d.close > d.open ? '#ef4444' : '#22c55e').attr('stroke-width', 1);
    candles.append('rect')
        .attr('x', d => x(d.date)!)
        .attr('y', d => y(Math.max(d.open, d.close)))
        .attr('width', x.bandwidth())
        .attr('height', d => Math.max(1, Math.abs(y(d.open) - y(d.close))))
        .attr('fill', d => d.close > d.open ? '#ef4444' : '#22c55e')
        .attr('stroke', d => d.close > d.open ? '#ef4444' : '#22c55e');

    // MAs
    const drawMA = (key: 'ma5' | 'ma20' | 'ma60', color: string) => {
        const maData = data.filter(d => d[key]);
        const maLine = d3.line<KlinePoint>()
            .x(d => x(d.date)! + x.bandwidth() / 2)
            .y(d => y(d[key] as number))
            .curve(d3.curveMonotoneX);
        container.append('path').datum(maData)
            .attr('fill', 'none').attr('stroke', color).attr('stroke-width', 1.5).attr('d', maLine);
    };

    if (options.showMA5) drawMA('ma5', '#a855f7');
    if (options.showMA20) drawMA('ma20', '#f97316');
    if (options.showMA60) drawMA('ma60', '#3b82f6');
}

// --- 2. Smart Lines Painter (Support/Resistance & Trend Strength) ---
export function drawSupRes(
    container: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    y: ScaleLinear,
    width: number,
    svg: SelectionGroup // Need SVG for badges outside clip
) {
    const pivotWindow = 5; 
    const N = 10; 

    const pivots: {type: 'HIGH'|'LOW', x: number, y: number}[] = [];
    for(let i = pivotWindow; i < data.length - pivotWindow; i++) {
        const curr = data[i];
        const range = data.slice(i-pivotWindow, i+pivotWindow+1);
        if (range.every(d => d.high <= curr.high)) pivots.push({type: 'HIGH', x: i, y: curr.high});
        if (range.every(d => d.low >= curr.low)) pivots.push({type: 'LOW', x: i, y: curr.low});
    }

    const lows = pivots.filter(p => p.type === 'LOW').slice(-N); 
    if (lows.length >= 3) {
        const lr = calculateLR(lows);
        let validCount = 0;
        lows.forEach(p => {
            const predictedY = lr.slope * p.x + lr.intercept;
            if (Math.abs(p.y - predictedY)/predictedY <= 0.01) validCount++; // Slightly looser tolerance
        });

        if (validCount >= 2) { // Relaxed rule
            const x1 = 0; const x2 = data.length - 1;
            container.append('line')
                .attr('x1', 0).attr('x2', width)
                .attr('y1', y(lr.slope * x1 + lr.intercept))
                .attr('y2', y(lr.slope * x2 + lr.intercept))
                .attr('stroke', '#22c55e').attr('stroke-width', 1.5);
            container.append('text').attr('x', width-5).attr('y', y(lr.slope * x2 + lr.intercept)-5)
                .text('智能支撑').attr('fill', '#22c55e').attr('text-anchor', 'end').attr('font-size', '10px');
        }
    }

    const highs = pivots.filter(p => p.type === 'HIGH').slice(-N);
    if (highs.length >= 3) {
        const lr = calculateLR(highs);
        let validCount = 0;
        highs.forEach(p => {
            const predictedY = lr.slope * p.x + lr.intercept;
            if (Math.abs(p.y - predictedY)/predictedY <= 0.01) validCount++;
        });

        if (validCount >= 2) {
            const x1 = 0; const x2 = data.length - 1;
            container.append('line')
                .attr('x1', 0).attr('x2', width)
                .attr('y1', y(lr.slope * x1 + lr.intercept))
                .attr('y2', y(lr.slope * x2 + lr.intercept))
                .attr('stroke', '#ef4444').attr('stroke-width', 1.5);
            container.append('text').attr('x', width-5).attr('y', y(lr.slope * x2 + lr.intercept)-5)
                .text('智能压力').attr('fill', '#ef4444').attr('text-anchor', 'end').attr('font-size', '10px');
        }
    }

    // Trend Strength Badge
    const closePoints = data.map((d, i) => ({x: i, y: d.close}));
    const trendLR = calculateLR(closePoints);
    const lastPrice = data[data.length-1].close;
    const pctSlope = (trendLR.slope / lastPrice) * 100;

    let strength = 'WEAK';
    let trendType = 'SIDEWAYS';
    let color = '#94a3b8';

    const lastPt = data[data.length-1];
    const ma20 = lastPt.ma20 || 0;

    if (pctSlope > 0) {
        if (lastPt.close > ma20) {
            trendType = 'UP';
            if (pctSlope >= 0.3) { strength = 'STRONG'; color = '#ef4444'; } 
            else { strength = 'NORMAL'; color = '#f87171'; }
        }
    } else {
        if (lastPt.close < ma20) {
            trendType = 'DOWN';
            if (Math.abs(pctSlope) >= 0.3) { strength = 'STRONG'; color = '#16a34a'; }
            else { strength = 'NORMAL'; color = '#4ade80'; }
        }
    }

    if (trendType !== 'SIDEWAYS') {
        const badgeGroup = svg.append('g').attr('transform', `translate(10, 50)`); 
        badgeGroup.append('rect').attr('width', 130).attr('height', 24).attr('rx', 4).attr('fill', color).attr('opacity', 0.1);
        badgeGroup.append('rect').attr('width', 3).attr('height', 24).attr('fill', color);
        badgeGroup.append('text').attr('x', 10).attr('y', 16)
            .text(`${trendType === 'UP' ? '上升' : '下降'}趋势: ${strength === 'STRONG' ? '强' : '普通'}`)
            .attr('fill', color).attr('font-size', '11px').attr('font-weight', 'bold');
    }
}

// --- 3. Trend Channel Painter ---
export function drawTrendChannel(
    container: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    y: ScaleLinear,
    width: number
) {
    const trendData = data; 
    const fractalWindow = Math.max(2, Math.floor(trendData.length / 30)); 

    const highs: {x: number, y: number}[] = [];
    const lows: {x: number, y: number}[] = [];

    for (let i = fractalWindow; i < trendData.length - fractalWindow; i++) {
        const current = trendData[i];
        const range = trendData.slice(i - fractalWindow, i + fractalWindow + 1);
        if (range.every(d => d.low >= current.low)) lows.push({ x: i, y: current.low });
        if (range.every(d => d.high <= current.high)) highs.push({ x: i, y: current.high });
    }

    if (lows.length >= 2 && highs.length >= 2) {
        const allPoints = trendData.map((d, i) => ({x: i, y: d.close}));
        const globalLR = calculateLR(allPoints);
        const isUptrend = globalLR.slope > 0;

        let m = 0; 
        let b_support = 0; 
        let b_resistance = 0;

        // Simplified Logic for robustness
        if (isUptrend) {
            m = calculateLR(lows).slope;
            b_support = Math.min(...lows.map(p => p.y - m * p.x));
            b_resistance = Math.max(...highs.map(p => p.y - m * p.x));
        } else {
            m = calculateLR(highs).slope;
            b_resistance = Math.max(...highs.map(p => p.y - m * p.x));
            b_support = Math.min(...lows.map(p => p.y - m * p.x));
        }

        const fillColor = isUptrend ? '#fee2e2' : '#dcfce7'; 
        const strokeColor = isUptrend ? '#ef4444' : '#22c55e'; 

        const x1 = 0; const x2 = trendData.length - 1;
        const areaPoints = [ 
            { x: 0, y: m * x1 + b_resistance }, 
            { x: width, y: m * x2 + b_resistance }, 
            { x: width, y: m * x2 + b_support }, 
            { x: 0, y: m * x1 + b_support } 
        ];

        const areaGen = d3.line<{x:number, y:number}>().x(d => d.x).y(d => y(d.y));
        container.append('path').datum(areaPoints).attr('d', areaGen).attr('fill', fillColor).attr('fill-opacity', 0.2).attr('stroke', 'none');

        const drawLine = (b: number, color: string) => { 
            container.append('line')
                .attr('x1', 0).attr('x2', width)
                .attr('y1', y(m * x1 + b)).attr('y2', y(m * x2 + b))
                .attr('stroke', color).attr('stroke-width', 1.5).attr('stroke-dasharray', '4,4').attr('opacity', 0.8); 
        };
        drawLine(b_resistance, strokeColor); 
        drawLine(b_support, strokeColor);
    }
}

// --- 9. Sub Charts (Volume & MACD) ---
export function drawSubCharts(
    volGroup: SelectionGroup,
    macdGroup: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    yVol: ScaleLinear,
    yMacd: ScaleLinear,
    volH: number,
    macdH: number,
    width: number,
    macdTop: number
) {
    // Volume
    volGroup.selectAll('.vol-bar').data(data).enter().append('rect')
        .attr('x', d => x(d.date)!)
        .attr('y', d => yVol(d.volume))
        .attr('width', x.bandwidth())
        .attr('height', d => volH - yVol(d.volume))
        .attr('fill', d => d.close > d.open ? '#f87171' : '#4ade80');

    // MACD
    macdGroup.append('rect').attr('width', width).attr('height', macdH).attr('fill', '#f8fafc').attr('opacity', 0.5);
    macdGroup.append('line').attr('x1', 0).attr('x2', width).attr('y1', yMacd(0)).attr('y2', yMacd(0)).attr('stroke', '#cbd5e1').attr('stroke-width', 1).attr('stroke-dasharray', '3,3');
    macdGroup.selectAll('.macd-bar').data(data).enter().append('rect')
        .attr('x', d => x(d.date)!)
        .attr('y', d => { const val = d.macd?.macd || 0; return val >= 0 ? yMacd(val) : yMacd(0); })
        .attr('width', x.bandwidth())
        .attr('height', d => { const val = d.macd?.macd || 0; return Math.abs(yMacd(val) - yMacd(0)); })
        .attr('fill', d => (d.macd?.macd || 0) >= 0 ? '#ef4444' : '#22c55e').attr('opacity', 0.8);

    const lineDiff = d3.line<KlinePoint>().x(d => x(d.date)! + x.bandwidth()/2).y(d => yMacd(d.macd?.diff || 0));
    const lineDea = d3.line<KlinePoint>().x(d => x(d.date)! + x.bandwidth()/2).y(d => yMacd(d.macd?.dea || 0));

    macdGroup.append('path').datum(data).attr('fill', 'none').attr('stroke', '#3b82f6').attr('stroke-width', 1.5).attr('d', lineDiff);
    macdGroup.append('path').datum(data).attr('fill', 'none').attr('stroke', '#f59e0b').attr('stroke-width', 1.5).attr('d', lineDea);
}

// --- 10. Fibonacci Painter ---
export function drawFibonacci(
    container: SelectionGroup,
    levels: FibLevel[],
    width: number,
    y: ScaleLinear,
    yMin: number,
    yMax: number
) {
    // 1. Draw Extension Background Zones
    // Find the base (0% or 100% depending on trend) and the furthest extension
    const baseLevel = levels.find(l => l.isBase);
    const extensions = levels.filter(l => l.isExtension);

    if (baseLevel && extensions.length > 0) {
        // Sort extensions by value
        const sortedExt = [...extensions].sort((a,b) => a.val - b.val);
        const furthestExt = sortedExt[baseLevel.val < sortedExt[0].val ? sortedExt.length - 1 : 0]; // Determine direction

        // Define zone from Base to Furthest Extension
        const yBase = y(baseLevel.val);
        const yExt = y(furthestExt.val);

        // Calculate bounded rect for display
        const topY = Math.min(yBase, yExt);
        const bottomY = Math.max(yBase, yExt);

        // Color based on trend? Extensions usually mean targets. 
        const isUpTarget = furthestExt.val > baseLevel.val;
        const zoneColor = isUpTarget ? '#fee2e2' : '#dcfce7'; 

        container.append('rect')
            .attr('x', 0)
            .attr('width', width)
            .attr('y', topY)
            .attr('height', Math.max(1, bottomY - topY))
            .attr('fill', zoneColor)
            .attr('opacity', 0.2); 
    }

    // 2. Draw Lines & Text
    levels.forEach(fib => {
       // Only draw if within visible range (loosely)
       if (fib.val >= yMin * 0.5 && fib.val <= yMax * 1.5) { // Allow some overflow drawing
         const yPos = y(fib.val);

         container.append('line')
            .attr('x1', 0).attr('x2', width)
            .attr('y1', yPos).attr('y2', yPos)
            .attr('stroke', fib.color)
            .attr('stroke-width', fib.dash === '5,3' ? 1.5 : 1)
            .attr('stroke-dasharray', fib.dash)
            .attr('opacity', 0.8);

         const text = `${fib.label}: ${fib.val.toFixed(3)}`;
         container.append('text')
            .attr('x', width - 5)
            .attr('y', yPos - 3)
            .attr('text-anchor', 'end')
            .attr('font-size', '10px')
            .attr('fill', fib.color)
            .attr('font-weight', 'bold')
            .text(text);
       }
    });
}

import * as d3 from 'd3';
import { KlinePoint, BoxSignal } from '../../../services/etf.service';
import { SelectionGroup, ScaleBand, ScaleLinear } from './types';

// --- 4. Volume Profile + 123 Painter ---
export function drawVolumeProfile(
    container: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    y: ScaleLinear,
    width: number
) {
    const yMin = y.domain()[0];
    const yMax = y.domain()[1];
    const binCount = 50;
    const binSize = (yMax - yMin) / binCount;
    const bins = new Array(binCount).fill(0);
    let maxVolBin = 0;
    let maxVolIdx = 0;

    data.forEach(d => {
        const idx = Math.floor((d.close - yMin) / binSize);
        if (idx >= 0 && idx < binCount) {
            bins[idx] += d.volume;
            if (bins[idx] > maxVolBin) {
                maxVolBin = bins[idx];
                maxVolIdx = idx;
            }
        }
    });

    const pocPrice = yMin + (maxVolIdx + 0.5) * binSize;
    const maxBarWidth = width * 0.2; 
    const vpGroup = container.append('g').attr('transform', `translate(${width}, 0)`);

    bins.forEach((vol, i) => {
        const barW = (vol / maxVolBin) * maxBarWidth;
        const barY = y(yMin + (i+1)*binSize);
        const barH = Math.abs(y(yMin + i*binSize) - barY);

        vpGroup.append('rect')
            .attr('x', -barW)
            .attr('y', barY)
            .attr('width', barW)
            .attr('height', barH)
            .attr('fill', i === maxVolIdx ? '#eab308' : '#64748b') 
            .attr('opacity', i === maxVolIdx ? 0.4 : 0.1);
    });

    container.append('line')
        .attr('x1', 0).attr('x2', width)
        .attr('y1', y(pocPrice)).attr('y2', y(pocPrice))
        .attr('stroke', '#eab308').attr('stroke-width', 1.5).attr('stroke-dasharray', '4,2');

    container.append('text')
        .attr('x', width - 5).attr('y', y(pocPrice) - 4)
        .text('POC (筹码峰)').attr('fill', '#eab308')
        .attr('font-size', '10px').attr('font-weight', 'bold').attr('text-anchor', 'end');

    // ZigZag / Wave Theory
    const zigzag: {x: number, y: number, date: string, type: 'HIGH'|'LOW'}[] = [];
    const lookback = Math.max(3, Math.floor(data.length / 20));

    for(let i=lookback; i<data.length-lookback; i++) {
            const d = data[i];
            const range = data.slice(i-lookback, i+lookback+1);
            const isHigh = range.every(item => item.high <= d.high);
            const isLow = range.every(item => item.low >= d.low);

            if (isHigh) zigzag.push({x: i, y: d.high, date: d.date, type: 'HIGH'});
            else if (isLow) zigzag.push({x: i, y: d.low, date: d.date, type: 'LOW'});
    }

    const cleanZigzag: typeof zigzag = [];
    zigzag.forEach(p => {
        if (cleanZigzag.length === 0) { cleanZigzag.push(p); return; }
        const last = cleanZigzag[cleanZigzag.length-1];
        if (last.type !== p.type) {
            cleanZigzag.push(p);
        } else {
            if (p.type === 'HIGH' && p.y > last.y) cleanZigzag[cleanZigzag.length-1] = p;
            if (p.type === 'LOW' && p.y < last.y) cleanZigzag[cleanZigzag.length-1] = p;
        }
    });

    const lineGen = d3.line<{x:number, y:number, date: string}>()
        .x(d => x(d.date)! + x.bandwidth()/2)
        .y(d => y(d.y));

    // Draw Thin Black Lines for Segments
    container.append('path')
        .datum(cleanZigzag)
        .attr('fill', 'none')
