// --- 11. Strategy Markers Painter (R0-R10) ---
export function drawStrategyMarkers(
    container: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    y: ScaleLinear,
    width: number
) {
    if (data.length < 30) return;

    // --- Helpers ---
    const getLRChannel = (idx: number, period: number = 20) => {
        if (idx < period - 1) return null;
        const subset = data.slice(idx - period + 1, idx + 1);
        const points = subset.map((d, i) => ({ x: i, y: d.close }));
        const { slope, intercept } = calculateLR(points);

        // Calculate max deviation (channel width)
        let maxDev = 0;
        subset.forEach((d, i) => {
             const regY = slope * i + intercept;
             maxDev = Math.max(maxDev, Math.abs(d.close - regY)); // Simplified height
        });

        // Current projected values
        const currentX = period - 1;
        const mid = slope * currentX + intercept;
        return { top: mid + maxDev, mid: mid, bottom: mid - maxDev, slope };
    };

    const drawIcon = (i: number, icon: string, color: string, label?: string, yOffset: number = 25) => {
        const d = data[i];
        const cx = x(d.date)! + x.bandwidth()/2;
        const cy = y(d.high); // Default above high
        const g = container.append('g').attr('transform', `translate(${cx}, ${cy - yOffset})`);

        g.append('text')
            .text(icon)
            .attr('font-size', '14px')
            .attr('text-anchor', 'middle');

        if (label) {
             g.append('text')
                .text(label)
                .attr('y', -12)
                .attr('fill', color)
                .attr('font-size', '9px')
                .attr('text-anchor', 'middle')
                .attr('font-weight', 'bold');
        }
    };

    // --- State Machine ---
    let position: { 
        entryIdx: number, 
        entryPrice: number, 
        qty: number, 
        waveLow: number, // Stop reference (0%)
        waveHigh: number // Peak since entry (100% reference updates)
    } | null = null;

    // Previous wave stats for Symmetry (R3-R5)
    // Simplified wave finder: assume zigzag provides the "previous wave"
    const zigzag = calculateZigZag(data); 

    // Simulation Loop
    for (let i = 20; i < data.length; i++) {
        const d = data[i];
        const prev = data[i-1];
        const next = i < data.length - 1 ? data[i+1] : null;

        const channel = getLRChannel(i, 20);
        if (!channel) continue;

        const volAvg5 = data.slice(i-5, i).reduce((sum, p) => sum + p.volume, 0) / 5;
        const volRatio = d.volume / (volAvg5 || 1);

        // --- I. Observation & Entry ---

        // R0: Observe (Close > Channel Top)
        if (!position && d.close > channel.top) {
            // Only draw if we haven't drawn recently to avoid clutter
            if (i % 5 === 0) drawIcon(i, '👁️', '#a855f7', '观察点'); 
        }

        // R1: Entry (Breakout + Vol + Confirmation)
        if (!position && d.close > channel.top && volRatio > 1.5) {
            // Check confirmation (Next day close < prev close -> Buy Tail)
            // Simulating "Next Day Action" at current step i if previous day i-1 triggered logic
            // But logic says: "At T+1 or T+2... If Next Day Close < Prev Close".
            // Let's implement: If today (i) confirms yesterday (i-1)'s breakout
            const prevChannel = getLRChannel(i-1, 20);
            if (prevChannel && prev.close > prevChannel.top) { // Yesterday broke out
                 if (d.close < prev.close) {
                     // Confirm Entry
                     drawIcon(i, '🚩', '#ef4444', '建仓点');

                     // Find local low for Fib calc (approximate 0%)
                     const localLow = Math.min(...data.slice(Math.max(0, i-20), i).map(p => p.low));

                     position = {
                         entryIdx: i,
                         entryPrice: d.close,
                         qty: 1, // Unit
                         waveLow: localLow,
                         waveHigh: d.high
                     };
                 }
            }
        }

        // --- Active Position Logic ---
        if (position) {
            position.waveHigh = Math.max(position.waveHigh, d.high);
            const range = position.waveHigh - position.waveLow;
            const daysHeld = i - position.entryIdx;

            // R2: Add Position (Window 10 days)
            if (daysHeld <= 10 && daysHeld > 0) {
                 // Retrace to Fib 38.2% or 50% (of current wave range)
                 // Price = High - Range * Ratio
                 const fib382 = position.waveHigh - range * 0.382;
                 const fib500 = position.waveHigh - range * 0.500;

                 // Condition: Low touched Fib but Close didn't break deep? 
                 // Simplified: Low <= Fib382 && Close > Fib500 (held 50%)
                 // And Touch Channel Mid/Bottom
                 const touchChannel = d.low <= channel.mid;
                 const isDownDay = d.close < prev.close;

                 if (touchChannel && d.low <= fib382 && d.close > fib500 && isDownDay) {
                      drawIcon(i, '➕', '#3b82f6', '加仓');
                 }
            }

            // --- II. Symmetry Warnings (Simplified for visual check) ---
            // R4: Time Symmetry Warning (Duration > Prev Wave Duration)
            // Need prev wave duration. 
            // Find current wave index in zigzag
            // This is complex to perfect without strict wave definitions, using heuristic:
            if (daysHeld > 20 && d.high < position.waveHigh) {
                 if (i % 5 === 0) drawIcon(i, '⚠️', '#eab308', '警告');
            }

            // --- III. Take Profit ---
            // R6: Fib Step Exit (38.2, 61.8, 100, 138.2 of Range relative to Entry?) 
            // The prompt says "Drop below Fib levels". This implies the price went UP significantly 
            // and is now retracing from the Peak.
            // "Fib 32.6%" usually means from Peak down. 
            // Let's assume standard Retracement from Peak:
            // Lvl A: Peak - Range * 0.326? Or Retrace TO 32.6% level?
            // Usually "Drop below 38.2% level" means price < (Low + Range * 0.382). That's a huge drop.
            // Text says: "Drop below 32.6% level... 61.8% level". 
            // Interpret as: Retracement Magnitude.

            const retracePct = (position.waveHigh - d.close) / (range || 1);

            // T+2 Confirmation simulated: If yesterday dropped, today still down?
            // Simplified for marker:
            if (retracePct > 0.326 && retracePct < 0.4 && daysHeld > 3) {
                 drawIcon(i, '🎯', '#ef4444', '止盈A');
            }
            if (retracePct > 0.618 && retracePct < 0.7) {
                 drawIcon(i, '🎯', '#eab308', '止盈B', 35); // Higher offset
            }
            if (retracePct > 1.0) { // Dropped below start of wave
                 drawIcon(i, '🎯', '#eab308', '止盈C', 35);
            }

            // R7: Channel Top Watch
            // If touched top, count days below top. 
            // (Complex to store state, skip strict 3-day count for pure marker, show "Clear" if deep drop from top)

            // R8: Hard Target (Profit > 30%)
            const pnl = (d.close - position.entryPrice) / position.entryPrice;
            if (pnl > 0.30) {
                 drawIcon(i, '❌', '#ef4444', '强制止损'); // User requested "Forced Stop Loss" label for profit taking
                 position = null; // Exit
                 continue;
            }

            // --- IV. Stop Loss ---
            // R9: Step Stop
            // Drop below -32.6% of entry? Or Fib of wave?
            // "Drop below Fib defense (-32.6% or -61.8%)" implies below the Wave Low.
            const distFromLow = (position.waveLow - d.close) / range;
            if (d.close < position.waveLow) {
                 drawIcon(i, '🛡️', '#ef4444', '止损A');
                 position = null; // Exit
                 continue;
            }

            // R10: Meltdown (Gap down or break lowest)
            // Gap down > 1% below Low
            if (d.open < position.waveLow * 0.99) {
                 drawIcon(i, '🚫', '#ef4444', '熔断止损');
                 position = null;
                 continue;
            }
        }
    }
}

// Helper for ZigZag
function calculateZigZag(data: KlinePoint[]) {
    const zigzag: {x: number, y: number, date: string, type: 'HIGH'|'LOW'}[] = [];
    const lookback = Math.max(3, Math.floor(data.length / 20));

    for(let i=lookback; i<data.length-lookback; i++) {
            const d = data[i];
            const range = data.slice(i-lookback, i+lookback+1);
            const isHigh = range.every(item => item.high <= d.high);
            const isLow = range.every(item => item.low >= d.low);

            if (isHigh) zigzag.push({x: i, y: d.high, date: d.date, type: 'HIGH'});
            else if (isLow) zigzag.push({x: i, y: d.low, date: d.date, type: 'LOW'});
    }

    const cleanZigzag: typeof zigzag = [];
    zigzag.forEach(p => {
        if (cleanZigzag.length === 0) { cleanZigzag.push(p); return; }
        const last = cleanZigzag[cleanZigzag.length-1];
        if (last.type !== p.type) {
            cleanZigzag.push(p);
        } else {
            if (p.type === 'HIGH' && p.y > last.y) cleanZigzag[cleanZigzag.length-1] = p;
            if (p.type === 'LOW' && p.y < last.y) cleanZigzag[cleanZigzag.length-1] = p;
        }
    });
    return cleanZigzag;
}

