    '159819', // 人工智能ETF
    '512800', // 银行ETF
    '512010', // 医药ETF
    '512880', // 证券ETF
    '515220', // 煤炭ETF
    '510300', // 沪深300ETF
    '510500', // 中证500ETF
    '513180', // 恒生科技指数ETF
    '159941', // 纳指ETF
