        breakMA5: false,
        breakMA20: false,
        breakDowntrend: false,
        isHighVolume: false,
        buySignals: 0,
        sellSignals: 0,
        buyFactors: [],
        sellFactors: [],
        trend: 'SIDEWAYS',
        score: 50,
        health: 50,
        suggestion: 'WAIT',
        lastUpdated: new Date().toLocaleTimeString(),
        history: [],
        fundSize: marketCap / 100000000, 
        establishmentDate: '',
        age: 0,
        suggestedEntryPrice: 0,
