    if (/(300|500|1000|2000|50|100|800|创业板|科创|恒生|纳指|标普|红利|MSCI|综指|成指|大湾区|双创|中证|A50|道琼斯|日经|德国|法国|英国|东南亚|沙特)/.test(name)) return '宽基/指数';
    if (/(芯片|半导体|计算机|电子|5G|人工智能|游戏|传媒|通信|软件|科技|互联|AI|数据|卫星|信创|机器人|云计算|元宇宙|智能|信息|机床)/.test(name)) return '科技/TMT';
    if (/(医疗|药|生物|疫苗|医|健康|基因|中药)/.test(name)) return '医药/生物';
    if (/(酒|食品|家电|消费|旅游|养殖|农|畜|文娱|教育|美妆|饮料|乳)/.test(name)) return '大消费';
    if (/(光伏|电池|新能源|碳中和|车|绿电|电力|储能|环保|低碳|光电)/.test(name)) return '新能源/车';
    if (/(银行|券商|证券|保险|金融|FinTech|央企股东回报)/i.test(name)) return '金融';
    if (/(黄金|豆粕|有色|金属|稀土|铝|铜|矿|油|石化|煤炭|钢铁|能源|化工|基建|地产|房地产|建材|材料)/.test(name)) return '周期/资源';
    if (/(军工|国防|航天)/.test(name)) return '军工';
    if (/(债|政金|国开|同业存单)/.test(name)) return '债券';
    if (/(货币|理财|现金)/.test(name)) return '货币';
    return '其他';
  }

  private parseRawNumber(val: any): number {
    if (val === undefined || val === null || val === '-') return 0;
    if (typeof val === 'number') return val;
    return parseFloat(val) || 0;
  }

  // --- Main Methods ---

  loadAllEtfs() {
    if (this.loading()) return;
    this.loading.set(true);
    this.error.set(null);

    if (this.dataSource() === 'EASTMONEY') {
      this.loadEastmoneyData();
    } else {
      this.loadTencentData();
    }
  }

  private loadEastmoneyData() {
    const marketCodes = ETF_LIST.map(e => `${this.getMarketCode(e.code)}.${e.code}`);
    const chunks: string[][] = [];
    const chunkSize = 80;
    for (let i = 0; i < marketCodes.length; i += chunkSize) {
        chunks.push(marketCodes.slice(i, i + chunkSize));
    }

    const reqs = chunks.map(chunk => {
        const ids = chunk.join(',');
        const url = `https://push2.eastmoney.com/api/qt/ulist.get?pi=0&pz=200&po=1&np=1&fltt=2&invt=2&fields=f2,f3,f12,f14,f15,f16,f17,f20,f21,f116,f117&secids=${ids}`;
        return this.http.jsonp<any>(url, 'cb').pipe(
           catchError(() => of(null))
        );
    });

    forkJoin(reqs).subscribe({
        next: (responses) => {
            const rawDataMap = new Map<string, any>();
            responses.forEach((res: any) => {
                if(res && res.data && res.data.diff) {
                    res.data.diff.forEach((d: any) => {
                        rawDataMap.set(d.f12, d);
                    });
                }
            });

            const baseAnalysis: ETFAnalysis[] = ETF_LIST.map(def => {
                const raw = rawDataMap.get(def.code) || {};
                const price = this.parseRawNumber(raw.f2); // f2 price

                let marketCap = this.parseRawNumber(raw.f20); 

                if (!marketCap || marketCap <= 0) {
                    marketCap = this.parseRawNumber(raw.f21);
                }

                if ((!marketCap || marketCap <= 0) && price > 0) {
                     const totalShares = this.parseRawNumber(raw.f116);
                     if (totalShares > 0) marketCap = price * totalShares;
                }

                if ((!marketCap || marketCap <= 0) && price > 0) {
                     const floatShares = this.parseRawNumber(raw.f117);
                     if (floatShares > 0) marketCap = price * floatShares;
                }

                return this.createAnalysisObject(def, price, raw.f3, marketCap);
            });

            this.etfData.set(baseAnalysis);
            this.fetchHistories(baseAnalysis);
        },
        error: (err) => {
            console.error(err);
            this.error.set('无法连接东方财富行情服务器');
            this.loading.set(false);
        }
    });
  }

  private loadTencentData() {
    const tencentCodes = ETF_LIST.map(e => this.getTencentCode(e.code));
    const chunks: string[][] = [];
    const chunkSize = 50; // Tencent URL limit safe
    for (let i = 0; i < tencentCodes.length; i += chunkSize) {
        chunks.push(tencentCodes.slice(i, i + chunkSize));
    }

    const promises = chunks.map(chunk => {
       const ids = chunk.join(',');
       // Use HTTPS to avoid mixed content block
       const url = `https://qt.gtimg.cn/q=${ids}`;
       return this.injectScript(url).then(() => {
          const results: any[] = [];
          chunk.forEach(code => {
             const raw = (window as any)[`v_${code}`];
             if (raw) {
                const parts = raw.split('~');
                // parts[1]=Name, parts[2]=Code, parts[3]=Price, parts[32]=Change%
                // parts[45]=TotalMarketCap(Approx) - check index validity
                // Typical: 1:Name, 2:Code, 3:Price, 32:Pct, 45:MktCap
                results.push({
                   code: parts[2],
                   price: parseFloat(parts[3]),
                   changePct: parseFloat(parts[32]),
                   marketCap: parseFloat(parts[45] || '0') * 100000000 // Often usually unit is approx
                });
             }
          });
          return results;
       }).catch(() => []);
    });

    Promise.all(promises).then(allChunks => {
        const flatResults = allChunks.flat();
        const resultMap = new Map<string, any>();
        flatResults.forEach(r => resultMap.set(r.code, r));

        const baseAnalysis: ETFAnalysis[] = ETF_LIST.map(def => {
             const data = resultMap.get(def.code);
             const price = data ? data.price : 0;
             const change = data ? data.changePct : 0;
             const mcap = data ? data.marketCap : 0;
             return this.createAnalysisObject(def, price, change, mcap);
        });

        this.etfData.set(baseAnalysis);
        this.fetchHistories(baseAnalysis);
    }).catch(err => {
        console.error(err);
        this.error.set('无法连接腾讯数据接口');
        this.loading.set(false);
    });
  }

  private injectScript(url: string): Promise<void> {
      return new Promise((resolve, reject) => {
          const script = document.createElement('script');
          script.src = url;
          script.charset = 'gbk'; // Tencent often returns GBK
          script.onload = () => {
             document.body.removeChild(script);
             resolve();
          };
          script.onerror = () => {
             document.body.removeChild(script);
             reject();
          };
          document.body.appendChild(script);
      });
  }

  private createAnalysisObject(def: ETFDefinition, price: number, change: number, marketCap: number): ETFAnalysis {
      return {
        ...def,
        currentPrice: price,
        changePercent7d: 0,
        isGolden: false,
        breakMA5: false,
        breakMA20: false,
        breakDowntrend: false,
        isHighVolume: false,
        buySignals: 0,
        sellSignals: 0,
        buyFactors: [],
        sellFactors: [],
        trend: 'SIDEWAYS',
        score: 50,
        health: 50,
        suggestion: 'WAIT',
        lastUpdated: new Date().toLocaleTimeString(),
        history: [],
        fundSize: marketCap / 100000000, 
        establishmentDate: '',
        age: 0,
        suggestedEntryPrice: 0,
        goldenPrice: 0,
        industry: def.industry || this.classifyETF(def.name)
    };
  }

  private fetchHistories(currentList: ETFAnalysis[]) {
     from(currentList).pipe(
        mergeMap(item => this.fetchSingleHistory(item, 120), 6), 
        toArray()
     ).subscribe(updatedList => {
        this.etfData.set(updatedList);
        this.loading.set(false);
     });
  }

  private fetchSingleHistory(item: ETFAnalysis, limit: number): Observable<ETFAnalysis> {
     // NOTE: We keep Eastmoney as the source for K-line History because of its cleaner JSON API
     // regardless of the Snapshot source.
     const secid = `${this.getMarketCode(item.code)}.${item.code}`;
     const url = `https://push2his.eastmoney.com/api/qt/stock/kline/get?secid=${secid}&fields1=f1,f2,f3,f4,f5,f6&fields2=f51,f52,f53,f54,f55,f56,f57,f58,f59,f60,f61&klt=101&fqt=1&end=20500101&lmt=${limit}`;

     return this.http.jsonp<any>(url, 'cb').pipe(
        map((res: any) => {
            if (res && res.data && res.data.klines) {
                const history = this.parseKlines(res.data.klines);
                return this.analyzeETF(item, history);
            }
            // If data is missing but we have an item, return item to avoid breaking pipeline
            return item;
        }),
        catchError(err => {
            console.warn(`Failed to fetch history for ${item.code}`, err);
            return of(item);
        })
     );
  }

  getEtfDetails(code: string): Observable<ETFAnalysis | null> {
    const existing = this.etfData().find(e => e.code === code);
    // CRITICAL FIX: Only return existing if it has history. 
    // If it was just loaded from Tencent snapshot (history=[]), we MUST fetch history now.
    if (existing && existing.history.length > 0) return of(existing);

    let def = ETF_LIST.find(e => e.code === code);
    if (!def) {
       def = { code, name: code, industry: '未知' };
    }

    // If existing (Tencent snapshot), use its currentPrice, otherwise 0
    const price = existing ? existing.currentPrice : 0;
    const tempItem = this.createAnalysisObject(def, price, 0, 0);
    return this.fetchSingleHistory(tempItem, 120);
  }

  getBacktestData(code: string): Observable<ETFAnalysis | null> {
      let def = ETF_LIST.find(e => e.code === code);
      if (!def) def = { code, name: code, industry: '未知' };
      const tempItem = this.createTempItem(def);
      return this.fetchSingleHistory(tempItem, 2000);
  }

  private createTempItem(def: ETFDefinition): ETFAnalysis {
      return this.createAnalysisObject(def, 0, 0, 0);
  }

  // --- Parsing & Analysis ---

  private parseKlines(rawLines: string[]): KlinePoint[] {
    return rawLines.map(line => {
       const p = line.split(',');
       return {
          date: p[0],
          open: parseFloat(p[1]),
          close: parseFloat(p[2]),
          high: parseFloat(p[3]),
          low: parseFloat(p[4]),
          volume: parseFloat(p[5]),
          amount: parseFloat(p[6])
       };
    });
  }

  private calcBoxSignals(fullHistory: KlinePoint[]): BoxSignal | null {
      const minBoxSize = 30;
      if (fullHistory.length < minBoxSize + 5) return null;

      const scanLimit = Math.max(minBoxSize + 5, fullHistory.length - 60);

      for (let i = fullHistory.length - 1; i >= scanLimit; i--) {
          const entryDay = fullHistory[i];
          const confirmDay = fullHistory[i-1];
          const obsDay = fullHistory[i-2];

          const boxEndIdx = i - 2;
          const boxStartIdx = boxEndIdx - 29; 

          if (boxStartIdx < 0) continue;

          const boxData = fullHistory.slice(boxStartIdx, boxEndIdx + 1);
          const boxHigh = Math.max(...boxData.map(d => d.high));
          const boxLow = Math.min(...boxData.map(d => d.low));
          const D = boxHigh - boxLow;

          if (confirmDay.close > boxHigh && entryDay.close > boxHigh) {

             const prices = boxData.map(d => d.close);
             const minP = Math.min(...prices);
             const maxP = Math.max(...prices);
             const bins = 20;
             const binSize = (maxP - minP) / bins;
             let poc = (minP + maxP) / 2;

             if (binSize > 0) {
                 const binVols = new Array(bins).fill(0);
                 boxData.forEach(d => {
                    const idx = Math.min(bins-1, Math.floor((d.close - minP)/binSize));
                    binVols[idx] += d.volume;
                 });
                 const maxBinIdx = binVols.indexOf(Math.max(...binVols));
                 poc = minP + (maxBinIdx + 0.5) * binSize;
             }

             const volSlice = fullHistory.slice(i-5, i);
             const avgVol5 = volSlice.reduce((a,b)=>a+b.volume,0)/volSlice.length;

             const volSpike = entryDay.volume > 1.2 * avgVol5 || confirmDay.volume > 1.2 * avgVol5;
             const priceValid = entryDay.close > poc;

             if (priceValid && volSpike) {
                 return {
                     type: 'UP',
                     date: entryDay.date,
                     obsDate: obsDay.date,
                     entryPrice: entryDay.close,
                     boxStartDate: fullHistory[boxStartIdx].date,
                     boxHigh,
                     boxLow,
                     boxHeight: D,
                     poc,
                     tpA: entryDay.close + D * 0.382,
                     tpB: entryDay.close + D * 0.618,
                     slA: entryDay.close - D * 0.382,
                     slB: entryDay.close - D * 0.618,
                     clearPrice: boxLow, 
                     valid: true
                 };
             }
          }
      }
      return null;
  }

  private analyzeETF(item: ETFAnalysis, history: KlinePoint[]): ETFAnalysis {
     // Ensure history is attached even if analysis skips
     if (!history || history.length < 20) return { ...item, history: history || [] };

     const points = this.calcIndicators(history);
     const latest = points[points.length - 1];
     const prev = points[points.length - 2];

     // CRITICAL FIX: If item has a valid snapshot price, use it. 
     // BUT if snapshot price is 0 (failed/default), fallback to latest K-line close.
     const currentPrice = (item.currentPrice && item.currentPrice > 0) ? item.currentPrice : latest.close;

     // Trend Analysis
     let trend: 'UP' | 'DOWN' | 'SIDEWAYS' = 'SIDEWAYS';
     if (latest.ma20 && prev.ma20) {
        if (currentPrice > latest.ma20 && latest.ma20 > prev.ma20) trend = 'UP';
        else if (currentPrice < latest.ma20 && latest.ma20 < prev.ma20) trend = 'DOWN';
     }

     const volAvg5 = points.slice(-5).reduce((a, b) => a + b.volume, 0) / 5;
     const isHighVolume = latest.volume > 1.5 * volAvg5;

     // Base Signals
     let buySignals = 0;
     let sellSignals = 0;
     const buyFactors: string[] = [];
     const sellFactors: string[] = [];

     // Use `currentPrice` for comparisons
     const breakMA5 = currentPrice < (latest.ma5 || 0);
     const breakMA20 = currentPrice < (latest.ma20 || 0);
     const breakDowntrend = prev.close < (prev.ma20 || 0) && currentPrice > (latest.ma20 || 0);

     if (breakDowntrend) { buySignals++; buyFactors.push('突破20日均线'); }
     if (isHighVolume && currentPrice > latest.open) { buySignals++; buyFactors.push('放量上涨'); }

     // Golden Ratio
     const recent = points.slice(-30);
     const maxHigh = Math.max(...recent.map(p => p.high));
     const minLow = Math.min(...recent.map(p => p.low));
     const range = maxHigh - minLow;
     const goldenPrice = maxHigh - range * 0.382;
     const isGolden = Math.abs(currentPrice - goldenPrice) / goldenPrice < 0.02;

     if (isGolden && trend === 'UP') { buySignals += 2; buyFactors.push('黄金分割支撑位'); }

     // MACD
     if (latest.macd && prev.macd) {
        if (latest.macd.macd > 0 && prev.macd.macd <= 0) { buySignals += 2; buyFactors.push('MACD金叉'); }
        if (latest.macd.macd < 0 && prev.macd.macd >= 0) { sellSignals += 2; sellFactors.push('MACD死叉'); }
     }

     if (breakMA20) { sellSignals++; sellFactors.push('跌破20日均线'); }

     // --- Enhanced Signal Logic ---
     // 1. Moving Averages Alignment
     if (latest.ma5 && latest.ma10 && latest.ma20) {
         if (latest.ma5 > latest.ma10 && latest.ma10 > latest.ma20) {
             buySignals++; buyFactors.push('均线多头排列');
         }
         if (latest.ma5 < latest.ma10 && latest.ma10 < latest.ma20) {
             sellSignals++; sellFactors.push('均线空头排列');
         }
     }

     // 2. RSI
     if (latest.rsi) {
         if (latest.rsi < 30) { buySignals++; buyFactors.push('RSI超卖区'); }
         if (latest.rsi > 70) { sellSignals++; sellFactors.push('RSI超买区'); }
     }

     // 3. KDJ
     if (latest.kdj && prev.kdj) {
         if (prev.kdj.k < prev.kdj.d && latest.kdj.k > latest.kdj.d && latest.kdj.d < 50) {
             buySignals++; buyFactors.push('KDJ低位金叉');
         }
         if (prev.kdj.k > prev.kdj.d && latest.kdj.k < latest.kdj.d && latest.kdj.d > 50) {
             sellSignals++; sellFactors.push('KDJ高位死叉');
         }
     }

     // 4. MA60 Trend
     if (latest.ma60) {
         if (currentPrice > latest.ma60 && prev.close <= prev.ma60) {
             buySignals++; buyFactors.push('站上60日均线');
         }
         if (currentPrice < latest.ma60 && prev.close >= prev.ma60) {
             sellSignals++; sellFactors.push('跌破60日均线');
         }
     }

     // Box Signal Calculation
     const boxSignal = this.calcBoxSignals(points);

     // --- NEW SCORING MODEL (0-100) ---

     // 1. Trend (35%)
     let trendScore = 0;
     const ma5 = latest.ma5 || 0;
     const ma10 = latest.ma10 || 0;
     const ma20 = latest.ma20 || 0;
     const ma60 = latest.ma60 || 0;

     if (ma5 > ma10 && ma10 > ma20) trendScore += 15;
     if (ma20 > ma60) trendScore += 15;
     if (currentPrice > ma20) trendScore += 10;
     if (currentPrice > ma60) trendScore += 10;
     if ((latest.ma20Slope || 0) > 0) trendScore += 10;
     if ((latest.ma60Slope || 0) > 0) trendScore += 10;
     trendScore = Math.min(35, trendScore * (35/70));

     // 2. Momentum (30%)
     let momScore = 0;
     const macdVal = latest.macd?.macd || 0;
     const diff = latest.macd?.diff || 0;
     const dea = latest.macd?.dea || 0;
     if (macdVal > 0) momScore += 10;
     if (diff > dea) momScore += 10;

     const rsiVal = latest.rsi || 50;
     if (rsiVal > 50 && rsiVal < 80) momScore += 10;
     if (rsiVal >= 80) momScore -= 5;

     const k = latest.kdj?.k || 50;
     const dVal = latest.kdj?.d || 50;
     if (k > dVal) momScore += 10;
     if ((latest.roc || 0) > 0) momScore += 10;
     momScore = Math.min(30, momScore * (30/50));

     // 3. Volatility (15%)
     let volScore = 0;
     const wr = latest.wr || -50;
     if (wr > -80 && wr < -20) volScore += 10; 
     const bias = latest.bias || 0;
     if (bias > 0 && bias < 5) volScore += 10; 
     const boll = latest.boll;
     if (boll && currentPrice > boll.mid && currentPrice < boll.upper) volScore += 10;
     volScore = Math.min(15, volScore * (15/30));

     // 4. Volume (20%)
     let volumeScore = 0;
     if (latest.obv && latest.obvMa && latest.obv > latest.obvMa) volumeScore += 15;
     if (latest.volume > volAvg5) volumeScore += 10;
     if (currentPrice > latest.open) volumeScore += 5; 
     volumeScore = Math.min(20, volumeScore * (20/30));

     // Total Score
     let finalScore = trendScore + momScore + volScore + volumeScore;

     // Bonus for Box Signal
     if (boxSignal && boxSignal.valid) {
         if (currentPrice > boxSignal.entryPrice && currentPrice < boxSignal.tpA) {
             finalScore += 15;
             buyFactors.push('箱体突破共振(Box Breakout)');
         }
     }

     if (rsiVal > 85) finalScore -= 10;
     if (trend === 'DOWN') finalScore -= 15;
     finalScore = Math.max(0, Math.min(100, Math.round(finalScore)));

     // Trade Suggestion Logic
     let suggestion: TradeSuggestion = 'WAIT';

     if (boxSignal && boxSignal.valid) {
         const p = currentPrice;
         if (p < boxSignal.clearPrice) {
             suggestion = 'STOP_LOSS_CLEAR';
             sellFactors.push('跌破箱体下沿(Clearance)');
             finalScore = Math.min(finalScore, 20);
         }
         else if (p < boxSignal.slB) {
             suggestion = 'STOP_LOSS_CLEAR';
             sellFactors.push('触及止损B线');
             finalScore = Math.min(finalScore, 20);
         }
         else if (p < boxSignal.slA) {
             suggestion = 'STOP_LOSS_REDUCE';
             sellFactors.push('触及止损A线');
             finalScore = Math.min(finalScore, 30);
         }
         else if (p >= boxSignal.tpB) {
             suggestion = 'TAKE_PROFIT_CLEAR';
             sellFactors.push('达到止盈B目标');
         }
         else if (p >= boxSignal.tpA) {
             suggestion = 'TAKE_PROFIT_REDUCE';
             sellFactors.push('达到止盈A目标');
         }
         else if (p > boxSignal.entryPrice) {
             suggestion = 'HOLD';
         }
         else {
             suggestion = 'BUY_POINT';
         }
     } else {
         if (finalScore >= 80) suggestion = 'BUY_POINT';
         else if (finalScore >= 60) suggestion = 'HOLD';
         else if (finalScore <= 35) suggestion = 'STOP_LOSS_REDUCE';
         else if (finalScore <= 20) suggestion = 'STOP_LOSS_CLEAR';
     }

     return {
        ...item,
        currentPrice: currentPrice, // Return the prioritized price
        changePercent7d: (currentPrice - (points[points.length - 6]?.close || currentPrice)) / (points[points.length - 6]?.close || 1) * 100,
        isGolden,
        goldenPrice,
        breakMA5,
        breakMA20,
        breakDowntrend,
        isHighVolume,
        buySignals,
        sellSignals,
        buyFactors,
        sellFactors,
        trend,
        score: finalScore,
        health: Math.floor(finalScore * 0.8 + Math.random() * 15),
        suggestion,
        boxSignal,
        lastUpdated: new Date().toLocaleTimeString(),
        history: points,
        suggestedEntryPrice: goldenPrice
     };
  }

  private calcIndicators(data: KlinePoint[]): KlinePoint[] {
      const results: KlinePoint[] = [];

      let ema12 = 0;
      let ema26 = 0;
      let dea = 0;
      let atr = 0;
      let avgGain = 0;
      let avgLoss = 0;
      let kValue = 50;
      let dValue = 50;
      let obv = 0;
      const obvHistory: number[] = [];

      for (let i = 0; i < data.length; i++) {
          const d = data[i];
          const close = d.close;
          const prev = i > 0 ? data[i-1] : null;

          // --- MAs ---
          const calcMa = (n: number) => {
              if (i < n - 1) return undefined;
              let sum = 0;
              for(let k=0; k<n; k++) sum += data[i-k].close;
              return sum / n;
          };
          const ma5 = calcMa(5);
          const ma10 = calcMa(10);
          const ma20 = calcMa(20);
          const ma60 = calcMa(60);

          let ma20Slope = 0;
          let ma60Slope = 0;
          if (i > 20 && ma20 && results[i-1]?.ma20) {
              ma20Slope = (ma20 - results[i-1].ma20!) / results[i-1].ma20! * 100;
          }
          if (i > 60 && ma60 && results[i-1]?.ma60) {
              ma60Slope = (ma60 - results[i-1].ma60!) / results[i-1].ma60! * 100;
          }

          // --- MACD ---
          if (i === 0) {
              ema12 = close;
              ema26 = close;
          } else {
              ema12 = (2 * close + 11 * ema12) / 13;
              ema26 = (2 * close + 25 * ema26) / 27;
          }
          const diff = ema12 - ema26;
          if (i === 0) dea = diff;
          else dea = (2 * diff + 8 * dea) / 10;
          const macd = 2 * (diff - dea);

          // --- ATR ---
          if (i === 0) atr = d.high - d.low;
          else {
              const tr = Math.max(d.high - d.low, Math.abs(d.high - prev!.close), Math.abs(d.low - prev!.close));
              atr = (atr * 13 + tr) / 14;
          }

          // --- BOLL ---
          let boll = undefined;
          if (ma20 && i >= 19) {
              let sumSq = 0;
              for (let k=0; k<20; k++) sumSq += Math.pow(data[i-k].close - ma20, 2);
              const std = Math.sqrt(sumSq / 20);
              boll = { upper: ma20 + 2 * std, mid: ma20, lower: ma20 - 2 * std, width: (4*std)/ma20 };
          }

          // --- RSI ---
          let rsi = undefined;
          if (i > 0) {
              const change = close - prev!.close;
              const gain = change > 0 ? change : 0;
              const loss = change < 0 ? -change : 0;
              if (i < 14) {
                  if (i === 1) { avgGain = gain; avgLoss = loss; }
                  else {
                      avgGain = (avgGain * (i-1) + gain) / i;
                      avgLoss = (avgLoss * (i-1) + loss) / i;
                  }
              } else {
                   avgGain = (avgGain * 13 + gain) / 14;
                   avgLoss = (avgLoss * 13 + loss) / 14;
                   if (avgLoss === 0) rsi = 100;
                   else rsi = 100 - (100 / (1 + avgGain / avgLoss));
              }
          }

          // --- KDJ ---
          let kdj = undefined;
          if (i >= 8) {
              let lowest = d.low;
              let highest = d.high;
              for(let j=0; j<9; j++) {
                  lowest = Math.min(lowest, data[i-j].low);
                  highest = Math.max(highest, data[i-j].high);
              }
              const rsv = (highest === lowest) ? 50 : (close - lowest) / (highest - lowest) * 100;
              kValue = (2/3) * kValue + (1/3) * rsv;
              dValue = (2/3) * dValue + (1/3) * kValue;
              kdj = { k: kValue, d: dValue, j: 3 * kValue - 2 * dValue };
          }

          // --- WR (14) ---
          let wr = undefined;
          if (i >= 13) {
              let h14 = -Infinity;
              let l14 = Infinity;
              for(let j=0; j<14; j++) {
                  h14 = Math.max(h14, data[i-j].high);
                  l14 = Math.min(l14, data[i-j].low);
              }
              wr = (h14 === l14) ? -50 : (h14 - close) / (h14 - l14) * -100;
          }

          // --- BIAS (20) ---
          let bias = undefined;
          if (ma20) bias = (close - ma20) / ma20 * 100;

          // --- ROC (12) ---
          let roc = undefined;
          if (i >= 12) {
              const ref = data[i-12].close;
              if (ref) roc = (close - ref) / ref * 100;
          }

          // --- MTM (12) ---
          let mtm = undefined;
          if (i >= 12) {
              mtm = close - data[i-12].close;
          }

          // --- OBV ---
          if (i > 0) {
              if (close > prev!.close) obv += d.volume;
              else if (close < prev!.close) obv -= d.volume;
          }
          obvHistory.push(obv);

          let obvMa = undefined;
          if (i >= 29) {
              let sumObv = 0;
              for(let k=0; k<30; k++) sumObv += obvHistory[i-k];
              obvMa = sumObv / 30;
          }

          results.push({
              ...d,
              ma5, ma10, ma20, ma60,
              ma20Slope, ma60Slope,
              macd: { diff, dea, macd },
              atr, boll, rsi, kdj,
              wr, bias, roc, mtm,
              obv, obvMa
          });
      }
      return results;
  }
}

import { Injectable, signal, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { ETFDefinition, ETF_LIST } from './etf-list';
import { map, forkJoin, catchError, of, Observable, from, mergeMap, toArray } from 'rxjs';

export type DataSource = 'EASTMONEY' | 'TENCENT';

export interface KlinePoint {
  date: string;
  open: number;
  close: number;
  high: number;
  low: number;
  volume: number;
  amount: number;
  // Moving Averages
  ma5?: number;
  ma10?: number;
  ma20?: number;
  ma60?: number;
  // Slopes (Percentage Change per day)
  ma20Slope?: number;
  ma60Slope?: number;

  // Indicators
  macd?: { diff: number; dea: number; macd: number };
  kdj?: { k: number; d: number; j: number };
  rsi?: number;
  wr?: number; // Williams %R
  boll?: { upper: number; mid: number; lower: number; width: number }; 
  bias?: number; // BIAS 20

  // New Indicators
  atr?: number; // Average True Range (14)
  roc?: number; // Rate of Change
  mtm?: number; // Momentum
  obv?: number; // On-Balance Volume
  obvMa?: number; // MA of OBV
}

export interface FundBaseInfo {
  fundSize: number; // In Billions (亿元)
  establishmentDate: string; // YYYY-MM-DD
  age: number; // Years since establishment
}

export interface WaveStats {
  height: number;
  days: number;
  slope: number;
}

// Updated Trade Suggestion Types for Multi-period Resonance
export type TradeSuggestion = 
  'OBSERVE' |          // 观察点
  'BUY_POINT' |        // 建仓点
  'HOLD' |             // 持仓
  'TAKE_PROFIT_REDUCE' | // 止盈(减仓)
  'TAKE_PROFIT_CLEAR' |  // 止盈(清仓)
  'STOP_LOSS_REDUCE' |   // 止损(减仓)
  'STOP_LOSS_CLEAR' |    // 止损(清仓)
  'WAIT';              // 观望

export interface BoxSignal {
  type: 'UP' | 'DOWN';
  date: string; // Entry Date
  obsDate: string; // Observation Date
  boxHigh: number;
  boxLow: number;
  boxHeight: number;
  entryPrice: number;
  poc: number; // Point of Control
  tpA: number; // Target 38.2%
  tpB: number; // Target 61.8%
  slA: number; // Stop Loss 38.2%
  slB: number; // Stop Loss 61.8%
  clearPrice: number; // Clearance Point (Box Low)
  valid: boolean;
  boxStartDate: string; // For drawing box
}

export interface ETFAnalysis extends ETFDefinition, FundBaseInfo {
  currentPrice: number;
  suggestedEntryPrice: number; // Calculated Buy Target
  goldenPrice: number; // Golden Ratio Support Price (0.618 retracement)
  changePercent7d: number;
  isGolden: boolean; 
  breakMA5: boolean;
  breakMA20: boolean;
  breakDowntrend: boolean; 
  isHighVolume: boolean;

  // Counts
  buySignals: number;
  sellSignals: number;

  // Detailed Reasons
  buyFactors: string[];
  sellFactors: string[];

  trend: 'UP' | 'DOWN' | 'SIDEWAYS';
  score: number;
  health: number; // New Health Score
  symmetry?: {
      lastWave: WaveStats;
      currentSlope: number;
      slopeRatio: number; // current / last
  };

  suggestion: TradeSuggestion;
  boxSignal?: BoxSignal | null; // Multi-period Resonance Signal
  lastUpdated: string;
  history: KlinePoint[];
}

export interface FilterState {
  searchTerm: string;
  showFilters: boolean;
  filterGolden: boolean;
  filterHighVolume: boolean;
  filterBreakDowntrend: boolean;
  filterBreakMA5: boolean;
  filterBreakMA20: boolean;
  filterTrend: string;
  filterIndustry: string; 
  filterSuggestion: string; // New Filter
  filterMinBuySignals: number;
  filterMinSellSignals: number;
  // New Filters
  filterMinScale: number; // Billion
  filterMinAge: number; // Years
  currentPage: number;
  sortField: string;
  sortDirection: 'asc' | 'desc';
}

@Injectable({
  providedIn: 'root'
})
export class EtfService {
  private http: HttpClient = inject(HttpClient);

  // State
  dataSource = signal<DataSource>('EASTMONEY');
  loading = signal<boolean>(false);
  error = signal<string | null>(null);
  etfData = signal<ETFAnalysis[]>([]);

  // Favorites State
  favorites = signal<Set<string>>(new Set());
  private readonly FAV_STORAGE_KEY = 'etf_favorites_v1';
  private readonly DEFAULT_FAVORITES = [
    '512480', // 半导体ETF
    '512400', // 有色ETF
    '513060', // 恒生医疗ETF
    '159611', // 电力ETF
    '515790', // 光伏ETF
    '512660', // 军工ETF
    '515000', // 科技ETF
    '159995', // 芯片ETF
    '159819', // 人工智能ETF
    '512800', // 银行ETF
    '512010', // 医药ETF
    '512880', // 证券ETF
    '515220', // 煤炭ETF
    '510300', // 沪深300ETF
    '510500', // 中证500ETF
    '513180', // 恒生科技指数ETF
    '159941', // 纳指ETF
    '513500', // 标普500ETF
    '513880', // 日经225ETF
    '518880', // 黄金ETF
    '511260'  // 十年国债ETF
  ];

  // Available industries for filter dropdown
  availableIndustries = signal<string[]>(['宽基/指数','科技/TMT','医药/生物','大消费','新能源/车','金融','周期/资源','军工','债券','货币','其他']);

  // Filter State Persistence
  filterState = signal<FilterState>({
    searchTerm: '',
    showFilters: false,
    filterGolden: false,
    filterHighVolume: false,
    filterBreakDowntrend: false,
    filterBreakMA5: false,
    filterBreakMA20: false,
    filterTrend: 'ALL',
    filterIndustry: 'ALL',
    filterSuggestion: 'ALL',
    filterMinBuySignals: 0,
    filterMinSellSignals: 0,
    filterMinScale: 0,
    filterMinAge: 0,
    currentPage: 1,
    sortField: 'score',
    sortDirection: 'desc'
  });

  constructor() {
      this.loadFavorites();
  }

  private loadFavorites() {
      const stored = localStorage.getItem(this.FAV_STORAGE_KEY);
      if (stored) {
          try {
              const parsed = JSON.parse(stored);
              if (Array.isArray(parsed) && parsed.length > 0) {
                  this.favorites.set(new Set(parsed));
              } else {
                  this.favorites.set(new Set(this.DEFAULT_FAVORITES));
              }
          } catch (e) {
              this.favorites.set(new Set(this.DEFAULT_FAVORITES));
          }
      } else {
          this.favorites.set(new Set(this.DEFAULT_FAVORITES));
      }
  }

  toggleFavorite(code: string) {
      this.favorites.update(set => {
          const newSet = new Set(set);
          if (newSet.has(code)) {
              newSet.delete(code);
          } else {
              newSet.add(code);
          }
          localStorage.setItem(this.FAV_STORAGE_KEY, JSON.stringify(Array.from(newSet)));
          return newSet;
      });
  }

  isFavorite(code: string): boolean {
      return this.favorites().has(code);
  }

  updateFilterState(updates: Partial<FilterState>) {
    this.filterState.update(state => ({ ...state, ...updates }));
  }

  resetFilterState() {
     this.filterState.set({
        searchTerm: '',
        showFilters: false,
        filterGolden: false,
        filterHighVolume: false,
        filterBreakDowntrend: false,
        filterBreakMA5: false,
        filterBreakMA20: false,
        filterTrend: 'ALL',
        filterIndustry: 'ALL',
        filterSuggestion: 'ALL',
        filterMinBuySignals: 0,
        filterMinSellSignals: 0,
        filterMinScale: 0,
        filterMinAge: 0,
        currentPage: 1,
        sortField: 'score',
        sortDirection: 'desc'
     });
  }

  // Helpers
  private getMarketCode(code: string): string {
    if (code.startsWith('5') || code.startsWith('6')) return '1';
    return '0';
  }

  private getTencentCode(code: string): string {
    // 5xx, 6xx, 58x -> sh
    // 1xx, 0xx, 3xx -> sz
    if (/^[56]/.test(code)) return `sh${code}`;
    return `sz${code}`;
  }

  private classifyETF(name: string): string {
    if (/(300|500|1000|2000|50|100|800|创业板|科创|恒生|纳指|标普|红利|MSCI|综指|成指|大湾区|双创|中证|A50|道琼斯|日经|德国|法国|英国|东南亚|沙特)/.test(name)) return '宽基/指数';
    if (/(芯片|半导体|计算机|电子|5G|人工智能|游戏|传媒|通信|软件|科技|互联|AI|数据|卫星|信创|机器人|云计算|元宇宙|智能|信息|机床)/.test(name)) return '科技/TMT';
    if (/(医疗|药|生物|疫苗|医|健康|基因|中药)/.test(name)) return '医药/生物';
    if (/(酒|食品|家电|消费|旅游|养殖|农|畜|文娱|教育|美妆|饮料|乳)/.test(name)) return '大消费';
    if (/(光伏|电池|新能源|碳中和|车|绿电|电力|储能|环保|低碳|光电)/.test(name)) return '新能源/车';
    if (/(银行|券商|证券|保险|金融|FinTech|央企股东回报)/i.test(name)) return '金融';
    if (/(黄金|豆粕|有色|金属|稀土|铝|铜|矿|油|石化|煤炭|钢铁|能源|化工|基建|地产|房地产|建材|材料)/.test(name)) return '周期/资源';
    if (/(军工|国防|航天)/.test(name)) return '军工';
    if (/(债|政金|国开|同业存单)/.test(name)) return '债券';
    if (/(货币|理财|现金)/.test(name)) return '货币';
    return '其他';
  }

  private parseRawNumber(val: any): number {
    if (val === undefined || val === null || val === '-') return 0;
    if (typeof val === 'number') return val;
    return parseFloat(val) || 0;
  }

  // --- Main Methods ---

  loadAllEtfs() {
    if (this.loading()) return;
    this.loading.set(true);
    this.error.set(null);

    if (this.dataSource() === 'EASTMONEY') {
      this.loadEastmoneyData();
    } else {
      this.loadTencentData();
    }
  }

  private loadEastmoneyData() {
    const marketCodes = ETF_LIST.map(e => `${this.getMarketCode(e.code)}.${e.code}`);
    const chunks: string[][] = [];
    const chunkSize = 80;
    for (let i = 0; i < marketCodes.length; i += chunkSize) {
        chunks.push(marketCodes.slice(i, i + chunkSize));
    }

    const reqs = chunks.map(chunk => {
        const ids = chunk.join(',');
        const url = `https://push2.eastmoney.com/api/qt/ulist.get?pi=0&pz=200&po=1&np=1&fltt=2&invt=2&fields=f2,f3,f12,f14,f15,f16,f17,f20,f21,f116,f117&secids=${ids}`;
        return this.http.jsonp<any>(url, 'cb').pipe(
           catchError(() => of(null))
        );
    });

    forkJoin(reqs).subscribe({
        next: (responses) => {
            const rawDataMap = new Map<string, any>();
            responses.forEach((res: any) => {
                if(res && res.data && res.data.diff) {
                    res.data.diff.forEach((d: any) => {
                        rawDataMap.set(d.f12, d);
                    });
                }
            });

            const baseAnalysis: ETFAnalysis[] = ETF_LIST.map(def => {
                const raw = rawDataMap.get(def.code) || {};
                const price = this.parseRawNumber(raw.f2); // f2 price

                let marketCap = this.parseRawNumber(raw.f20); 

                if (!marketCap || marketCap <= 0) {
                    marketCap = this.parseRawNumber(raw.f21);
                }

                if ((!marketCap || marketCap <= 0) && price > 0) {
                     const totalShares = this.parseRawNumber(raw.f116);
                     if (totalShares > 0) marketCap = price * totalShares;
                }

                if ((!marketCap || marketCap <= 0) && price > 0) {
                     const floatShares = this.parseRawNumber(raw.f117);
                     if (floatShares > 0) marketCap = price * floatShares;
                }

                return this.createAnalysisObject(def, price, raw.f3, marketCap);
            });

            this.etfData.set(baseAnalysis);
            this.fetchHistories(baseAnalysis);
        },
        error: (err) => {
            console.error(err);
            this.error.set('无法连接东方财富行情服务器');
            this.loading.set(false);
        }
    });
  }

  private loadTencentData() {
    const tencentCodes = ETF_LIST.map(e => this.getTencentCode(e.code));
    const chunks: string[][] = [];
    const chunkSize = 50; // Tencent URL limit safe
    for (let i = 0; i < tencentCodes.length; i += chunkSize) {
        chunks.push(tencentCodes.slice(i, i + chunkSize));
    }

    const promises = chunks.map(chunk => {
       const ids = chunk.join(',');
       // Use HTTPS to avoid mixed content block
       const url = `https://qt.gtimg.cn/q=${ids}`;
       return this.injectScript(url).then(() => {
          const results: any[] = [];
          chunk.forEach(code => {
             const raw = (window as any)[`v_${code}`];
             if (raw) {
                const parts = raw.split('~');
                // parts[1]=Name, parts[2]=Code, parts[3]=Price, parts[32]=Change%
                // parts[45]=TotalMarketCap(Approx) - check index validity
                // Typical: 1:Name, 2:Code, 3:Price, 32:Pct, 45:MktCap
                results.push({
                   code: parts[2],
                   price: parseFloat(parts[3]),
                   changePct: parseFloat(parts[32]),
                   marketCap: parseFloat(parts[45] || '0') * 100000000 // Often usually unit is approx
                });
             }
          });
          return results;
       }).catch(() => []);
    });

    Promise.all(promises).then(allChunks => {
        const flatResults = allChunks.flat();
        const resultMap = new Map<string, any>();
        flatResults.forEach(r => resultMap.set(r.code, r));

        const baseAnalysis: ETFAnalysis[] = ETF_LIST.map(def => {
             const data = resultMap.get(def.code);
             const price = data ? data.price : 0;
             const change = data ? data.changePct : 0;
             const mcap = data ? data.marketCap : 0;
             return this.createAnalysisObject(def, price, change, mcap);
        });

        this.etfData.set(baseAnalysis);
        this.fetchHistories(baseAnalysis);
    }).catch(err => {
        console.error(err);
        this.error.set('无法连接腾讯数据接口');
        this.loading.set(false);
    });
  }

  private injectScript(url: string): Promise<void> {
      return new Promise((resolve, reject) => {
          const script = document.createElement('script');
          script.src = url;
          script.charset = 'gbk'; // Tencent often returns GBK
          script.onload = () => {
             document.body.removeChild(script);
             resolve();
          };
          script.onerror = () => {
             document.body.removeChild(script);
             reject();
          };
          document.body.appendChild(script);
      });
  }

  private createAnalysisObject(def: ETFDefinition, price: number, change: number, marketCap: number): ETFAnalysis {
      return {
        ...def,
        currentPrice: price,
        changePercent7d: 0,
        isGolden: false,
        breakMA5: false,
        breakMA20: false,
        breakDowntrend: false,
        isHighVolume: false,
        buySignals: 0,
        sellSignals: 0,
        buyFactors: [],
        sellFactors: [],
        trend: 'SIDEWAYS',
        score: 50,
        health: 50,
        suggestion: 'WAIT',
        lastUpdated: new Date().toLocaleTimeString(),
        history: [],
        fundSize: marketCap / 100000000, 
        establishmentDate: '',
        age: 0,
        suggestedEntryPrice: 0,
        goldenPrice: 0,
        industry: def.industry || this.classifyETF(def.name)
    };
  }

  private fetchHistories(currentList: ETFAnalysis[]) {
     from(currentList).pipe(
        mergeMap(item => this.fetchSingleHistory(item, 120), 6), 
        toArray()
     ).subscribe(updatedList => {
        this.etfData.set(updatedList);
        this.loading.set(false);
     });
  }

  private fetchSingleHistory(item: ETFAnalysis, limit: number): Observable<ETFAnalysis> {
     // NOTE: We keep Eastmoney as the source for K-line History because of its cleaner JSON API
     // regardless of the Snapshot source.
     const secid = `${this.getMarketCode(item.code)}.${item.code}`;
     // Added random timestamp to prevent caching
     const url = `https://push2his.eastmoney.com/api/qt/stock/kline/get?secid=${secid}&fields1=f1,f2,f3,f4,f5,f6&fields2=f51,f52,f53,f54,f55,f56,f57,f58,f59,f60,f61&klt=101&fqt=1&end=20500101&lmt=${limit}&_=${Date.now()}`;

     return this.http.jsonp<any>(url, 'cb').pipe(
        map((res: any) => {
            if (res && res.data && res.data.klines) {
                const history = this.parseKlines(res.data.klines);
                return this.analyzeETF(item, history);
            }
            // If data is missing but we have an item, return item to avoid breaking pipeline
            return item;
        }),
        catchError(err => {
            console.warn(`Failed to fetch history for ${item.code}`, err);
            return of(item);
        })
     );
  }

  getEtfDetails(code: string): Observable<ETFAnalysis | null> {
    const existing = this.etfData().find(e => e.code === code);
    // CRITICAL FIX: Only return existing if it has history. 
    // If it was just loaded from Tencent snapshot (history=[]), we MUST fetch history now.
    if (existing && existing.history.length > 0) return of(existing);

    let def = ETF_LIST.find(e => e.code === code);
    if (!def) {
       def = { code, name: code, industry: '未知' };
    }

    // If existing (Tencent snapshot), use its currentPrice, otherwise 0
    const price = existing ? existing.currentPrice : 0;
    const tempItem = this.createAnalysisObject(def, price, 0, 0);
    return this.fetchSingleHistory(tempItem, 120);
  }

  getBacktestData(code: string): Observable<ETFAnalysis | null> {
      let def = ETF_LIST.find(e => e.code === code);
      if (!def) def = { code, name: code, industry: '未知' };
      const tempItem = this.createTempItem(def);
      return this.fetchSingleHistory(tempItem, 2000);
  }

  private createTempItem(def: ETFDefinition): ETFAnalysis {
      return this.createAnalysisObject(def, 0, 0, 0);
  }

  // --- Parsing & Analysis ---

  private parseKlines(rawLines: string[]): KlinePoint[] {
    return rawLines.map(line => {
       const p = line.split(',');
       return {
          date: p[0],
          open: parseFloat(p[1]),
          close: parseFloat(p[2]),
          high: parseFloat(p[3]),
          low: parseFloat(p[4]),
          volume: parseFloat(p[5]),
          amount: parseFloat(p[6])
       };
    });
  }

  private calcBoxSignals(fullHistory: KlinePoint[]): BoxSignal | null {
      const minBoxSize = 30;
      if (fullHistory.length < minBoxSize + 5) return null;

      const scanLimit = Math.max(minBoxSize + 5, fullHistory.length - 60);

      for (let i = fullHistory.length - 1; i >= scanLimit; i--) {
          const entryDay = fullHistory[i];
          const confirmDay = fullHistory[i-1];
          const obsDay = fullHistory[i-2];

          const boxEndIdx = i - 2;
          const boxStartIdx = boxEndIdx - 29; 

          if (boxStartIdx < 0) continue;

          const boxData = fullHistory.slice(boxStartIdx, boxEndIdx + 1);
          const boxHigh = Math.max(...boxData.map(d => d.high));
          const boxLow = Math.min(...boxData.map(d => d.low));
          const D = boxHigh - boxLow;

          if (confirmDay.close > boxHigh && entryDay.close > boxHigh) {

             const prices = boxData.map(d => d.close);
             const minP = Math.min(...prices);
             const maxP = Math.max(...prices);
             const bins = 20;
             const binSize = (maxP - minP) / bins;
             let poc = (minP + maxP) / 2;

             if (binSize > 0) {
                 const binVols = new Array(bins).fill(0);
                 boxData.forEach(d => {
                    const idx = Math.min(bins-1, Math.floor((d.close - minP)/binSize));
                    binVols[idx] += d.volume;
                 });
                 const maxBinIdx = binVols.indexOf(Math.max(...binVols));
                 poc = minP + (maxBinIdx + 0.5) * binSize;
             }

             const volSlice = fullHistory.slice(i-5, i);
             const avgVol5 = volSlice.reduce((a,b)=>a+b.volume,0)/volSlice.length;

             const volSpike = entryDay.volume > 1.2 * avgVol5 || confirmDay.volume > 1.2 * avgVol5;
             const priceValid = entryDay.close > poc;

             if (priceValid && volSpike) {
                 return {
                     type: 'UP',
                     date: entryDay.date,
                     obsDate: obsDay.date,
                     entryPrice: entryDay.close,
                     boxStartDate: fullHistory[boxStartIdx].date,
                     boxHigh,
                     boxLow,
                     boxHeight: D,
                     poc,
                     tpA: entryDay.close + D * 0.382,
                     tpB: entryDay.close + D * 0.618,
                     slA: entryDay.close - D * 0.382,
                     slB: entryDay.close - D * 0.618,
                     clearPrice: boxLow, 
                     valid: true
                 };
             }
          }
      }
      return null;
  }

  private analyzeETF(item: ETFAnalysis, history: KlinePoint[]): ETFAnalysis {
     // Ensure history is attached even if analysis skips
     if (!history || history.length < 20) return { ...item, history: history || [] };

     const points = this.calcIndicators(history);
     const latest = points[points.length - 1];
     const prev = points[points.length - 2];

     // CRITICAL FIX: If item has a valid snapshot price, use it. 
     // BUT if snapshot price is 0 (failed/default), fallback to latest K-line close.
     const currentPrice = (item.currentPrice && item.currentPrice > 0) ? item.currentPrice : latest.close;

     // Trend Analysis
     let trend: 'UP' | 'DOWN' | 'SIDEWAYS' = 'SIDEWAYS';
     if (latest.ma20 && prev.ma20) {
        if (currentPrice > latest.ma20 && latest.ma20 > prev.ma20) trend = 'UP';
        else if (currentPrice < latest.ma20 && latest.ma20 < prev.ma20) trend = 'DOWN';
     }

     const volAvg5 = points.slice(-5).reduce((a, b) => a + b.volume, 0) / 5;
     const isHighVolume = latest.volume > 1.5 * volAvg5;

     // Base Signals
     let buySignals = 0;
     let sellSignals = 0;
     const buyFactors: string[] = [];
     const sellFactors: string[] = [];

     // Use `currentPrice` for comparisons
     const breakMA5 = currentPrice < (latest.ma5 || 0);
     const breakMA20 = currentPrice < (latest.ma20 || 0);
     const breakDowntrend = prev.close < (prev.ma20 || 0) && currentPrice > (latest.ma20 || 0);

     if (breakDowntrend) { buySignals++; buyFactors.push('突破20日均线'); }
     if (isHighVolume && currentPrice > latest.open) { buySignals++; buyFactors.push('放量上涨'); }

     // Golden Ratio
     const recent = points.slice(-30);
     const maxHigh = Math.max(...recent.map(p => p.high));
     const minLow = Math.min(...recent.map(p => p.low));
     const range = maxHigh - minLow;
     const goldenPrice = maxHigh - range * 0.382;
     const isGolden = Math.abs(currentPrice - goldenPrice) / goldenPrice < 0.02;

     if (isGolden && trend === 'UP') { buySignals += 2; buyFactors.push('黄金分割支撑位'); }

     // MACD
     if (latest.macd && prev.macd) {
        if (latest.macd.macd > 0 && prev.macd.macd <= 0) { buySignals += 2; buyFactors.push('MACD金叉'); }
        if (latest.macd.macd < 0 && prev.macd.macd >= 0) { sellSignals += 2; sellFactors.push('MACD死叉'); }
     }

     if (breakMA20) { sellSignals++; sellFactors.push('跌破20日均线'); }

     // --- Enhanced Signal Logic ---
     // 1. Moving Averages Alignment
     if (latest.ma5 && latest.ma10 && latest.ma20) {
         if (latest.ma5 > latest.ma10 && latest.ma10 > latest.ma20) {
             buySignals++; buyFactors.push('均线多头排列');
         }
         if (latest.ma5 < latest.ma10 && latest.ma10 < latest.ma20) {
             sellSignals++; sellFactors.push('均线空头排列');
         }
     }

     // 2. RSI
     if (latest.rsi) {
         if (latest.rsi < 30) { buySignals++; buyFactors.push('RSI超卖区'); }
         if (latest.rsi > 70) { sellSignals++; sellFactors.push('RSI超买区'); }
     }

     // 3. KDJ
     if (latest.kdj && prev.kdj) {
         if (prev.kdj.k < prev.kdj.d && latest.kdj.k > latest.kdj.d && latest.kdj.d < 50) {
             buySignals++; buyFactors.push('KDJ低位金叉');
         }
         if (prev.kdj.k > prev.kdj.d && latest.kdj.k < latest.kdj.d && latest.kdj.d > 50) {
             sellSignals++; sellFactors.push('KDJ高位死叉');
         }
     }

     // 4. MA60 Trend
     if (latest.ma60) {
         if (currentPrice > latest.ma60 && prev.close <= prev.ma60) {
             buySignals++; buyFactors.push('站上60日均线');
         }
         if (currentPrice < latest.ma60 && prev.close >= prev.ma60) {
             sellSignals++; sellFactors.push('跌破60日均线');
         }
     }

     // Box Signal Calculation
     const boxSignal = this.calcBoxSignals(points);

     // --- NEW SCORING MODEL (0-100) ---

     // 1. Trend (35%)
     let trendScore = 0;
     const ma5 = latest.ma5 || 0;
     const ma10 = latest.ma10 || 0;
     const ma20 = latest.ma20 || 0;
     const ma60 = latest.ma60 || 0;

     if (ma5 > ma10 && ma10 > ma20) trendScore += 15;
     if (ma20 > ma60) trendScore += 15;
     if (currentPrice > ma20) trendScore += 10;
     if (currentPrice > ma60) trendScore += 10;
     if ((latest.ma20Slope || 0) > 0) trendScore += 10;
     if ((latest.ma60Slope || 0) > 0) trendScore += 10;
     trendScore = Math.min(35, trendScore * (35/70));

     // 2. Momentum (30%)
     let momScore = 0;
     const macdVal = latest.macd?.macd || 0;
     const diff = latest.macd?.diff || 0;
     const dea = latest.macd?.dea || 0;
     if (macdVal > 0) momScore += 10;
     if (diff > dea) momScore += 10;

     const rsiVal = latest.rsi || 50;
     if (rsiVal > 50 && rsiVal < 80) momScore += 10;
     if (rsiVal >= 80) momScore -= 5;

     const k = latest.kdj?.k || 50;
     const dVal = latest.kdj?.d || 50;
     if (k > dVal) momScore += 10;
     if ((latest.roc || 0) > 0) momScore += 10;
     momScore = Math.min(30, momScore * (30/50));

     // 3. Volatility (15%)
     let volScore = 0;
     const wr = latest.wr || -50;
     if (wr > -80 && wr < -20) volScore += 10; 
     const bias = latest.bias || 0;
     if (bias > 0 && bias < 5) volScore += 10; 
     const boll = latest.boll;
     if (boll && currentPrice > boll.mid && currentPrice < boll.upper) volScore += 10;
     volScore = Math.min(15, volScore * (15/30));

     // 4. Volume (20%)
     let volumeScore = 0;
     if (latest.obv && latest.obvMa && latest.obv > latest.obvMa) volumeScore += 15;
     if (latest.volume > volAvg5) volumeScore += 10;
     if (currentPrice > latest.open) volumeScore += 5; 
     volumeScore = Math.min(20, volumeScore * (20/30));

     // Total Score
     let finalScore = trendScore + momScore + volScore + volumeScore;

     // Bonus for Box Signal
     if (boxSignal && boxSignal.valid) {
         if (currentPrice > boxSignal.entryPrice && currentPrice < boxSignal.tpA) {
             finalScore += 15;
             buyFactors.push('箱体突破共振(Box Breakout)');
         }
     }

     if (rsiVal > 85) finalScore -= 10;
     if (trend === 'DOWN') finalScore -= 15;
     finalScore = Math.max(0, Math.min(100, Math.round(finalScore)));

     // Trade Suggestion Logic
     let suggestion: TradeSuggestion = 'WAIT';

     if (boxSignal && boxSignal.valid) {
         const p = currentPrice;
         if (p < boxSignal.clearPrice) {
             suggestion = 'STOP_LOSS_CLEAR';
             sellFactors.push('跌破箱体下沿(Clearance)');
             finalScore = Math.min(finalScore, 20);
         }
         else if (p < boxSignal.slB) {
             suggestion = 'STOP_LOSS_CLEAR';
             sellFactors.push('触及止损B线');
             finalScore = Math.min(finalScore, 20);
         }
         else if (p < boxSignal.slA) {
             suggestion = 'STOP_LOSS_REDUCE';
             sellFactors.push('触及止损A线');
             finalScore = Math.min(finalScore, 30);
         }
         else if (p >= boxSignal.tpB) {
             suggestion = 'TAKE_PROFIT_CLEAR';
             sellFactors.push('达到止盈B目标');
         }
         else if (p >= boxSignal.tpA) {
             suggestion = 'TAKE_PROFIT_REDUCE';
             sellFactors.push('达到止盈A目标');
         }
         else if (p > boxSignal.entryPrice) {
             suggestion = 'HOLD';
         }
         else {
             suggestion = 'BUY_POINT';
         }
     } else {
         if (finalScore >= 80) suggestion = 'BUY_POINT';
         else if (finalScore >= 60) suggestion = 'HOLD';
         else if (finalScore <= 35) suggestion = 'STOP_LOSS_REDUCE';
         else if (finalScore <= 20) suggestion = 'STOP_LOSS_CLEAR';
     }

     return {
        ...item,
        currentPrice: currentPrice, // Return the prioritized price
        changePercent7d: (currentPrice - (points[points.length - 6]?.close || currentPrice)) / (points[points.length - 6]?.close || 1) * 100,
        isGolden,
        goldenPrice,
        breakMA5,
        breakMA20,
        breakDowntrend,
        isHighVolume,
        buySignals,
        sellSignals,
        buyFactors,
        sellFactors,
        trend,
        score: finalScore,
        health: Math.floor(finalScore * 0.8 + Math.random() * 15),
        suggestion,
        boxSignal,
        lastUpdated: new Date().toLocaleTimeString(),
        history: points,
        suggestedEntryPrice: goldenPrice
     };
  }

  private calcIndicators(data: KlinePoint[]): KlinePoint[] {
      const results: KlinePoint[] = [];

      let ema12 = 0;
      let ema26 = 0;
      let dea = 0;
      let atr = 0;
      let avgGain = 0;
      let avgLoss = 0;
      let kValue = 50;
      let dValue = 50;
      let obv = 0;
      const obvHistory: number[] = [];

      for (let i = 0; i < data.length; i++) {
          const d = data[i];
          const close = d.close;
          const prev = i > 0 ? data[i-1] : null;

          // --- MAs ---
          const calcMa = (n: number) => {
              if (i < n - 1) return undefined;
              let sum = 0;
              for(let k=0; k<n; k++) sum += data[i-k].close;
              return sum / n;
          };
          const ma5 = calcMa(5);
          const ma10 = calcMa(10);
          const ma20 = calcMa(20);
          const ma60 = calcMa(60);

          let ma20Slope = 0;
          let ma60Slope = 0;
          if (i > 20 && ma20 && results[i-1]?.ma20) {
              ma20Slope = (ma20 - results[i-1].ma20!) / results[i-1].ma20! * 100;
          }
          if (i > 60 && ma60 && results[i-1]?.ma60) {
              ma60Slope = (ma60 - results[i-1].ma60!) / results[i-1].ma60! * 100;
          }

          // --- MACD ---
          if (i === 0) {
              ema12 = close;
              ema26 = close;
          } else {
              ema12 = (2 * close + 11 * ema12) / 13;
              ema26 = (2 * close + 25 * ema26) / 27;
          }
          const diff = ema12 - ema26;
          if (i === 0) dea = diff;
          else dea = (2 * diff + 8 * dea) / 10;
          const macd = 2 * (diff - dea);

          // --- ATR ---
          if (i === 0) atr = d.high - d.low;
          else {
              const tr = Math.max(d.high - d.low, Math.abs(d.high - prev!.close), Math.abs(d.low - prev!.close));
              atr = (atr * 13 + tr) / 14;
          }

          // --- BOLL ---
          let boll = undefined;
          if (ma20 && i >= 19) {
              let sumSq = 0;
              for (let k=0; k<20; k++) sumSq += Math.pow(data[i-k].close - ma20, 2);
              const std = Math.sqrt(sumSq / 20);
              boll = { upper: ma20 + 2 * std, mid: ma20, lower: ma20 - 2 * std, width: (4*std)/ma20 };
          }

          // --- RSI ---
          let rsi = undefined;
          if (i > 0) {
              const change = close - prev!.close;
              const gain = change > 0 ? change : 0;
              const loss = change < 0 ? -change : 0;
              if (i < 14) {
                  if (i === 1) { avgGain = gain; avgLoss = loss; }
                  else {
                      avgGain = (avgGain * (i-1) + gain) / i;
                      avgLoss = (avgLoss * (i-1) + loss) / i;
                  }
              } else {
                   avgGain = (avgGain * 13 + gain) / 14;
                   avgLoss = (avgLoss * 13 + loss) / 14;
                   if (avgLoss === 0) rsi = 100;
                   else rsi = 100 - (100 / (1 + avgGain / avgLoss));
              }
          }

          // --- KDJ ---
          let kdj = undefined;
          if (i >= 8) {
              let lowest = d.low;
              let highest = d.high;
              for(let j=0; j<9; j++) {
                  lowest = Math.min(lowest, data[i-j].low);
                  highest = Math.max(highest, data[i-j].high);
              }
              const rsv = (highest === lowest) ? 50 : (close - lowest) / (highest - lowest) * 100;
              kValue = (2/3) * kValue + (1/3) * rsv;
              dValue = (2/3) * dValue + (1/3) * kValue;
              kdj = { k: kValue, d: dValue, j: 3 * kValue - 2 * dValue };
          }

          // --- WR (14) ---
          let wr = undefined;
          if (i >= 13) {
              let h14 = -Infinity;
              let l14 = Infinity;
              for(let j=0; j<14; j++) {
                  h14 = Math.max(h14, data[i-j].high);
                  l14 = Math.min(l14, data[i-j].low);
              }
              wr = (h14 === l14) ? -50 : (h14 - close) / (h14 - l14) * -100;
          }

          // --- BIAS (20) ---
          let bias = undefined;
          if (ma20) bias = (close - ma20) / ma20 * 100;

          // --- ROC (12) ---
          let roc = undefined;
          if (i >= 12) {
              const ref = data[i-12].close;
              if (ref) roc = (close - ref) / ref * 100;
          }

          // --- MTM (12) ---
          let mtm = undefined;
          if (i >= 12) {
              mtm = close - data[i-12].close;
          }

          // --- OBV ---
          if (i > 0) {
              if (close > prev!.close) obv += d.volume;
              else if (close < prev!.close) obv -= d.volume;
          }
          obvHistory.push(obv);

          let obvMa = undefined;
          if (i >= 29) {
              let sumObv = 0;
              for(let k=0; k<30; k++) sumObv += obvHistory[i-k];
              obvMa = sumObv / 30;
          }

          results.push({
              ...d,
              ma5, ma10, ma20, ma60,
              ma20Slope, ma60Slope,
              macd: { diff, dea, macd },
              atr, boll, rsi, kdj,
              wr, bias, roc, mtm,
              obv, obvMa
          });
      }
      return results;
  }
}

import * as d3 from 'd3';
import { KlinePoint, BoxSignal } from '../../../services/etf.service';
import { SelectionGroup, ScaleBand, ScaleLinear, calculateLR } from './types';

// --- 4. Volume Profile + 123 Painter ---
export function drawVolumeProfile(
    container: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    y: ScaleLinear,
    width: number
) {
    const yMin = y.domain()[0];
    const yMax = y.domain()[1];
    const binCount = 50;
    const binSize = (yMax - yMin) / binCount;
    const bins = new Array(binCount).fill(0);
    let maxVolBin = 0;
    let maxVolIdx = 0;

    data.forEach(d => {
        const idx = Math.floor((d.close - yMin) / binSize);
        if (idx >= 0 && idx < binCount) {
            bins[idx] += d.volume;
            if (bins[idx] > maxVolBin) {
                maxVolBin = bins[idx];
                maxVolIdx = idx;
            }
        }
    });

    const pocPrice = yMin + (maxVolIdx + 0.5) * binSize;
    const maxBarWidth = width * 0.2; 
    const vpGroup = container.append('g').attr('transform', `translate(${width}, 0)`);

    bins.forEach((vol, i) => {
        const barW = (vol / maxVolBin) * maxBarWidth;
        const barY = y(yMin + (i+1)*binSize);
        const barH = Math.abs(y(yMin + i*binSize) - barY);

        vpGroup.append('rect')
            .attr('x', -barW)
            .attr('y', barY)
            .attr('width', barW)
            .attr('height', barH)
            .attr('fill', i === maxVolIdx ? '#eab308' : '#64748b') 
            .attr('opacity', i === maxVolIdx ? 0.4 : 0.1);
    });

    container.append('line')
        .attr('x1', 0).attr('x2', width)
        .attr('y1', y(pocPrice)).attr('y2', y(pocPrice))
        .attr('stroke', '#eab308').attr('stroke-width', 1.5).attr('stroke-dasharray', '4,2');

    container.append('text')
        .attr('x', width - 5).attr('y', y(pocPrice) - 4)
        .text('POC (筹码峰)').attr('fill', '#eab308')
        .attr('font-size', '10px').attr('font-weight', 'bold').attr('text-anchor', 'end');

    // ZigZag / Wave Theory
    const zigzag = calculateZigZag(data);

    const lineGen = d3.line<{x:number, y:number, date: string}>()
        .x(d => x(d.date)! + x.bandwidth()/2)
        .y(d => y(d.y));

    // Draw Thin Black Lines for Segments
    container.append('path')
        .datum(zigzag)
        .attr('fill', 'none')
        .attr('stroke', '#000000') 
        .attr('stroke-width', 1)
        .attr('opacity', 0.8)
        .attr('d', (d) => lineGen(d.map(p => ({x: p.x, y: p.y, date: p.date}))));

    // Draw Wave Labels (1, 2, 3, 4, 5, A, B, C)
    const waveLabels = ['1', '2', '3', '4', '5', 'A', 'B', 'C'];

    if (zigzag.length > 0) {
        zigzag.forEach((p, idx) => {
            const px = x(p.date)! + x.bandwidth()/2;
            const py = y(p.y);
            const label = waveLabels[idx % waveLabels.length];

            // Offset logic: HIGH above candle, LOW below candle
            const yOffset = p.type === 'HIGH' ? -15 : 15;

            const g = container.append('g').attr('transform', `translate(${px}, ${py + yOffset})`);

            // Purple Hollow Circle
            g.append('circle')
                .attr('r', 7)
                .attr('fill', 'white')
                .attr('stroke', '#a855f7') // Purple
                .attr('stroke-width', 1.5);

            // Text inside circle
            g.append('text')
                .text(label)
                .attr('dy', '0.35em')
                .attr('text-anchor', 'middle')
                .attr('fill', '#a855f7')
                .attr('font-size', '9px')
                .attr('font-weight', 'bold');
        });
    }
}

// --- 5. Resonance Signal Painter (Box Strategy) ---
export function drawResonanceSignal(
    container: SelectionGroup,
    signal: BoxSignal,
    x: ScaleBand,
    y: ScaleLinear,
    width: number
) {
    if (!signal || !signal.valid) return;

    const boxStartX = x(signal.boxStartDate);
    const obsX = x(signal.obsDate);
    const entryX = x(signal.date);
    const yHigh = y(signal.boxHigh);
    const yLow = y(signal.boxLow);
    const yPoc = y(signal.poc);
    const lineStart = boxStartX !== undefined ? boxStartX : (entryX !== undefined ? 0 : 0);

    if (entryX !== undefined || (boxStartX !== undefined)) {
            container.append('line').attr('x1', lineStart).attr('x2', width).attr('y1', yLow).attr('y2', yLow).attr('stroke', '#334155').attr('stroke-width', 2).attr('stroke-opacity', 0.8);
            container.append('line').attr('x1', lineStart).attr('x2', width).attr('y1', yHigh).attr('y2', yHigh).attr('stroke', '#334155').attr('stroke-width', 2).attr('stroke-opacity', 0.8);
            container.append('line').attr('x1', lineStart).attr('x2', width).attr('y1', yPoc).attr('y2', yPoc).attr('stroke', '#f97316').attr('stroke-width', 1).attr('stroke-dasharray', '4,2');
            if (boxStartX !== undefined) {
            container.append('text').attr('x', boxStartX + 5).attr('y', yPoc - 3).text('POC').attr('fill', '#f97316').attr('font-size', '10px');
            }
    }
    if (obsX !== undefined) {
            container.append('text').attr('x', obsX + x.bandwidth()/2).attr('y', yHigh - 10).text('👁').attr('font-size', '14px').attr('text-anchor', 'middle');
    }
    if (entryX !== undefined) {
        const cx = entryX + x.bandwidth()/2;
        const yEntry = y(signal.entryPrice);
        container.append('text').attr('x', cx).attr('y', yEntry + 15).text('🚩').attr('font-size', '14px').attr('text-anchor', 'middle');
        container.append('text').attr('x', cx).attr('y', yEntry + 28).text('建仓').attr('fill', '#ef4444').attr('font-size', '10px').attr('text-anchor', 'middle').attr('font-weight', 'bold');
    }

    const drawTarget = (val: number, label: string, color: string, icon: string) => {
        const yPos = y(val);
        container.append('line').attr('x1', 0).attr('x2', width).attr('y1', yPos).attr('y2', yPos).attr('stroke', color).attr('stroke-width', 1).attr('opacity', 0.8); 
        container.append('text').attr('x', 5).attr('y', yPos - 4).text(icon).attr('font-size', '14px').attr('text-anchor', 'start');
        container.append('text').attr('x', 25).attr('y', yPos - 4).text(`${label} : ${val.toFixed(3)}`).attr('fill', color).attr('font-size', '10px').attr('font-weight', 'bold').attr('text-anchor', 'start');
    };
    drawTarget(signal.tpA, '止盈A', '#ef4444', '🎯');
    drawTarget(signal.tpB, '止盈B', '#ef4444', '💰');
    drawTarget(signal.slA, '止损A', '#22c55e', '🛡');
    drawTarget(signal.slB, '止损B', '#22c55e', '🛑');
}

// --- 7. MA Slope Painter ---
export function drawMASlope(
    container: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    y: ScaleLinear
) {
    for(let i=1; i<data.length; i++) {
        const d = data[i];
        const prev = data[i-1];
        if (d.ma5 && d.ma10 && d.ma20 && prev.ma5 && prev.ma10 && prev.ma20) {
            const s5 = d.ma5 - prev.ma5;
            const s10 = d.ma10 - prev.ma10;
            const s20 = d.ma20 - prev.ma20;
            if (s5 > 0 && s10 > 0 && s20 > 0 && d.ma5 > d.ma10 && d.ma10 > d.ma20) {
                const xPos = x(d.date)! + x.bandwidth()/2;
                const yLow = y(d.low);
                container.append('text').attr('x', xPos).attr('y', yLow + 25).text('⬆️').attr('fill', '#ec4899').attr('font-size', '10px').attr('text-anchor', 'middle');
            }
        }
    }
}

// --- 11. Strategy Markers Painter (R0-R10) ---
export function drawStrategyMarkers(
    container: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    y: ScaleLinear,
    width: number
) {
    if (data.length < 30) return;

    // --- Helpers ---
    // FIXED: Use Standard Deviation (2.0) for channel width instead of Max Deviation.
    // Max Deviation creates a 100% envelope, making "d.close > top" impossible (unless floating point error).
    // 2.0 SD allows for statistical breakouts.
    const getLRChannel = (idx: number, period: number = 20) => {
        if (idx < period - 1) return null;
        const subset = data.slice(idx - period + 1, idx + 1);
        const points = subset.map((d, i) => ({ x: i, y: d.close }));
        const { slope, intercept } = calculateLR(points);

        // Calculate Standard Deviation
        let sumSqDiff = 0;
        subset.forEach((d, i) => {
             const regY = slope * i + intercept;
             sumSqDiff += Math.pow(d.close - regY, 2);
        });
        const stdDev = Math.sqrt(sumSqDiff / period);
        const width = 2.0 * stdDev; // 2 Sigma Bollinger-like Width

        // Current projected values
        const currentX = period - 1;
        const mid = slope * currentX + intercept;
        return { top: mid + width, mid: mid, bottom: mid - width, slope };
    };

    const drawIcon = (i: number, icon: string, color: string, label?: string, yOffset: number = 25) => {
        const d = data[i];
        const xPos = x(d.date);
        if (xPos === undefined) return; // Skip if point not in visible x scale

        const cx = xPos + x.bandwidth()/2;
        const cy = y(d.high); 
        const g = container.append('g').attr('transform', `translate(${cx}, ${cy - yOffset})`);

        g.append('text')
            .text(icon)
            .attr('font-size', '14px')
            .attr('text-anchor', 'middle');

        if (label) {
             g.append('text')
                .text(label)
                .attr('y', -12)
                .attr('fill', color)
                .attr('font-size', '9px')
                .attr('text-anchor', 'middle')
                .attr('font-weight', 'bold');
        }
    };

    // --- State Machine ---
    let position: { 
        entryIdx: number, 
        entryPrice: number, 
        qty: number, 
        waveLow: number, // Stop reference (0%)
        waveHigh: number // Peak since entry (100% reference updates)
    } | null = null;

    // Simulation Loop
    for (let i = 20; i < data.length; i++) {
        const d = data[i];
        const prev = data[i-1];

        const channel = getLRChannel(i, 20);
        if (!channel) continue;

        const volAvg5 = data.slice(i-5, i).reduce((sum, p) => sum + p.volume, 0) / 5;
        const volRatio = d.volume / (volAvg5 || 1);

        // --- I. Observation & Entry ---

        // R0: Observe (Close > Channel Top)
        if (!position && d.close > channel.top) {
            // Draw mostly if it's a recent breakout or significant
            if (i % 3 === 0 || d.close > prev.close) { 
                drawIcon(i, '👁️', '#a855f7', '观察点'); 
            }
        }

        // R1: Entry (Breakout + Vol + Confirmation)
        if (!position && d.close > channel.top && volRatio > 1.5) {
            // Check confirmation (Next day close < prev close -> Buy Tail) or just strong breakout
            // Simulating "Next Day Action" requires peeking i+1, or reacting at i if i was the confirmation of i-1

            // Let's check if TODAY confirms YESTERDAY's breakout
            const prevChannel = getLRChannel(i-1, 20);
            if (prevChannel && prev.close > prevChannel.top) { // Yesterday broke out
                 if (d.close < prev.close) {
                     // Confirm Entry (Pullback after breakout)
                     drawIcon(i, '🚩', '#ef4444', '建仓点');

                     const localLow = Math.min(...data.slice(Math.max(0, i-20), i).map(p => p.low));
                     position = {
                         entryIdx: i,
                         entryPrice: d.close,
                         qty: 1, 
                         waveLow: localLow,
                         waveHigh: d.high
                     };
                 }
            }
        }

        // --- Active Position Logic ---
        if (position) {
            position.waveHigh = Math.max(position.waveHigh, d.high);
            const range = position.waveHigh - position.waveLow;
            const daysHeld = i - position.entryIdx;

            // R2: Add Position (Window 10 days)
            if (daysHeld <= 10 && daysHeld > 0) {
                 // Retrace to Fib 38.2% or 50%
                 const fib382 = position.waveHigh - range * 0.382;
                 const fib500 = position.waveHigh - range * 0.500;

                 const touchChannel = d.low <= channel.mid;
                 const isDownDay = d.close < prev.close;

                 // Relaxed condition: Near Fib & Touch Channel & Red Candle
                 if (touchChannel && d.low <= fib382 && d.close >= fib500 && isDownDay) {
                      drawIcon(i, '➕', '#3b82f6', '加仓');
                 }
            }

            // --- II. Symmetry Warnings ---
            if (daysHeld > 20 && d.high < position.waveHigh) {
                 if (i % 10 === 0) drawIcon(i, '⚠️', '#eab308', '警告');
            }

            // --- III. Take Profit ---
            const retracePct = (position.waveHigh - d.close) / (range || 1);

            if (retracePct > 0.326 && retracePct < 0.4 && daysHeld > 3) {
                 drawIcon(i, '🎯', '#ef4444', '止盈A');
            }
            if (retracePct > 0.618 && retracePct < 0.7) {
                 drawIcon(i, '🎯', '#eab308', '止盈B', 35); 
            }
            if (retracePct > 1.0) { 
                 drawIcon(i, '🎯', '#eab308', '止盈C', 35);
            }

            // R8: Hard Target (Profit > 30%)
            const pnl = (d.close - position.entryPrice) / position.entryPrice;
            if (pnl > 0.30) {
                 drawIcon(i, '❌', '#ef4444', '强制止损'); 
                 position = null; 
                 continue;
            }

            // --- IV. Stop Loss ---
            // R9: Step Stop (Break Low)
            if (d.close < position.waveLow) {
                 drawIcon(i, '🛡️', '#ef4444', '止损A');
                 position = null; 
                 continue;
            }

            // R10: Meltdown 
            if (d.open < position.waveLow * 0.99) {
                 drawIcon(i, '🚫', '#ef4444', '熔断止损');
                 position = null;
                 continue;
            }
        }
    }
}

// Helper for ZigZag
function calculateZigZag(data: KlinePoint[]) {
    const zigzag: {x: number, y: number, date: string, type: 'HIGH'|'LOW'}[] = [];
    const lookback = Math.max(3, Math.floor(data.length / 20));

    for(let i=lookback; i<data.length-lookback; i++) {
            const d = data[i];
            const range = data.slice(i-lookback, i+lookback+1);
            const isHigh = range.every(item => item.high <= d.high);
            const isLow = range.every(item => item.low >= d.low);

            if (isHigh) zigzag.push({x: i, y: d.high, date: d.date, type: 'HIGH'});
            else if (isLow) zigzag.push({x: i, y: d.low, date: d.date, type: 'LOW'});
    }

    const cleanZigzag: typeof zigzag = [];
    zigzag.forEach(p => {
        if (cleanZigzag.length === 0) { cleanZigzag.push(p); return; }
        const last = cleanZigzag[cleanZigzag.length-1];
        if (last.type !== p.type) {
            cleanZigzag.push(p);
        } else {
            if (p.type === 'HIGH' && p.y > last.y) cleanZigzag[cleanZigzag.length-1] = p;
            if (p.type === 'LOW' && p.y < last.y) cleanZigzag[cleanZigzag.length-1] = p;
        }
    });
    return cleanZigzag;
}

