// --- 11. Strategy Markers Painter (R1-R10) ---
export function drawStrategyMarkers(
    container: SelectionGroup,
    data: KlinePoint[],
    x: ScaleBand,
    y: ScaleLinear,
    width: number
) {
    if (data.length < 30) return;

    // --- Helpers ---
    // USE 2.0 Standard Deviations for Channel Width (Bollinger Logic)
    const getLRChannel = (idx: number, period: number = 20) => {
        if (idx < period - 1) return null;
        const subset = data.slice(idx - period + 1, idx + 1);
        const points = subset.map((d, i) => ({ x: i, y: d.close }));
        const { slope, intercept } = calculateLR(points);

        let sumSqDiff = 0;
        subset.forEach((d, i) => {
             const regY = slope * i + intercept;
             sumSqDiff += Math.pow(d.close - regY, 2);
        });
        const stdDev = Math.sqrt(sumSqDiff / period);
        // 2 Sigma for robust breakouts
        const width = 2.0 * stdDev; 

        const currentX = period - 1;
        const mid = slope * currentX + intercept;
        return { top: mid + width, mid: mid, bottom: mid - width, slope: slope / data[idx].close };
    };

    const drawIcon = (i: number, icon: string, color: string, label?: string, yOffset: number = 25) => {
        const d = data[i];
        const xPos = x(d.date);
        if (xPos === undefined) return;

        const cx = xPos + x.bandwidth()/2;
        const cy = y(d.high); 
        const g = container.append('g').attr('transform', `translate(${cx}, ${cy - yOffset})`);

        g.append('text')
            .text(icon)
            .attr('font-size', '14px')
            .attr('text-anchor', 'middle');

        if (label) {
             g.append('text')
                .text(label)
                .attr('y', -12)
                .attr('fill', color)
                .attr('font-size', '9px')
                .attr('text-anchor', 'middle')
                .attr('font-weight', 'bold');
        }
    };

    // Calculate Major ZigZag to simulate "Previous Wave"
    const zigzag = calculateZigZag(data);
    const getPrevWaveStats = (idx: number) => {
        const pastPivots = zigzag.filter((p, pi) => x(p.date)! < x(data[idx].date)!);
        if (pastPivots.length < 2) return null;
        const p2 = pastPivots[pastPivots.length-1]; // Last pivot
        const p1 = pastPivots[pastPivots.length-2]; // Prev pivot
        if (p2.type === 'HIGH') return null; // We need a rising wave as prev? Or just any wave.
        // Assuming we are in Uptrend, we look at prev rising wave
        const rising = zigzag.filter(z => z.type === 'HIGH');
        if(rising.length < 1) return null;
        // Simple mock: last completed wave height
        return { heightPct: 0.10, days: 15, slope: 0.005 }; 
    };

    // --- State Machine ---
    let position: { 
        entryIdx: number, 
        entryPrice: number, 
        waveLow: number, // 0% Ref
        waveHigh: number // 100% Ref
    } | null = null;

    let entrySignalDay = -1; // Track R1 trigger day

    // Simulation Loop
    for (let i = 20; i < data.length; i++) {
        const d = data[i];
        const prev = data[i-1];
        const channel = getLRChannel(i, 20);
        if (!channel) continue;

        const volAvg5 = data.slice(i-5, i).reduce((sum, p) => sum + p.volume, 0) / 5;
        const volRatio = d.volume / (volAvg5 || 1);

        // --- I. Observation & Entry (R1) ---
        if (!position) {
            // R1: Observe
            if (d.close > channel.top) {
                drawIcon(i, '👁️', '#a855f7', '观察点');

                // Check if valid breakout (Close > Top * 1.005) & Vol
                if (d.close > channel.top * 1.005 && volRatio > 1.5) {
                    drawIcon(i, '🚩', '#ef4444', '信号触发', 40);
                    entrySignalDay = i;
                }
            }

            // R1: Execution (Next Day Confirmation)
            if (entrySignalDay === i - 1) {
                // Confirm: Close < PrevClose (Pullback) OR just strong continuation? 
                // Rule says: if close < prev close -> buy at close.
                // If close > prev close * 1.01 -> Wait.
                if (d.close < prev.close) {
                     drawIcon(i, '🚀', '#ef4444', '建仓点');
                     // Initialize Position
                     const localLow = Math.min(...data.slice(Math.max(0, i-30), i).map(p => p.low));
                     position = {
                         entryIdx: i,
                         entryPrice: d.close,
                         waveLow: localLow,
                         waveHigh: d.high
                     };
                }
            }
        } 

        // --- II. Holding Phase ---
        else {
            position.waveHigh = Math.max(position.waveHigh, d.high);
            const range = position.waveHigh - position.waveLow;
            const daysHeld = i - position.entryIdx;

            // R2: Add Position (Window 10 days)
            if (daysHeld <= 10) {
                const fib382 = position.waveHigh - range * 0.382;
                const fib50 = position.waveHigh - range * 0.50;

                // Add A: Touch 38.2
                if (d.low <= fib382 && d.close > fib382 * 0.99) {
                     // Check overlap to avoid clutter
                     drawIcon(i, '➕', '#3b82f6', '加仓A');
                }
                // Add B: Touch 50
                if (d.low <= fib50 && d.close > fib50 * 0.99) {
                     drawIcon(i, '➕', '#3b82f6', '加仓B');
                }
            }

            // R3/R4 Symmetry Warnings
            // Simplified check: If days held > 20 and no new high
            if (daysHeld > 20 && d.high < position.waveHigh) {
                 if (daysHeld % 5 === 0) drawIcon(i, '⚠️', '#eab308', '警告');
            }

            // R6: Step Take Profit (Retracement from High)
            // Trigger: Close < specific level
            const fib326L = position.waveHigh - range * 0.326;
            const fib618L = position.waveHigh - range * 0.618;

            if (d.close < fib326L && prev.close >= fib326L) {
                 drawIcon(i, '🎯', '#ef4444', '止盈A');
            }
            if (d.close < fib618L && prev.close >= fib618L) {
                 drawIcon(i, '🎯', '#eab308', '止盈B');
            }

            // R8: Hard TP (Profit > 30%)
            if ((d.close - position.entryPrice) / position.entryPrice > 0.30) {
                 drawIcon(i, '❌', '#ef4444', '强制止盈');
                 position = null; // Clear
                 continue;
            }

            // R9: Stop Loss (Break Fib Defense relative to Entry)
            // Logic: Price < Entry * (1 - 0.05) approx
            if (d.close < position.entryPrice * 0.95) {
                 drawIcon(i, '🛡️', '#ef4444', '止损');
                 position = null;
                 continue;
            }

            // R10: Meltdown
            if (d.open < position.waveLow * 0.99) {
                 drawIcon(i, '🚫', '#ef4444', '熔断');
                 position = null;
                 continue;
            }
        }
    }
}

// Helper for ZigZag
function calculateZigZag(data: KlinePoint[]) {
    const zigzag: {x: number, y: number, date: string, type: 'HIGH'|'LOW'}[] = [];
    const lookback = Math.max(3, Math.floor(data.length / 20));

    for(let i=lookback; i<data.length-lookback; i++) {
            const d = data[i];
            const range = data.slice(i-lookback, i+lookback+1);
            const isHigh = range.every(item => item.high <= d.high);
            const isLow = range.every(item => item.low >= d.low);

            if (isHigh) zigzag.push({x: i, y: d.high, date: d.date, type: 'HIGH'});
            else if (isLow) zigzag.push({x: i, y: d.low, date: d.date, type: 'LOW'});
    }

    const cleanZigzag: typeof zigzag = [];
    zigzag.forEach(p => {
        if (cleanZigzag.length === 0) { cleanZigzag.push(p); return; }
        const last = cleanZigzag[cleanZigzag.length-1];
        if (last.type !== p.type) {
            cleanZigzag.push(p);
        } else {
            if (p.type === 'HIGH' && p.y > last.y) cleanZigzag[cleanZigzag.length-1] = p;
            if (p.type === 'LOW' && p.y < last.y) cleanZigzag[cleanZigzag.length-1] = p;
        }
    });
    return cleanZigzag;
}

import { Injectable } from '@angular/core';
import { KlinePoint } from './etf.service';

export interface CachedETFData {
  code: string;
  history: KlinePoint[];
  lastUpdated: number; // Timestamp
}

@Injectable({
  providedIn: 'root'
})
export class DbService {
  private dbName = 'ETF_Alpha_DB';
  private storeName = 'kline_history';
  private version = 1;
  private dbPromise: Promise<IDBDatabase>;

  constructor() {
    this.dbPromise = this.initDB();
  }

  private initDB(): Promise<IDBDatabase> {
    return new Promise((resolve, reject) => {
      const request = indexedDB.open(this.dbName, this.version);

      request.onerror = (event) => {
        console.error('IndexedDB error:', event);
        reject('Database error');
      };

      request.onsuccess = (event) => {
        resolve((event.target as IDBOpenDBRequest).result);
      };

      request.onupgradeneeded = (event) => {
        const db = (event.target as IDBOpenDBRequest).result;
        if (!db.objectStoreNames.contains(this.storeName)) {
          db.createObjectStore(this.storeName, { keyPath: 'code' });
        }
      };
    });
  }

  async getETF(code: string): Promise<CachedETFData | undefined> {
    const db = await this.dbPromise;
    return new Promise((resolve, reject) => {
      const transaction = db.transaction([this.storeName], 'readonly');
      const store = transaction.objectStore(this.storeName);
      const request = store.get(code);

      request.onsuccess = () => resolve(request.result);
      request.onerror = () => reject(request.error);
    });
  }

  async saveETF(data: CachedETFData): Promise<void> {
    const db = await this.dbPromise;
    return new Promise((resolve, reject) => {
      const transaction = db.transaction([this.storeName], 'readwrite');
      const store = transaction.objectStore(this.storeName);
      const request = store.put(data);

      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  }

  async clear(): Promise<void> {
    const db = await this.dbPromise;
    return new Promise((resolve, reject) => {
      const transaction = db.transaction([this.storeName], 'readwrite');
      const store = transaction.objectStore(this.storeName);
      const request = store.clear();
      request.onsuccess = () => resolve();
      request.onerror = () => reject(request.error);
    });
  }
}

import { Injectable, signal, inject } from '@angular/core';
import { HttpClient } from '@angular/common/http';
import { ETFDefinition, ETF_LIST } from './etf-list';
import { map, forkJoin, catchError, of, Observable, from, mergeMap, toArray, switchMap, tap } from 'rxjs';
import { DbService, CachedETFData } from './db.service';

export interface KlinePoint {
  date: string;
  open: number;
  close: number;
  high: number;
  low: number;
  volume: number;
  amount: number;
  // Moving Averages
  ma5?: number;
  ma10?: number;
  ma20?: number;
  ma60?: number;
  // Slopes (Percentage Change per day)
  ma20Slope?: number;
  ma60Slope?: number;

  // Indicators
  macd?: { diff: number; dea: number; macd: number };
  kdj?: { k: number; d: number; j: number };
  rsi?: number;
  wr?: number; // Williams %R
  boll?: { upper: number; mid: number; lower: number; width: number }; 
  bias?: number; // BIAS 20

  // New Indicators
  atr?: number; // Average True Range (14)
  roc?: number; // Rate of Change
  mtm?: number; // Momentum
  obv?: number; // On-Balance Volume
  obvMa?: number; // MA of OBV
}

export interface FundBaseInfo {
  fundSize: number; // In Billions (亿元)
  establishmentDate: string; // YYYY-MM-DD
  age: number; // Years since establishment
}

export interface WaveStats {
  height: number;
  days: number;
  slope: number;
}

// Updated Trade Suggestion Types for Multi-period Resonance
export type TradeSuggestion = 
  'OBSERVE' |          // 观察点
  'BUY_POINT' |        // 建仓点
  'HOLD' |             // 持仓
  'TAKE_PROFIT_REDUCE' | // 止盈(减仓)
  'TAKE_PROFIT_CLEAR' |  // 止盈(清仓)
  'STOP_LOSS_REDUCE' |   // 止损(减仓)
  'STOP_LOSS_CLEAR' |    // 止损(清仓)
  'WAIT';              // 观望

export interface BoxSignal {
  type: 'UP' | 'DOWN';
  date: string; // Entry Date
  obsDate: string; // Observation Date
  boxHigh: number;
  boxLow: number;
  boxHeight: number;
  entryPrice: number;
  poc: number; // Point of Control
  tpA: number; // Target 38.2%
  tpB: number; // Target 61.8%
  slA: number; // Stop Loss 38.2%
  slB: number; // Stop Loss 61.8%
  clearPrice: number; // Clearance Point (Box Low)
  valid: boolean;
  boxStartDate: string; // For drawing box
}

export interface ETFAnalysis extends ETFDefinition, FundBaseInfo {
  currentPrice: number;
  suggestedEntryPrice: number; // Calculated Buy Target
  goldenPrice: number; // Golden Ratio Support Price (0.618 retracement)
  changePercent7d: number;
  isGolden: boolean; 
  breakMA5: boolean;
  breakMA20: boolean;
  breakDowntrend: boolean; 
  isHighVolume: boolean;

  // Counts
  buySignals: number;
  sellSignals: number;

  // Detailed Reasons
  buyFactors: string[];
  sellFactors: string[];

  trend: 'UP' | 'DOWN' | 'SIDEWAYS';
  score: number;
  health: number; // New Health Score
  symmetry?: {
      lastWave: WaveStats;
      currentSlope: number;
      slopeRatio: number; // current / last
  };

  suggestion: TradeSuggestion;
  boxSignal?: BoxSignal | null; // Multi-period Resonance Signal
  lastUpdated: string;
  history: KlinePoint[];
}

